# Capture user-provided INSTALL_DIR before we potentially override it.
# If the user explicitly set INSTALL_DIR (and it's not the default),
# we respect their choice over auto-detection.
_USER_INSTALL_DIR="${INSTALL_DIR}"
[ "$_USER_INSTALL_DIR" = "/opt/helixscreen" ] && _USER_INSTALL_DIR=""
INIT_SCRIPT_DEST=""
PREVIOUS_UI_SCRIPT=""
AD5M_FIRMWARE=""
K1_FIRMWARE=""
KLIPPER_USER=""
KLIPPER_GROUP=""
KLIPPER_HOME=""

# Friendly description of the underlying SBC for the user-facing log line.
# Returns free-text (NOT used for routing). Pi/pi32 covers a long tail of
# aarch64/armv7l Klipper boxes (Raspberry Pi, BTT CB1, MKS-Pi, QIDI Q2/Plus,
# generic Armbian) — they all run the same binary, but "Detected: pi" reads
# as wrong to anyone whose printer says QIDI on the lid. This emits a label
# based on /proc/device-tree/model, hostname, and home-directory shape so
# the user sees their own hardware reflected back.
describe_hardware() {
    local _model="" _hostname="" _pretty=""

    if [ -r /proc/device-tree/model ]; then
        _model=$(tr -d '\0' </proc/device-tree/model 2>/dev/null)
    fi
    if [ -r /etc/hostname ]; then
        _hostname=$(cat /etc/hostname 2>/dev/null | tr -d '[:space:]')
    fi
    if [ -r /etc/os-release ]; then
        # shellcheck disable=SC1091
        _pretty=$(. /etc/os-release 2>/dev/null && echo "${PRETTY_NAME:-${NAME:-}}")
    fi

    # Device-tree model is the strongest signal when present.
    case "$_model" in
        *"Raspberry Pi"*) echo "$_model"; return ;;
        *"BIGTREETECH"*|*"BTT"*) echo "BIGTREETECH SBC ($_model)"; return ;;
        *Rockchip*|*"RK3"*|*Allwinner*|*Amlogic*) ;;  # fall through, often too generic alone
    esac

    # Hostname + user-dir heuristics for boards without a useful DT model.
    # `linaro-alip` is the Linaro Debian reference rootfs hostname; QIDI
    # ships it on the Q2 (and likely Plus 4) running Klipper as `mks`.
    if [ "$_hostname" = "linaro-alip" ] && [ -d "/home/mks" ]; then
        echo "QIDI-class SBC (likely Q2/Plus, hostname: $_hostname, user: mks)"
        return
    fi
    if [ -d "/home/biqu" ]; then
        echo "BIGTREETECH Pi/CB1 (user: biqu)"
        return
    fi
    if [ -d "/home/mks" ]; then
        echo "MKS-branded SBC (user: mks)"
        return
    fi
    if [ -d "/home/pi" ] && [ -z "$_model" ]; then
        echo "Raspberry Pi (user: pi)"
        return
    fi

    if [ -n "$_model" ]; then
        echo "$_model"
        return
    fi
    if [ -n "$_pretty" ]; then
        echo "ARM SBC ($_pretty)"
        return
    fi
    echo "ARM SBC"
}

# Resolve the primary group of a user, falling back to the user name.
# Some firmwares (e.g. QIDI Q2 stock) ship a `mks` user without a matching
# `mks` group, which makes `Group=mks` in the systemd unit fail with
# "Failed to determine group credentials". Use `id -gn` to find the actual
# primary group; only fall back to the user name when getent fails.
_resolve_primary_group() {
    local _user="$1"
    [ -n "$_user" ] || { echo "root"; return; }
    local _g
    _g=$(id -gn "$_user" 2>/dev/null) || _g=""
    if [ -n "$_g" ]; then
        echo "$_g"
    else
        echo "$_user"
    fi
}

# Detect platform
# Returns: "ad5m", "ad5x", "cc1", "k1", "k2", "m1", "pi", "pi32", "snapmaker-u1", "x86", or "unsupported"
detect_platform() {
    local arch kernel
    arch=$(uname -m)
    kernel=$(uname -r)

    # Check for Elegoo Centauri Carbon running OpenCentauri COSMOS firmware.
    # MUST come before AD5M check — both are armv7l with kernel 5.4.61.
    # COSMOS replaces the stock Tina/OpenWrt userland with a Yocto-based rootfs
    # that ships Klipper, Moonraker, and its own update tool.
    if [ "$arch" = "armv7l" ] && [ -x "/usr/bin/update-cosmos" ]; then
        echo "cc1"
        return
    fi

    # Check for Creality K2 series (armv7l, OpenWrt/Tina Linux, /mnt/UDISK)
    # MUST come before AD5M check — both are armv7l with kernel 5.4.61
    if [ "$arch" = "armv7l" ] && [ -d "/mnt/UDISK" ]; then
        # K2 runs Tina Linux (OpenWrt-based) with storage on /mnt/UDISK
        if [ -f /etc/os-release ] && grep -qi "openwrt\|tina" /etc/os-release 2>/dev/null; then
            echo "k2"
            return
        fi
        # Fallback: /mnt/UDISK/printer_data is a strong K2 indicator even without os-release
        if [ -d "/mnt/UDISK/printer_data" ] || [ -d "/mnt/UDISK/creality" ]; then
            echo "k2"
            return
        fi
    fi

    # Check for AD5M (armv7l with specific kernel, NOT K2)
    if [ "$arch" = "armv7l" ]; then
        # AD5M has a specific kernel identifier
        if echo "$kernel" | grep -q "ad5m\|5.4.61"; then
            echo "ad5m"
            return
        fi
    fi

    # Check for FlashForge AD5X (MIPS with /usr/data and FlashForge indicators)
    # AD5X uses Ingenic X2600 (MIPS); identified by /usr/prog/ dir or /ZMOD file alongside /usr/data/
    if [ "$arch" = "mips" ]; then
        if [ -d "/usr/data" ] && { [ -d "/usr/prog" ] || [ -f "/ZMOD" ]; }; then
            echo "ad5x"
            return
        fi
    fi

    # Check for Creality K1 series (Simple AF or stock with Klipper)
    # K1 uses buildroot and has /usr/data structure
    if [ -f /etc/os-release ] && grep -q "buildroot" /etc/os-release 2>/dev/null; then
        # Buildroot-based system - check for K1 indicators
        if [ -d "/usr/data" ]; then
            # Check for K1-specific indicators (require at least 2 for confidence)
            # - get_sn_mac.sh is a Creality-specific script
            # - /usr/data/pellcorp is Simple AF
            # - /usr/data/printer_data with klipper is a strong K1 indicator
            local k1_indicators=0
            [ -x "/usr/bin/get_sn_mac.sh" ] && k1_indicators=$((k1_indicators + 1))
            [ -d "/usr/data/pellcorp" ] && k1_indicators=$((k1_indicators + 1))
            [ -d "/usr/data/printer_data" ] && k1_indicators=$((k1_indicators + 1))
            [ -d "/usr/data/klipper" ] && k1_indicators=$((k1_indicators + 1))
            # Also check for Creality-specific paths
            [ -f "/usr/data/creality/userdata/config/system_config.json" ] && k1_indicators=$((k1_indicators + 1))

            if [ "$k1_indicators" -ge 2 ]; then
                echo "k1"
                return
            fi
        fi
    fi

    # Snapmaker U1 (aarch64 + extended firmware markers)
    # Must check BEFORE generic Pi/ARM SBC since U1 is also aarch64 Debian
    if [ "$arch" = "aarch64" ]; then
        local u1_markers=0
        [ -d "/home/lava" ] && u1_markers=$((u1_markers + 1))
        [ -d "/home/lava/printer_data" ] && u1_markers=$((u1_markers + 1))
        [ -x "/usr/bin/unisrv" ] && u1_markers=$((u1_markers + 1))
        [ -d "/oem" ] && u1_markers=$((u1_markers + 1))
        # Check for RK3562 SoC in device-tree
        if [ -f /proc/device-tree/compatible ] && grep -q "rockchip,rk3562" /proc/device-tree/compatible 2>/dev/null; then
            u1_markers=$((u1_markers + 1))
        fi
        if [ "$u1_markers" -ge 2 ]; then
            echo "snapmaker-u1"
            return 0
        fi
    fi

    # Artillery M1 Pro (systemd Debian SBC running stock Artillery firmware).
    # MUST come before the generic Debian SBC fallback since M1 is Debian-based
    # and would otherwise be misdetected as plain "pi" — which would skip the
    # M1-specific competing-UI shutdown (algo_app.service + makerbase-client).
    # Fingerprints: the two stock services live under systemd; either physical
    # unit files or systemctl listing them is enough.
    if [ "$arch" = "aarch64" ] || [ "$arch" = "armv7l" ]; then
        local m1_markers=0
        [ -f /etc/systemd/system/algo_app.service ] && m1_markers=$((m1_markers + 1))
        [ -f /etc/systemd/system/makerbase-client.services ] && m1_markers=$((m1_markers + 1))
        [ -f /lib/systemd/system/algo_app.service ] && m1_markers=$((m1_markers + 1))
        [ -f /lib/systemd/system/makerbase-client.services ] && m1_markers=$((m1_markers + 1))
        if [ "$m1_markers" = 0 ] && command -v systemctl >/dev/null 2>&1; then
            if systemctl list-unit-files 2>/dev/null | grep -qE '^(algo_app\.service|makerbase-client\.services)\b'; then
                m1_markers=1
            fi
        fi
        if [ "$m1_markers" -ge 1 ]; then
            echo "m1"
            return 0
        fi
    fi

    # Check for Debian-family SBC (Raspberry Pi, MKS, BTT, Armbian, etc.)
    # Returns "pi" for 64-bit, "pi32" for 32-bit
    if [ "$arch" = "aarch64" ] || [ "$arch" = "armv7l" ]; then
        local is_arm_sbc=false

        # 1. os-release: check for Debian-family indicators
        #    ID_LIKE=debian appears in all derivatives (Ubuntu, Armbian, Raspbian, etc.)
        #    so grepping for "debian" alone catches most cases.
        if [ -f /etc/os-release ] && \
           grep -qi "debian\|raspbian\|ubuntu\|armbian" /etc/os-release 2>/dev/null; then
            is_arm_sbc=true
        fi

        # 2. Package manager: dpkg is the definitive Debian-family indicator.
        #    Catches any derivative not listed above.
        if [ "$is_arm_sbc" = false ] && command -v dpkg >/dev/null 2>&1; then
            is_arm_sbc=true
        fi

        # 3. Well-known SBC user home directories (MainsailOS, BTT Pi, MKS)
        if [ "$is_arm_sbc" = false ]; then
            if [ -d /home/pi ] || [ -d /home/mks ] || [ -d /home/biqu ]; then
                is_arm_sbc=true
            fi
        fi

        if [ "$is_arm_sbc" = true ]; then
            # Detect actual userspace bitness, not just kernel arch.
            # Many Pi systems run 64-bit kernel with 32-bit userspace,
            # which makes uname -m report aarch64 even though only
            # 32-bit binaries can execute.
            local userspace_bits
            userspace_bits=$(getconf LONG_BIT 2>/dev/null || echo "")
            if [ "$userspace_bits" = "64" ]; then
                echo "pi"
            elif [ "$userspace_bits" = "32" ]; then
                if [ "$arch" = "aarch64" ]; then
                    log_warn "64-bit kernel with 32-bit userspace detected — using pi32 build"
                fi
                echo "pi32"
            else
                # getconf unavailable — fall back to checking system binary
                if file /usr/bin/id 2>/dev/null | grep -q "64-bit"; then
                    echo "pi"
                elif file /usr/bin/id 2>/dev/null | grep -q "32-bit"; then
                    if [ "$arch" = "aarch64" ]; then
                        log_warn "64-bit kernel with 32-bit userspace detected — using pi32 build"
                    fi
                    echo "pi32"
                else
                    # Last resort: trust kernel arch
                    if [ "$arch" = "aarch64" ]; then
                        echo "pi"
                    else
                        echo "pi32"
                    fi
                fi
            fi
            return
        fi
    fi

    # Check for x86_64 Linux (generic Debian/Ubuntu desktop or server)
    if [ "$arch" = "x86_64" ] || [ "$arch" = "i686" ] || [ "$arch" = "amd64" ]; then
        echo "x86"
        return
    fi

    # Unknown ARM device - don't assume it's a Pi
    # Require explicit platform indicators to avoid false positives
    if [ "$arch" = "aarch64" ] || [ "$arch" = "armv7l" ]; then
        log_warn "Unknown ARM platform. Cannot auto-detect."
        echo "unsupported"
        return
    fi

    echo "unsupported"
}

# Map a detected platform to the platform key used for release downloads.
#
# Most platforms are 1:1 (pi → pi, ad5m → ad5m, …). The exception is platforms
# like `m1` (Artillery M1 Pro) that have no dedicated release artifact: the
# generic pi/pi32 binary is ABI-compatible, so we reuse it instead of doubling
# CI for an identical build. The `m1` *platform* key is preserved everywhere
# else (hooks, banner, competing-UI shutdown) so M1-specific behavior still
# fires; only the download URL changes.
#
# Args: detected_platform
# Echoes: platform key to use when constructing release archive URLs
get_download_platform() {
    local detected=$1
    case "$detected" in
        m1)
            # Artillery M1 Pro is a Debian SBC. The pi/pi32 binary runs as-is.
            # Pick the variant matching the device's userspace bitness.
            local userspace_bits
            userspace_bits=$(getconf LONG_BIT 2>/dev/null || echo "")
            if [ "$userspace_bits" = "32" ]; then
                echo "pi32"
            else
                echo "pi"
            fi
            ;;
        *)
            echo "$detected"
            ;;
    esac
}

# Single source of truth: platform -> self-update release asset (zip) name.
#
# Both the Moonraker type:web updater (write_release_info() in moonraker.sh) and
# the build-time release_info.json baked by mk/cross.mk resolve the asset name
# through THIS function, so the two can't drift. Drift is not cosmetic: Moonraker
# downloads the asset whose name matches release_info.json's asset_name, and if
# no asset matches it falls back to the alphabetically-first release asset — a
# .sym debug file — then dies with "File is not a zip file"
# (prestonbrown/helixscreen#993). This must also agree with
# UpdateChecker::get_platform_key() (src/system/update_checker.cpp);
# tests/shell/test_update_platform_coverage.bats enforces the agreement.
#
# Convention: a platform's asset is helixscreen-<platform>.zip. The only borrows
# are handled by get_download_platform() (m1 -> pi/pi32 by userspace bitness) and
# the k1-dynamic dev/debug variant, which is not built by the release matrix and
# rides the stable k1 asset.
#
# Args: platform (detected platform key)
# Echoes: release asset filename, e.g. helixscreen-pi.zip
helix_self_update_asset() {
    case "$1" in
        k1-dynamic) echo "helixscreen-k1.zip" ;;
        *)          echo "helixscreen-$(get_download_platform "$1").zip" ;;
    esac
}

# AD5X (FlashForge / ZMOD) preflight: refuse to run outside the chroot.
#
# ZMOD installs HelixScreen into an overlay rooted at /usr/data/.mod/.zmod/.
# Inside the chroot the rootfs is the overlay (/, /etc, /opt, /srv all live
# under that overlay). Outside, those same paths point at the squashfs base
# view that helix-screen never sees — so a curl|sh, --local, --update, or
# --uninstall run from a fresh SSH session writes to the wrong filesystem
# entirely. The `/usr/data/.mod/.zmod` directory is only visible from outside
# the chroot, so its presence is the reliable "you forgot to chroot" tell.
#
# Aborts with an actionable message when called outside the chroot.
ad5x_check_chroot_context() {
    [ -d "/usr/data/.mod/.zmod" ] || return 0

    log_error ""
    log_error "=========================================================="
    log_error " AD5X manual installs must run inside the ZMOD chroot."
    log_error "=========================================================="
    log_error ""
    log_error "ZMOD installs HelixScreen into an overlay at:"
    log_error "  /usr/data/.mod/.zmod/"
    log_error ""
    log_error "Running this installer from your default SSH shell writes"
    log_error "into the squashfs base view, not the overlay HelixScreen"
    log_error "actually runs out of. That leaves you with broken paths,"
    log_error "no init script in scope, and a printer that boots into"
    log_error "the stock UI."
    log_error ""
    log_error "Enter the chroot first, then re-run your command:"
    log_error ""
    log_error "  chroot /usr/data/.mod/.zmod"
    log_error "  # then re-run: curl ... | sh   OR   sh install.sh --local <zip>"
    log_error "  # OR:          sh install.sh --update / --uninstall"
    log_error ""
    log_error "ZMOD also manages routine updates through Moonraker's update"
    log_error "manager — you only need this manual path for --local installs,"
    log_error "specific versions, or troubleshooting."
    log_error ""
    exit 1
}

# Detect the Klipper ecosystem user (who runs klipper/moonraker services)
# Detection cascade (most reliable first):
#   1. systemd: systemctl show klipper.service
#   2. Process table: ps for running klipper
#   3. printer_data scan: /home/*/printer_data
#   4. Well-known users: biqu, pi, mks
#   5. Fallback: root
# Sets: KLIPPER_USER, KLIPPER_HOME
detect_klipper_user() {
    # 1. systemd service owner (most reliable on Pi)
    if command -v systemctl >/dev/null 2>&1; then
        local svc_user
        svc_user=$(systemctl show -p User --value klipper.service 2>/dev/null) || true
        if [ -n "$svc_user" ] && [ "$svc_user" != "root" ] && id "$svc_user" >/dev/null 2>&1; then
            KLIPPER_USER="$svc_user"
            KLIPPER_GROUP=$(_resolve_primary_group "$svc_user")
            KLIPPER_HOME=$(eval echo "~$svc_user")
            log_info "Klipper user (systemd): $KLIPPER_USER (group: $KLIPPER_GROUP)"
            return 0
        fi
    fi

    # 2. Process table (catches running instances)
    local ps_user
    ps_user=$(ps -eo user,comm 2>/dev/null | awk '/klipper$/ && !/grep/ {print $1; exit}') || true
    if [ -n "$ps_user" ] && [ "$ps_user" != "root" ] && id "$ps_user" >/dev/null 2>&1; then
        KLIPPER_USER="$ps_user"
        KLIPPER_GROUP=$(_resolve_primary_group "$ps_user")
        KLIPPER_HOME=$(eval echo "~$ps_user")
        log_info "Klipper user (process): $KLIPPER_USER (group: $KLIPPER_GROUP)"
        return 0
    fi

    # 3. printer_data directory scan
    local pd_dir
    for pd_dir in /home/*/printer_data; do
        [ -d "$pd_dir" ] || continue
        local pd_user
        pd_user=$(echo "$pd_dir" | sed 's|^/home/||;s|/printer_data$||')
        if [ -n "$pd_user" ] && id "$pd_user" >/dev/null 2>&1; then
            KLIPPER_USER="$pd_user"
            KLIPPER_GROUP=$(_resolve_primary_group "$pd_user")
            KLIPPER_HOME="/home/$pd_user"
            log_info "Klipper user (printer_data): $KLIPPER_USER (group: $KLIPPER_GROUP)"
            return 0
        fi
    done

    # 4. Well-known users (checked in priority order)
    local known_user
    for known_user in biqu pi mks; do
        if id "$known_user" >/dev/null 2>&1; then
            KLIPPER_USER="$known_user"
            KLIPPER_GROUP=$(_resolve_primary_group "$known_user")
            KLIPPER_HOME="/home/$known_user"
            log_info "Klipper user (well-known): $KLIPPER_USER (group: $KLIPPER_GROUP)"
            return 0
        fi
    done

    # 5. Fallback: root (embedded platforms, AD5M, K1)
    KLIPPER_USER="root"
    KLIPPER_GROUP="root"
    KLIPPER_HOME="/root"
    log_info "Klipper user (fallback): root"
    return 0
}

# Detect AD5M firmware variant (Klipper Mod vs Forge-X vs ZMOD)
# Only called when platform is "ad5m"
# Returns: "klipper_mod", "forge_x", or "zmod"
detect_ad5m_firmware() {
    # ZMOD indicator - check for /ZMOD marker file
    # ZMOD is used on AD5M, AD5M Pro, and AD5X (FlashForge series)
    if [ -f "/ZMOD" ]; then
        echo "zmod"
        return
    fi

    # Klipper Mod indicators - check for its specific directory structure
    # Klipper Mod runs in a chroot on /mnt/data/.klipper_mod/chroot
    # v00.05: printer software in /root/printer_software/
    # v00.06+: printer software in /opt/ (no /root/printer_software)
    if [ -d "/root/printer_software" ] || [ -d "/mnt/data/.klipper_mod" ]; then
        echo "klipper_mod"
        return
    fi

    # Forge-X indicators - check for its mod overlay structure
    if [ -d "/opt/config/mod/.root" ]; then
        echo "forge_x"
        return
    fi

    # Default to forge_x (original behavior, most common)
    echo "forge_x"
}

# Detect K1 firmware variant (Simple AF, Guilouz helper-script, or stock)
# Only called when platform is "k1"
# Returns: "simple_af", "guilouz", or "stock_klipper"
detect_k1_firmware() {
    # Simple AF (pellcorp/creality) indicators
    if [ -d "/usr/data/pellcorp" ]; then
        echo "simple_af"
        return
    fi

    # Check for GuppyScreen which Simple AF installs
    if [ -d "/usr/data/guppyscreen" ] && [ -f "/etc/init.d/S99guppyscreen" ]; then
        echo "simple_af"
        return
    fi

    # Guilouz Helper Script (community firmware mod for K1 series)
    if [ -d "/usr/data/helper-script" ]; then
        echo "guilouz"
        return
    fi

    # Default to stock_klipper (generic K1 with Klipper)
    echo "stock_klipper"
}

# Detect Pi install directory based on Klipper ecosystem presence
# Cascade (first match wins):
#   1. User explicitly set INSTALL_DIR → keep it
#   2. ~/klipper or ~/moonraker exists → ~/helixscreen
#   3. ~/printer_data exists → ~/helixscreen
#   4. moonraker.service is active → ~/helixscreen
#   5. Fallback → /opt/helixscreen
# Requires: KLIPPER_HOME to be set (by detect_klipper_user)
# Sets: INSTALL_DIR
detect_pi_install_dir() {
    # 1. User explicitly set INSTALL_DIR — respect their choice
    if [ -n "$_USER_INSTALL_DIR" ]; then
        INSTALL_DIR="$_USER_INSTALL_DIR"
        log_info "Install directory (user override): $INSTALL_DIR"
        return 0
    fi

    # Need KLIPPER_HOME for ecosystem detection
    if [ -z "$KLIPPER_HOME" ]; then
        INSTALL_DIR="/opt/helixscreen"
        return 0
    fi

    # 2. Klipper or Moonraker source directories
    if [ -d "$KLIPPER_HOME/klipper" ] || [ -d "$KLIPPER_HOME/moonraker" ]; then
        INSTALL_DIR="$KLIPPER_HOME/helixscreen"
        log_info "Install directory (klipper ecosystem): $INSTALL_DIR"
        return 0
    fi

    # 3. printer_data directory (Klipper config structure)
    if [ -d "$KLIPPER_HOME/printer_data" ]; then
        INSTALL_DIR="$KLIPPER_HOME/helixscreen"
        log_info "Install directory (printer_data): $INSTALL_DIR"
        return 0
    fi

    # 4. Moonraker service running (ecosystem present but maybe different layout)
    if command -v systemctl >/dev/null 2>&1; then
        if systemctl is-active --quiet moonraker.service 2>/dev/null || \
           systemctl is-active --quiet moonraker 2>/dev/null; then
            INSTALL_DIR="$KLIPPER_HOME/helixscreen"
            log_info "Install directory (moonraker service): $INSTALL_DIR"
            return 0
        fi
    fi

    # 5. Fallback: no ecosystem detected
    INSTALL_DIR="/opt/helixscreen"
    return 0
}

# Detect best temp directory for extraction
# Mirrors get_helix_cache_dir() heuristic from app_globals.cpp:
# tries candidates in order, picks first writable dir with >= 100MB free.
# User can override via TMP_DIR env var.
# Sets: TMP_DIR
detect_tmp_dir() {
    # User already set TMP_DIR — respect it
    if [ -n "${TMP_DIR:-}" ]; then
        log_info "Temp directory (user override): $TMP_DIR"
        return 0
    fi

    local required_mb=100
    # /user-resource is CC1's large writable partition (4GB+); /data is tiny (~118MB)
    # and often too full once the tarball is downloaded there, so list /user-resource
    # ahead of the smaller candidates.
    local candidates="/user-resource/helixscreen-install /data/helixscreen-install /mnt/data/helixscreen-install /usr/data/helixscreen-install /var/tmp/helixscreen-install /tmp/helixscreen-install"

    for candidate in $candidates; do
        local check_dir
        check_dir=$(dirname "$candidate")

        # Must exist (or be creatable) and be writable
        if [ ! -d "$check_dir" ]; then
            continue
        fi
        if [ ! -w "$check_dir" ] && ! $SUDO test -w "$check_dir" 2>/dev/null; then
            continue
        fi

        # Check free space (BusyBox df: KB in $4)
        local available_mb
        available_mb=$(df "$check_dir" 2>/dev/null | tail -1 | awk '{print int($4/1024)}')
        if [ -z "$available_mb" ] || [ "$available_mb" -lt "$required_mb" ]; then
            continue
        fi

        TMP_DIR="$candidate"
        if [ "$check_dir" != "/tmp" ]; then
            log_info "Temp directory: $TMP_DIR (${available_mb}MB free)"
        fi
        return 0
    done

    # Last resort — /tmp even if small (will fail later at extraction with a clear error)
    TMP_DIR="/tmp/helixscreen-install"
    log_warn "No temp directory with ${required_mb}MB+ free found, using /tmp"
}

# Set installation paths based on platform and firmware
# Sets: INSTALL_DIR, INIT_SCRIPT_DEST, PREVIOUS_UI_SCRIPT, TMP_DIR
set_install_paths() {
    local platform=$1
    local firmware=${2:-}

    if [ "$platform" = "ad5m" ]; then
        # AD5M runs the helix-screen service as root on all three firmwares
        # (klipper_mod, zmod, forge_x). Pin KLIPPER_USER/HOME explicitly so
        # clean_helix_state_dirs and any other consumer don't fall back to
        # the empty default and silently skip the user-home sweep.
        KLIPPER_USER="root"
        KLIPPER_GROUP="root"
        KLIPPER_HOME="/root"
        case "$firmware" in
            klipper_mod)
                # v00.05 and earlier: /root/printer_software/helixscreen
                # v00.06+: /opt/helixscreen (no /root/printer_software dir)
                if [ -d "/root/printer_software" ]; then
                    INSTALL_DIR="/root/printer_software/helixscreen"
                else
                    INSTALL_DIR="/opt/helixscreen"
                fi
                INIT_SCRIPT_DEST="/etc/init.d/S80helixscreen"
                PREVIOUS_UI_SCRIPT="/etc/init.d/S80klipperscreen"
                log_info "AD5M firmware: Klipper Mod"
                log_info "Install directory: ${INSTALL_DIR}"
                ;;
            zmod)
                INSTALL_DIR="/srv/helixscreen"
                INIT_SCRIPT_DEST="/etc/init.d/S80helixscreen"
                PREVIOUS_UI_SCRIPT=""
                log_info "AD5M firmware: ZMOD"
                log_info "Install directory: ${INSTALL_DIR}"
                ;;
            forge_x|*)
                INSTALL_DIR="/opt/helixscreen"
                INIT_SCRIPT_DEST="/etc/init.d/S90helixscreen"
                PREVIOUS_UI_SCRIPT="/opt/config/mod/.root/S80guppyscreen"
                log_info "AD5M firmware: Forge-X"
                log_info "Install directory: ${INSTALL_DIR}"
                ;;
        esac
    elif [ "$platform" = "ad5x" ]; then
        # FlashForge AD5X - uses ZMOD, /usr/data structure, runs as root
        KLIPPER_USER="root"
        KLIPPER_GROUP="root"
        KLIPPER_HOME="/root"
        INSTALL_DIR="/srv/helixscreen"
        INIT_SCRIPT_DEST="/etc/init.d/S80helixscreen"
        PREVIOUS_UI_SCRIPT=""
        log_info "Platform: FlashForge AD5X (ZMOD)"
        log_info "Install directory: ${INSTALL_DIR}"
    elif [ "$platform" = "k1" ]; then
        # Creality K1 series - uses /usr/data structure.
        # printer_data is at /usr/data/printer_data (squashfs /root is RO).
        # Without the explicit override, detect_klipper_user falls back to
        # KLIPPER_HOME=/root and setup_config_symlink skips with
        # "No printer_data/config found" on every K1 install.
        INSTALL_DIR="/usr/data/helixscreen"
        INIT_SCRIPT_DEST="/etc/init.d/S99helixscreen"
        KLIPPER_USER="root"
        KLIPPER_GROUP="root"
        KLIPPER_HOME="/usr/data"
        case "$firmware" in
            simple_af)
                PREVIOUS_UI_SCRIPT="/etc/init.d/S99guppyscreen"
                log_info "K1 firmware: Simple AF"
                ;;
            guilouz)
                PREVIOUS_UI_SCRIPT=""
                log_info "K1 firmware: Guilouz Helper Script"
                ;;
            stock_klipper|*)
                PREVIOUS_UI_SCRIPT=""
                log_info "K1 firmware: Stock Klipper"
                ;;
        esac
        log_info "Install directory: ${INSTALL_DIR}"
    elif [ "$platform" = "k2" ]; then
        # Creality K2 series - OpenWrt/Tina Linux, storage on /mnt/UDISK.
        # printer_data lives on /mnt/UDISK (squashfs /root has no space).
        # Some K2 bootstrap projects (k2-improvements) drop a symlink
        # /root/printer_data -> /mnt/UDISK/printer_data/, but the installer
        # runs before that bootstrap for many users — point KLIPPER_HOME at
        # the actual storage so config symlinks work on first install.
        INSTALL_DIR="/opt/helixscreen"
        INIT_SCRIPT_DEST="/etc/init.d/S99helixscreen"
        PREVIOUS_UI_SCRIPT=""
        KLIPPER_USER="root"
        KLIPPER_GROUP="root"
        KLIPPER_HOME="/mnt/UDISK"
        log_info "Platform: Creality K2 series"
        log_info "Install directory: ${INSTALL_DIR}"
    elif [ "$platform" = "cc1" ]; then
        # Elegoo Centauri Carbon running OpenCentauri COSMOS.
        # - / is read-only squashfs; /etc is an overlay on /data (writable).
        # - /user-resource is the 6.3 GB ext4 partition where user installs go.
        # - COSMOS provides gui-switcher: drop /etc/init.d/<name>, then
        #   `config-manager ui screen_ui <name>` + restart gui-switcher.
        INSTALL_DIR="/user-resource/helixscreen"
        INIT_SCRIPT_DEST="/etc/init.d/helixscreen"
        PREVIOUS_UI_SCRIPT=""
        KLIPPER_USER="root"
        KLIPPER_GROUP="root"
        KLIPPER_HOME="/root"
        INIT_SYSTEM="sysv"
        log_info "Platform: Elegoo Centauri Carbon (COSMOS)"
        log_info "Install directory: ${INSTALL_DIR}"
    elif [ "$platform" = "snapmaker-u1" ]; then
        # Snapmaker U1: klipper runs as user 'lava', printer_data lives at
        # /home/lava/printer_data. HelixScreen itself runs as root, but
        # config symlinks must target the lava-owned tree so Mainsail/Fluidd
        # can read them. detect_klipper_user normally finds /home/lava, but
        # on a freshly-flashed U1 before klipper has ever run that path may
        # not exist yet — make it explicit so the installer is deterministic.
        INSTALL_DIR="/userdata/helixscreen"
        KLIPPER_USER="root"
        KLIPPER_GROUP="root"
        KLIPPER_HOME="/home/lava"
        INIT_SYSTEM="sysv"
        # U1 does NOT install /etc/init.d/S99helixscreen. install_service_snapmaker_u1
        # patches the stock /etc/init.d/S99screen to delegate to helixscreen.init for
        # start|stop|restart only (no `status`). Point INIT_SCRIPT_DEST at the real,
        # full-featured init script so post-install commands and stop_service work.
        INIT_SCRIPT_DEST="${INSTALL_DIR}/config/helixscreen.init"
        log_info "Platform: Snapmaker U1"
        log_info "Install directory: ${INSTALL_DIR}"
    else
        # Pi and other platforms — detect klipper user, then auto-detect install dir
        INIT_SCRIPT_DEST="/etc/init.d/S90helixscreen"
        PREVIOUS_UI_SCRIPT=""
        detect_klipper_user
        detect_pi_install_dir
    fi

    # Auto-detect best temp directory (all platforms)
    detect_tmp_dir
}

# User-editable config files that live in printer_data/config/helixscreen/.
# These are the files users may want to edit from Fluidd/Mainsail, and that
# the app writes to at runtime. All other files in INSTALL_DIR/config/ are
# static assets reinstalled on each update.
HELIX_USER_CONFIG_FILES="settings.json helixscreen.env .disabled_services tool_spools.json"

# Set up editable config directory in printer_data/config/helixscreen/.
#
# Creates a real directory (not a symlink) in printer_data/config/helixscreen/
# and symlinks user-editable files FROM the install dir INTO printer_data.
# This reverses the old approach (directory symlink into install dir) which
# was blocked by Moonraker's update_manager reserved path protection.
#
# Layout after setup:
#   ~/printer_data/config/helixscreen/           (real directory)
#   ~/printer_data/config/helixscreen/settings.json     (real file)
#   ~/helixscreen/config/settings.json → above          (symlink)
#
# On upgrade from old layout, migrates files from install dir to printer_data.
# Reads: KLIPPER_HOME, INSTALL_DIR
setup_config_symlink() {
    # Only proceed if we have a Klipper home and install directory
    if [ -z "${KLIPPER_HOME:-}" ] || [ -z "${INSTALL_DIR:-}" ]; then
        return 0
    fi

    local pd_config="${KLIPPER_HOME}/printer_data/config"
    local pd_helix="${pd_config}/helixscreen"
    local install_config="${INSTALL_DIR}/config"

    # Skip if printer_data/config doesn't exist
    if [ ! -d "$pd_config" ]; then
        log_info "No printer_data/config found, skipping config symlink"
        return 0
    fi

    # Skip if install config directory doesn't exist
    if [ ! -d "$install_config" ]; then
        log_warn "Install config directory not found: $install_config"
        return 0
    fi

    # --- Migrate from old layout (directory symlink) ---
    if [ -L "$pd_helix" ]; then
        log_info "Migrating from old config symlink layout..."
        local old_target
        old_target=$(readlink "$pd_helix" 2>/dev/null || echo "")
        $(file_sudo "$pd_helix") rm -f "$pd_helix"
        log_info "Removed old directory symlink (was: $old_target)"
    fi

    # --- Create printer_data/config/helixscreen/ directory ---
    if [ ! -d "$pd_helix" ]; then
        if $(file_sudo "$pd_config") mkdir -p "$pd_helix" 2>/dev/null; then
            log_info "Created $pd_helix"
        else
            log_warn "Could not create $pd_helix (permission denied?)"
            return 0
        fi
    fi

    # --- Migrate helixconfig.json → settings.json in printer_data if needed ---
    if [ -f "${pd_helix}/helixconfig.json" ] && [ ! -f "${pd_helix}/settings.json" ]; then
        $(file_sudo "$pd_helix") mv "${pd_helix}/helixconfig.json" "${pd_helix}/settings.json"
        log_info "Migrated printer_data config: helixconfig.json → settings.json"
    fi
    # Remove old symlink if it exists (new one will be created by HELIX_USER_CONFIG_FILES loop)
    if [ -L "${install_config}/helixconfig.json" ]; then
        $(file_sudo "$install_config") rm "${install_config}/helixconfig.json"
        log_info "Removed old helixconfig.json symlink"
    fi

    # --- Set up per-file symlinks ---
    local file
    for file in $HELIX_USER_CONFIG_FILES; do
        local pd_file="${pd_helix}/${file}"
        local install_file="${install_config}/${file}"

        # If the install dir has a real file (not a symlink), move it to printer_data
        if [ -f "$install_file" ] && [ ! -L "$install_file" ]; then
            if [ ! -f "$pd_file" ]; then
                # Move the file to printer_data — check for success before removing original.
                # A silent cp failure followed by rm would permanently destroy the user's config.
                if $(file_sudo "$pd_helix") cp "$install_file" "$pd_file" 2>/dev/null; then
                    log_info "Migrated $file to printer_data"
                else
                    log_warn "Could not migrate $file to printer_data — keeping in install dir"
                    continue  # Skip symlink creation; leave the real file in place
                fi
            fi
            # Remove the original so we can create the symlink
            $(file_sudo "$install_config") rm -f "$install_file" 2>/dev/null
        fi

        # If pd_file still doesn't exist (e.g. runtime-created file like tool_spools.json
        # or .disabled_services that isn't packaged and hasn't been written yet), skip
        # symlink creation.  A dangling symlink is worse than no symlink: reads return
        # ENOENT and writes may fail depending on the OS/filesystem.  The app will
        # create the file at pd_file naturally; setup_config_symlink will wire it up
        # correctly on the next update or reinstall.
        if [ ! -f "$pd_file" ] && [ ! -L "$pd_file" ]; then
            # Only skip if install_file also doesn't exist or isn't already a symlink
            if [ ! -L "$install_file" ]; then
                continue
            fi
        fi

        # Create symlink: install_dir/config/file → printer_data/config/helixscreen/file
        if [ -L "$install_file" ]; then
            local current_target
            current_target=$(readlink "$install_file" 2>/dev/null || echo "")
            if [ "$current_target" = "$pd_file" ]; then
                continue  # Already correct
            fi
            $(file_sudo "$install_config") rm -f "$install_file" 2>/dev/null
        fi

        if $(file_sudo "$install_config") ln -s "$pd_file" "$install_file" 2>/dev/null; then
            : # Symlink created
        else
            log_warn "Could not create symlink for $file"
        fi
    done

    log_success "Config directory: $pd_helix"
    log_info "You can now edit HelixScreen config from Mainsail/Fluidd"
    return 0
}

# Remove config symlinks and optionally the printer_data directory.
# Called during uninstall. Preserves user files in printer_data.
# Reads: KLIPPER_HOME, INSTALL_DIR
remove_config_symlink() {
    if [ -z "${KLIPPER_HOME:-}" ] || [ -z "${INSTALL_DIR:-}" ]; then
        return 0
    fi

    local pd_helix="${KLIPPER_HOME}/printer_data/config/helixscreen"
    local install_config="${INSTALL_DIR}/config"

    # Remove per-file symlinks from install dir
    local file
    for file in $HELIX_USER_CONFIG_FILES; do
        local install_file="${install_config}/${file}"
        if [ -L "$install_file" ]; then
            rm -f "$install_file" 2>/dev/null
        fi
    done

    # Remove old-style directory symlink if present
    if [ -L "$pd_helix" ]; then
        rm -f "$pd_helix" 2>/dev/null
        log_info "Removed old config directory symlink"
    fi

    # Leave printer_data/config/helixscreen/ directory intact — user's config files
    if [ -d "$pd_helix" ]; then
        log_info "User config preserved at: $pd_helix"
    fi

    return 0
}

# Fix known Klipper config issues on AD5M KlipperMod printers.
# The AD5M ships with screw_thread: CW-M4 but the correct value is CCW-M4.
# This causes SCREWS_TILT_CALCULATE to output inverted CW/CCW directions,
# leading users to tighten when they should loosen (and vice versa).
# Only applies to KlipperMod (Forge-X and ZMOD don't ship screws_tilt_adjust).
fix_ad5m_klipper_config() {
    # Guard: only run on AD5M KlipperMod (uses lowercase $platform from main())
    if [ "${platform:-}" != "ad5m" ] || [ "${AD5M_FIRMWARE:-}" != "klipper_mod" ]; then
        return 0
    fi

    log_info "Checking AD5M Klipper config for known issues..."

    local config_dir="${KLIPPER_HOME}/printer_data/config"
    if [ ! -d "$config_dir" ]; then
        log_info "No printer_data/config found, skipping Klipper config fixup"
        return 0
    fi

    # Find config file with screws_tilt_adjust containing exactly "CW-M4"
    # (not "CCW-M4" — grep -w ensures word boundary so CW-M4 won't match CCW-M4)
    local target_file=""
    for cfg_file in "$config_dir"/printer.base.cfg "$config_dir"/printer.cfg; do
        [ -f "$cfg_file" ] || continue
        if grep -q '\[screws_tilt_adjust\]' "$cfg_file" && \
           grep -qw 'CW-M4' "$cfg_file" && \
           ! grep -qw 'CCW-M4' "$cfg_file"; then
            target_file="$cfg_file"
            break
        fi
    done

    if [ -z "$target_file" ]; then
        log_info "AD5M screw_thread config OK (or not present)"
        return 0
    fi

    log_info "Found incorrect screw_thread in: $target_file"
    log_info "  CW-M4 → CCW-M4 (AD5M bed screws need reverse direction)"

    # Backup before modifying
    local backup_file="${target_file}.pre-helix"
    if [ ! -f "$backup_file" ]; then
        $SUDO cp "$target_file" "$backup_file"
        log_info "  Backup: $backup_file"
    fi

    # Fix: replace exactly "CW-M4" with "CCW-M4" on screw_thread lines only.
    # Anchored on line start (^) and end ($) to prevent matching CCW-M4.
    # Uses temp file instead of sed -i for portability (macOS vs BusyBox).
    local tmp_file="${target_file}.tmp"
    $SUDO sed 's/^\(screw_thread:[[:space:]]*\)CW-M4$/\1CCW-M4/' "$target_file" > "$tmp_file"
    $SUDO mv "$tmp_file" "$target_file"

    if grep -qw 'CCW-M4' "$target_file"; then
        log_success "Fixed AD5M screw_thread: CW-M4 → CCW-M4"
    else
        log_warn "Failed to fix screw_thread, restoring backup"
        $SUDO cp "$backup_file" "$target_file"
        return 1
    fi

    return 0
}

# ============================================
# Module: permissions.sh
# ============================================

#
# Initialize SUDO (will be set by check_permissions)
SUDO=""
# Check if running as root (required for AD5M/K1, optional for Pi)
# Sets: SUDO variable ("sudo" or "")
check_permissions() {
    local platform=$1

    case "$platform" in
    ad5m|ad5x|k1|k2)
        if [ "$(id -u)" != "0" ]; then
            log_error "Installation on $platform requires root privileges."
            log_error "Please run: sudo $0 $*"
            exit 1
        fi
        SUDO=""
        ;;
    *)
        # Pi: warn if not root but allow sudo
        if [ "$(id -u)" != "0" ]; then
            if ! command -v sudo >/dev/null 2>&1; then
                log_error "Not running as root and sudo is not available."
                log_error "Please run as root or install sudo."
                exit 1
            fi
            log_info "Not running as root. Will use sudo for privileged operations."
            SUDO="sudo"
        else
            SUDO=""
        fi
        ;;
    esac
}

# Check if a polkit rule for HelixScreen exists (either .rules or .pkla)
_polkit_rule_exists() {
    local pkla="/etc/polkit-1/localauthority/50-local.d/helixscreen-network.pkla"
    local rules="/etc/polkit-1/rules.d/49-helixscreen-network.rules"
    local rules_old="/etc/polkit-1/rules.d/50-helixscreen-network.rules"

    test -f "$rules" 2>/dev/null && return 0
    test -f "$rules_old" 2>/dev/null && return 0
    test -f "$pkla" 2>/dev/null && return 0
    return 1
}

# Check if deployed permission rules contain un-substituted templates
_permission_rules_need_repair() {
    local helix_user="$1"
    local pkla="/etc/polkit-1/localauthority/50-local.d/helixscreen-network.pkla"
    local rules="/etc/polkit-1/rules.d/49-helixscreen-network.rules"

    # Check pkla file for literal placeholder (parent dir may be root-only)
    if $SUDO test -f "$pkla" && $SUDO grep -q '@@HELIX_USER@@' "$pkla" 2>/dev/null; then
        return 0
    fi
    # Check JS rules file for literal placeholder
    if $SUDO test -f "$rules" && $SUDO grep -q '@@HELIX_USER@@' "$rules" 2>/dev/null; then
        return 0
    fi
    return 1
}

# Install system permission rules for non-root operation
# - udev rule: backlight brightness write access for video group
# - polkit rule: NetworkManager access for service user
# Only installed on platforms that run as non-root (Pi, generic Linux)
install_permission_rules() {
    local platform=$1
    local helix_user="${KLIPPER_USER:-root}"

    # Skip for platforms that run as root or if user is root
    case "$platform" in ad5m|ad5x|k1|k2) helix_user="root" ;; esac
    if [ "$helix_user" = "root" ]; then
        log_info "Skipping permission rules (running as root)"
        return 0
    fi

    # Under NoNewPrivileges (self-update), sudo is blocked.  Check if rules
    # are already correctly deployed before skipping.
    if _has_no_new_privs; then
        if command -v nmcli >/dev/null 2>&1 && ! _polkit_rule_exists; then
            log_warn "NetworkManager polkit rule is MISSING — Wi-Fi will not work as non-root."
            log_warn "Fix by re-running the installer:  curl -fsSL https://releases.helixscreen.org/install.sh | bash"
        elif _permission_rules_need_repair "$helix_user"; then
            log_warn "Permission rules need repair (pkla/polkit file has un-substituted template)."
            log_warn "Wi-Fi may not work. Fix with:  sudo sed -i 's|@@HELIX_USER@@|${helix_user}|g' /etc/polkit-1/localauthority/50-local.d/helixscreen-network.pkla"
            log_warn "Or re-run the installer:  curl -fsSL https://releases.helixscreen.org/install.sh | bash"
        else
            log_info "Skipping permission rules (NoNewPrivileges; already installed)"
        fi
        return 0
    fi

    # --- Backlight udev rule ---
    local udev_src="${INSTALL_DIR}/config/99-helixscreen-backlight.rules"
    local udev_dest="/etc/udev/rules.d/99-helixscreen-backlight.rules"

    if [ -f "$udev_src" ] && [ -d /etc/udev/rules.d ]; then
        $SUDO cp "$udev_src" "$udev_dest"
        # Trigger udev to apply immediately for any existing backlight devices
        $SUDO udevadm trigger --subsystem-match=backlight 2>/dev/null || true
        log_info "Installed backlight udev rule"
    fi

    # --- NetworkManager polkit rule ---
    # All content is generated inline — no template files, no sed, no @@HELIX_USER@@.
    if command -v nmcli >/dev/null 2>&1; then
        # polkit JavaScript rules for newer polkit (Debian 12+, polkit >= 0.106)
        local rules_dir="/etc/polkit-1/rules.d"
        # polkit local authority (.pkla) for older polkit (Debian 11 and similar)
        local pkla_dir="/etc/polkit-1/localauthority/50-local.d"

        if $SUDO test -d "$rules_dir"; then
            local rules_dest="${rules_dir}/49-helixscreen-network.rules"
            if $SUDO tee "$rules_dest" > /dev/null << POLKIT_EOF
// Installed by HelixScreen — allow service user to manage NetworkManager
polkit.addRule(function(action, subject) {
    if (action.id.indexOf("org.freedesktop.NetworkManager.") === 0 &&
        subject.user === "${helix_user}") {
        return polkit.Result.YES;
    }
});
POLKIT_EOF
            then
                log_info "Installed NetworkManager polkit rule (.rules for ${helix_user})"
            else
                log_warn "Failed to install polkit rule to ${rules_dest} — Wi-Fi scanning may not work"
            fi
            # Clean up old 50- rule and stale .pkla from older installs / OS upgrades
            $SUDO rm -f "${rules_dir}/50-helixscreen-network.rules" 2>/dev/null || true
            local stale_pkla="${pkla_dir}/helixscreen-network.pkla"
            if $SUDO test -f "$stale_pkla" 2>/dev/null; then
                $SUDO rm -f "$stale_pkla" 2>/dev/null || true
                log_info "Removed stale .pkla file (superseded by .rules)"
            fi
        elif $SUDO test -d "$pkla_dir"; then
            local pkla_dest="${pkla_dir}/helixscreen-network.pkla"
            if $SUDO tee "$pkla_dest" > /dev/null << PKLA_EOF
# polkit local authority rule: allow HelixScreen service user to manage
# NetworkManager connections (Wi-Fi connect/disconnect/scan)
# Installed by HelixScreen for non-root service operation
[HelixScreen NetworkManager access]
Identity=unix-user:${helix_user}
Action=org.freedesktop.NetworkManager.*
ResultAny=yes
ResultInactive=yes
ResultActive=yes
PKLA_EOF
            then
                log_info "Installed NetworkManager polkit rule (.pkla for ${helix_user})"
            else
                log_warn "Failed to install polkit rule to ${pkla_dest} — Wi-Fi scanning may not work"
            fi
        else
            log_warn "polkit rules directory not found — Wi-Fi may not work as non-root"
        fi

        # Reload polkit to pick up the new rule immediately
        if systemctl is-active polkit >/dev/null 2>&1; then
            $SUDO systemctl restart polkit 2>/dev/null || true
            log_info "Restarted polkit to apply new rules"
        fi
    fi
}

# ============================================
# Module: requirements.sh
# ============================================

#
# Initialize INIT_SYSTEM (will be set by detect_init_system)
INIT_SYSTEM=""
# Run `apt-get update` at most once per installer run. The first call updates
# the package index; subsequent calls become no-ops. Avoids 5-15s of redundant
# index refreshes when both check_requirements and install_runtime_deps need apt.
_HELIX_APT_UPDATED=""
_apt_update_once() {
    [ -n "$_HELIX_APT_UPDATED" ] && return 0
    $SUDO apt-get update -qq 2>/dev/null || true
    _HELIX_APT_UPDATED=1
}

# Append a name to the global $missing list, comma-separated.
_helix_add_missing() { missing="${missing:+$missing, }$1"; }

# Check required commands exist. unzip is mandatory because release archives
# ship as .zip (Moonraker Update Manager contract); tar/gunzip remain required
# for bridge-release tar.gz fallback until 1.0 retires the format.
check_requirements() {
    local missing=""

    # Need curl, wget, or python3 (urllib) to download the release.
    if ! command -v curl >/dev/null 2>&1 && ! command -v wget >/dev/null 2>&1 && ! _has_python; then
        _helix_add_missing "curl, wget, or python3"
    fi
    command -v tar >/dev/null 2>&1 || _helix_add_missing "tar"
    # gunzip needed for AD5M BusyBox tar which doesn't support -z
    command -v gunzip >/dev/null 2>&1 || _helix_add_missing "gunzip"

    # Zip extraction: prefer unzip, but python's zipfile module is a built-in
    # fallback (used on platforms like recent Creality K2 firmware that lack
    # unzip but ship python3). The fallback needs zipfile + zlib (release zips
    # are DEFLATE-compressed), so gate on those modules rather than mere python
    # presence — otherwise a zlib-less python passes here and the install dies
    # in extract_release instead of failing fast with a clear message. Try a
    # transparent apt-install of unzip on Debian/Ubuntu images that lack it
    # (notably Snapmaker U1 extended firmware); only mark it missing when
    # there's no apt AND no usable python zipfile fallback.
    if ! command -v unzip >/dev/null 2>&1; then
        if command -v apt-get >/dev/null 2>&1 && ! _has_no_new_privs; then
            log_info "Installing missing dependency: unzip"
            _apt_update_once
            $SUDO apt-get install -y --no-install-recommends unzip >/dev/null 2>&1 || true
            if ! command -v unzip >/dev/null 2>&1 && ! _py_has_module zipfile zlib; then
                _helix_add_missing "unzip"
            fi
        elif ! _py_has_module zipfile zlib; then
            _helix_add_missing "unzip"
        fi
    fi

    if [ -n "$missing" ]; then
        log_error "Missing required commands: $missing"
        log_error "Please install them and try again."
        exit 1
    fi

    log_success "All required commands available"
}

# Install runtime dependencies for Pi platform
# Required for DRM display and evdev input handling
# AD5M uses framebuffer with static linking, no deps needed
install_runtime_deps() {
    local platform=$1

    # Only needed for Pi (32-bit and 64-bit) - AD5M uses framebuffer with static linking
    if [ "$platform" != "pi" ] && [ "$platform" != "pi32" ]; then
        return 0
    fi

    log_info "Checking runtime dependencies for display/input..."

    # Required libraries for DRM display, libinput, GPU rendering, and camera
    # GPU libs are needed for DRM+EGL hardware-accelerated rendering on Pi
    # libturbojpeg: SIMD-accelerated JPEG decode for camera MJPEG streams
    #   Debian names it libturbojpeg0, Ubuntu names it libturbojpeg
    # Note: OpenSSL is statically linked for Pi builds, no runtime libssl needed
    local deps="libdrm2 libinput10 libgbm1 libegl1 libgles2"
    local missing=""

    # turbojpeg: package name varies by distro (Debian=libturbojpeg0, Ubuntu=libturbojpeg)
    local turbo_pkg=""
    for candidate in libturbojpeg0 libturbojpeg; do
        if dpkg-query -W -f='${Status}' "$candidate" 2>/dev/null | grep -q "install ok installed" || \
           apt-cache show "$candidate" 2>/dev/null | grep -q "^Package:"; then
            turbo_pkg="$candidate"
            break
        fi
    done
    if [ -n "$turbo_pkg" ]; then
        deps="$deps $turbo_pkg"
    else
        log_warn "No turbojpeg package found (tried libturbojpeg0, libturbojpeg)"
        log_warn "JPEG thumbnail decoding may not work"
    fi

    for dep in $deps; do
        # Check if package is installed (dpkg-query returns 0 if installed)
        if ! dpkg-query -W -f='${Status}' "$dep" 2>/dev/null | grep -q "install ok installed"; then
            if [ -n "$missing" ]; then
                missing="$missing $dep"
            else
                missing="$dep"
            fi
        fi
    done

    if [ -n "$missing" ]; then
        # Under NoNewPrivileges (self-update from the running app), sudo is blocked.
        # Warn about missing deps but don't fail — the binary may still work, and
        # verify_binary_deps() will catch truly fatal missing libraries later.
        if _has_no_new_privs; then
            log_warn "Missing runtime libraries (cannot install under self-update): $missing"
            log_warn "Install manually after update: sudo apt-get install $missing"
            return 0
        fi
        log_info "Installing missing libraries: $missing"
        _apt_update_once
        # shellcheck disable=SC2086
        if ! $SUDO apt-get install -y --no-install-recommends $missing; then
            log_warn "Failed to install some runtime libraries: $missing"
            log_warn "The update will continue. Install manually: sudo apt-get install $missing"
        else
            log_success "Runtime libraries installed"
        fi
    else
        log_success "All runtime libraries already installed"
    fi
}

# Check available disk space
# Requires at least 50MB free on the install directory's filesystem
# Note: INSTALL_DIR must be set before calling this function
check_disk_space() {
    local platform=$1
    local required_mb=50

    # Get the parent directory of install location (the filesystem to check)
    local check_dir
    check_dir=$(dirname "${INSTALL_DIR:-/opt/helixscreen}")
    # Walk up until we find an existing directory
    while [ ! -d "$check_dir" ] && [ "$check_dir" != "/" ]; do
        check_dir=$(dirname "$check_dir")
    done
    if [ "$check_dir" = "/" ]; then
        check_dir="/"
    fi

    # Get available space in MB
    local available_mb
    case "$platform" in
        ad5m|ad5x|k1|k2)
            # BusyBox df: blocks are in KB by default
            available_mb=$(df "$check_dir" 2>/dev/null | tail -1 | awk '{print int($4/1024)}')
            ;;
        *)
            # GNU df with -m flag outputs in MB
            available_mb=$(df -m "$check_dir" 2>/dev/null | tail -1 | awk '{print $4}')
            ;;
    esac

    if [ -n "$available_mb" ] && [ "$available_mb" -lt "$required_mb" ]; then
        log_error "Insufficient disk space on $check_dir"
        log_error "Required: ${required_mb}MB, Available: ${available_mb}MB"
        exit 1
    fi

    log_info "Disk space check: ${available_mb}MB available on $check_dir"
}

# Detect init system (systemd vs SysV)
# Sets: INIT_SYSTEM to "systemd" or "sysv"
detect_init_system() {
    # Check for systemd
    if command -v systemctl >/dev/null 2>&1 && [ -d /run/systemd/system ]; then
        INIT_SYSTEM="systemd"
        log_info "Init system: systemd"
        return
    fi

    # Check for SysV init (BusyBox or traditional)
    if [ -d /etc/init.d ]; then
        INIT_SYSTEM="sysv"
        log_info "Init system: SysV (BusyBox/traditional)"
        return
    fi

    log_error "Could not detect init system."
    log_error "Neither systemd nor /etc/init.d found."
    exit 1
}

# Check that Klipper and Moonraker are running (AD5M + K1 only)
# These platforms require local Klipper/Moonraker; without them HelixScreen
# has nothing to connect to. Warns and prompts for confirmation.
check_klipper_ecosystem() {
    local platform=$1

    # Only relevant for embedded platforms with local Klipper
    case "$platform" in
        ad5m|ad5x|k1|k2) ;;
        *) return 0 ;;
    esac

    local warnings=""

    # Check Klipper process
    # Klipper runs as "klippy" (python module) or "klipper" (service name)
    if ! ps | grep -v grep | grep -q -e '[Kk]lipper' -e '[Kk]lippy'; then
        warnings="Klipper does not appear to be running."
    fi

    # Check Moonraker process
    if ! ps | grep -v grep | grep -q '[Mm]oonraker'; then
        if [ -n "$warnings" ]; then
            warnings="$warnings
Moonraker does not appear to be running."
        else
            warnings="Moonraker does not appear to be running."
        fi
    fi

    # If Moonraker process is up, verify it responds on the expected port
    if ps | grep -v grep | grep -q '[Mm]oonraker'; then
        if command -v wget >/dev/null 2>&1; then
            if ! wget -q -O /dev/null --timeout=5 "http://127.0.0.1:7125/server/info" 2>/dev/null; then
                if [ -n "$warnings" ]; then
                    warnings="$warnings
Moonraker is running but not responding on http://127.0.0.1:7125."
                else
                    warnings="Moonraker is running but not responding on http://127.0.0.1:7125."
                fi
            fi
        elif command -v curl >/dev/null 2>&1; then
            if ! curl -sf --connect-timeout 5 "http://127.0.0.1:7125/server/info" >/dev/null 2>&1; then
                if [ -n "$warnings" ]; then
                    warnings="$warnings
Moonraker is running but not responding on http://127.0.0.1:7125."
                else
                    warnings="Moonraker is running but not responding on http://127.0.0.1:7125."
                fi
            fi
        fi
    fi

    # Everything looks good
    if [ -z "$warnings" ]; then
        log_success "Klipper and Moonraker are running"
        return 0
    fi

    # Show warnings and prompt
    log_warn ""
    log_warn "WARNING: Klipper ecosystem check failed:"
    # Print each warning line separately
    echo "$warnings" | while IFS= read -r line; do
        log_warn "  - $line"
    done
    log_warn ""
    log_warn "HelixScreen requires Klipper and Moonraker to function."
    log_warn "It will install but won't work until these services are available."

    # Non-interactive mode: just warn and continue
    if [ ! -t 0 ]; then
        log_warn "Non-interactive mode: continuing anyway."
        return 0
    fi

    printf "Continue anyway? [y/N] "
    read -r answer
    case "$answer" in
        [Yy]|[Yy][Ee][Ss])
            log_info "Continuing installation..."
            return 0
            ;;
        *)
            log_error "Installation cancelled."
            exit 1
            ;;
    esac
}

# Verify the installed binary can find all shared libraries
# Runs ldd on the binary and checks for "not found" entries.
# If libssl.so.1.1 is missing (Bullseye→Bookworm upgrade), tries to install compat package.
# Called after extraction, before starting the service.
# Requires: INSTALL_DIR
verify_binary_deps() {
    local platform=$1
    local binary="${INSTALL_DIR}/bin/helix-screen"

    # Only relevant for platforms with dynamic linking and ldd
    if ! command -v ldd >/dev/null 2>&1; then
        return 0
    fi

    # Binary must exist
    if [ ! -f "$binary" ]; then
        log_warn "Binary not found at $binary, skipping dependency check"
        return 0
    fi

    # Check for missing shared libraries
    local missing_libs
    missing_libs=$(ldd "$binary" 2>/dev/null | grep "not found" || true)

    if [ -z "$missing_libs" ]; then
        log_success "All shared library dependencies satisfied"
        return 0
    fi

    log_warn "Missing shared libraries detected:"
    echo "$missing_libs" | while IFS= read -r line; do
        log_warn "  $line"
    done

    # Try to fix known issues on Pi
    case "$platform" in
        pi|pi32)
            # libssl.so.1.1 missing = Bookworm system with Bullseye-era binary
            if echo "$missing_libs" | grep -q "libssl.so.1.1"; then
                log_info "libssl.so.1.1 not found (common after Debian Bullseye→Bookworm upgrade)"
                # Try installing the compat package if available
                if apt-cache show libssl1.1 >/dev/null 2>&1; then
                    log_info "Installing libssl1.1 compatibility package..."
                    $SUDO apt-get install -y --no-install-recommends libssl1.1
                else
                    log_error "libssl1.1 package not available in your repositories."
                    log_error "This binary was built against OpenSSL 1.1 but your system has OpenSSL 3."
                    log_error "Please update HelixScreen to the latest version which includes OpenSSL statically."
                    exit 1
                fi
            fi

            # Re-check after attempted fixes
            missing_libs=$(ldd "$binary" 2>/dev/null | grep "not found" || true)
            if [ -n "$missing_libs" ]; then
                # Check if fbdev fallback binary exists and is loadable
                local fallback="${INSTALL_DIR}/bin/helix-screen-fbdev"
                if [ -x "$fallback" ]; then
                    local fb_missing
                    fb_missing=$(ldd "$fallback" 2>/dev/null | grep "not found" || true)
                    if [ -z "$fb_missing" ]; then
                        log_warn "DRM binary has missing GL libraries -- fbdev fallback will be used"
                        log_warn "Install GPU libraries for hardware acceleration: sudo apt install libgbm1 libegl1 libgles2"
                        return 0
                    fi
                fi
                # Under NoNewPrivileges (self-update), we can't install libs.
                # Warn but don't block — the binary may still start with reduced
                # functionality (e.g. no SIMD camera decode).
                if _has_no_new_privs; then
                    log_warn "Missing libraries (cannot install during self-update):"
                    echo "$missing_libs" | while IFS= read -r line; do
                        log_warn "  $line"
                    done
                    # Extract library basenames (e.g. "libturbojpeg.so.0") for user guidance
                    local lib_names
                    lib_names=$(echo "$missing_libs" | awk '{print $1}' | tr '\n' ' ')
                    log_warn "Install manually: sudo apt-get install packages providing: $lib_names"
                    return 0
                fi
                # No usable fallback — original error behavior
                log_error "Could not resolve all missing libraries:"
                echo "$missing_libs" | while IFS= read -r line; do
                    log_error "  $line"
                done
                log_error "The binary may not start correctly."
                log_error "Please report this issue at https://github.com/prestonbrown/helixscreen/issues"
                exit 1
            fi
            log_success "All shared library dependencies resolved"
            ;;
        *)
            # Non-Pi platforms: just warn, don't block
            log_warn "Some libraries are missing. The binary may not start correctly."
            ;;
    esac
}

# ============================================
# Module: forgex.sh
# ============================================

#
# Configure ForgeX display settings for HelixScreen
# We use GUPPY mode because ForgeX handles backlight properly in this mode.
# STOCK mode expects ffstartup-arm to manage display/backlight which doesn't work for us.
# We disable GuppyScreen's init scripts so HelixScreen takes over the display.
configure_forgex_display() {
    var_file="/opt/config/mod_data/variables.cfg"
    guppy_init="/opt/config/mod/.root/S80guppyscreen"
    tslib_init="/opt/config/mod/.root/S35tslib"
    changed=false

    # Set display mode to GUPPY (required for backlight to work)
    if [ -f "$var_file" ]; then
        if grep -q "display[[:space:]]*=[[:space:]]*'STOCK'" "$var_file"; then
            log_info "Setting ForgeX display mode to GUPPY..."
            $SUDO sed -i "s/display[[:space:]]*=[[:space:]]*'STOCK'/display = 'GUPPY'/" "$var_file"
            changed=true
        elif grep -q "display[[:space:]]*=[[:space:]]*'HEADLESS'" "$var_file"; then
            log_info "Setting ForgeX display mode to GUPPY..."
            $SUDO sed -i "s/display[[:space:]]*=[[:space:]]*'HEADLESS'/display = 'GUPPY'/" "$var_file"
            changed=true
        fi
    fi

    # Disable GuppyScreen init script (remove execute permission)
    if [ -x "$guppy_init" ]; then
        log_info "Disabling GuppyScreen init script..."
        $SUDO chmod a-x "$guppy_init"
        changed=true
    fi

    # Disable tslib init script (GuppyScreen's touch input layer)
    # HelixScreen uses its own input handling
    if [ -x "$tslib_init" ]; then
        log_info "Disabling tslib init script..."
        $SUDO chmod a-x "$tslib_init"
        changed=true
    fi

    if [ "$changed" = true ]; then
        log_success "ForgeX configured for HelixScreen (GUPPY mode, GuppyScreen disabled)"
        return 0
    fi
    return 1
}

# Patch ForgeX screen.sh to skip non-100 backlight control when HelixScreen is active
# ForgeX's headless.cfg runs a delayed_gcode that dims the backlight 3 seconds after
# Klipper starts. This patch blocks dimming calls but allows the S99root 0→100 cycle.
#
# The smart patch:
# - Allows "backlight 100" (needed for S99root initialization cycle)
# - Blocks other values (10, 0, etc.) when helixscreen_active flag exists
patch_forgex_screen_sh() {
    screen_sh="/opt/config/mod/.shell/screen.sh"

    if [ ! -f "$screen_sh" ]; then
        log_info "ForgeX screen.sh not found, skipping patch"
        return 1
    fi

    # Check if already patched (look for the smart patch signature)
    if grep -q 'helixscreen_active.*!=.*100' "$screen_sh" 2>/dev/null; then
        log_info "ForgeX screen.sh already has smart patch"
        return 0
    fi

    # Remove old-style patch if present (blocks ALL backlight when flag exists)
    if grep -q "helixscreen_active" "$screen_sh" 2>/dev/null; then
        log_info "Removing old-style patch from screen.sh..."
        tmp_file="${screen_sh}.tmp"
        grep -v "helixscreen_active\|# Skip if HelixScreen" "$screen_sh" > "$tmp_file"
        $SUDO mv "$tmp_file" "$screen_sh"
        $SUDO chmod +x "$screen_sh"
    fi

    # Find the backlight) case and add our guard
    if ! grep -q "^[[:space:]]*backlight)" "$screen_sh"; then
        log_info "Could not find backlight case in screen.sh"
        return 1
    fi

    log_info "Patching ForgeX screen.sh with smart backlight control..."

    # Use awk to insert our check after "backlight)" line (BusyBox compatible)
    # Smart patch: only block non-100 values, allowing S99root's 0→100 init cycle
    tmp_file="${screen_sh}.tmp"
    awk '
    /^[[:space:]]*backlight\)/ {
        print
        print "        # Skip non-100 backlight changes when HelixScreen is controlling display"
        print "        # Allows S99root 0->100 init cycle but blocks Klipper eco dimming"
        print "        if [ -f /tmp/helixscreen_active ] && [ \"$2\" != \"100\" ]; then"
        print "            exit 0"
        print "        fi"
        next
    }
    { print }
    ' "$screen_sh" > "$tmp_file"

    if [ -s "$tmp_file" ] && grep -q 'helixscreen_active.*!=.*100' "$tmp_file" 2>/dev/null; then
        $SUDO mv "$tmp_file" "$screen_sh"
        $SUDO chmod +x "$screen_sh"
        log_success "ForgeX screen.sh patched with smart backlight control"
        return 0
    else
        rm -f "$tmp_file"
        log_warn "Failed to patch ForgeX screen.sh"
        return 1
    fi
}

# Remove HelixScreen patch from ForgeX screen.sh (for uninstall)
unpatch_forgex_screen_sh() {
    screen_sh="/opt/config/mod/.shell/screen.sh"

    if [ ! -f "$screen_sh" ]; then
        return 1
    fi

    # Check if patched
    if ! grep -q "helixscreen_active" "$screen_sh" 2>/dev/null; then
        log_info "ForgeX screen.sh not patched, nothing to remove"
        return 0
    fi

    log_info "Removing HelixScreen patch from ForgeX screen.sh..."

    # Use awk to remove only our specific block (BusyBox compatible)
    # Match and skip: comment line, if line with helixscreen_active, exit 0, fi
    tmp_file="${screen_sh}.tmp"
    awk '
    /# Skip if HelixScreen is controlling the display/ { skip=1; next }
    /if \[ -f \/tmp\/helixscreen_active \]; then/ { skip=1; next }
    skip && /^[[:space:]]*exit 0[[:space:]]*$/ { next }
    skip && /^[[:space:]]*fi[[:space:]]*$/ { skip=0; next }
    { print }
    ' "$screen_sh" > "$tmp_file"

    if [ -s "$tmp_file" ]; then
        $SUDO mv "$tmp_file" "$screen_sh"
        $SUDO chmod +x "$screen_sh"
    else
        rm -f "$tmp_file"
        log_warn "Failed to unpatch ForgeX screen.sh"
        return 1
    fi

    # Verify removal
    if grep -q "helixscreen_active" "$screen_sh" 2>/dev/null; then
        log_warn "Could not fully remove patch from screen.sh"
        return 1
    fi

    log_success "ForgeX screen.sh patch removed"
    return 0
}

# Disable stock FlashForge UI in auto_run.sh
# The stock firmware UI (ffstartup-arm/firmwareExe) is started by /opt/auto_run.sh
# which runs AFTER init scripts. We comment out the line to prevent it starting.
disable_stock_firmware_ui() {
    auto_run="/opt/auto_run.sh"
    if [ -f "$auto_run" ]; then
        # Check if ffstartup-arm line exists and is not already commented
        if grep -q "^/opt/PROGRAM/ffstartup-arm" "$auto_run"; then
            log_info "Disabling stock FlashForge UI in auto_run.sh..."
            # Comment out the ffstartup-arm line
            $SUDO sed -i 's|^/opt/PROGRAM/ffstartup-arm|# Disabled by HelixScreen: /opt/PROGRAM/ffstartup-arm|' "$auto_run"
            log_success "Stock FlashForge UI disabled"
            return 0
        fi
    fi
    return 1
}

# Re-enable stock FlashForge UI in auto_run.sh (for uninstall)
restore_stock_firmware_ui() {
    auto_run="/opt/auto_run.sh"
    if [ -f "$auto_run" ]; then
        # Check if our disabled line exists
        if grep -q "^# Disabled by HelixScreen: /opt/PROGRAM/ffstartup-arm" "$auto_run"; then
            log_info "Re-enabling stock FlashForge UI in auto_run.sh..."
            # Uncomment the ffstartup-arm line
            $SUDO sed -i 's|^# Disabled by HelixScreen: /opt/PROGRAM/ffstartup-arm|/opt/PROGRAM/ffstartup-arm|' "$auto_run"
            log_success "Stock FlashForge UI re-enabled"
            return 0
        fi
    fi
    return 1
}

# Patch ForgeX screen.sh to skip screen drawing when HelixScreen is active
# ForgeX's S99root calls draw_splash, draw_loading, and boot_message which write
# directly to the framebuffer, overwriting our splash screen during boot.
patch_forgex_screen_drawing() {
    screen_sh="/opt/config/mod/.shell/screen.sh"

    if [ ! -f "$screen_sh" ]; then
        log_info "ForgeX screen.sh not found, skipping screen drawing patch"
        return 1
    fi

    # Check if already patched (look for our signature in draw_splash)
    if grep -q 'draw_splash)' "$screen_sh" && \
       grep -A2 'draw_splash)' "$screen_sh" | grep -q 'helixscreen_active'; then
        log_info "ForgeX screen.sh already has screen drawing patches"
        return 0
    fi

    log_info "Patching ForgeX screen.sh to skip drawing when HelixScreen active..."

    # Patch draw_loading, draw_splash, and boot_message cases
    # Add helixscreen_active check after each case label
    tmp_file="${screen_sh}.tmp"
    awk '
    /^[[:space:]]*(draw_loading|draw_splash|boot_message)\)/ {
        print
        print "        # Skip when HelixScreen is controlling display"
        print "        if [ -f /tmp/helixscreen_active ]; then"
        print "            exit 0"
        print "        fi"
        next
    }
    { print }
    ' "$screen_sh" > "$tmp_file"

    if [ -s "$tmp_file" ] && grep -q 'helixscreen_active' "$tmp_file" 2>/dev/null; then
        $SUDO mv "$tmp_file" "$screen_sh"
        $SUDO chmod +x "$screen_sh"
        log_success "ForgeX screen.sh patched for screen drawing"
        return 0
    else
        rm -f "$tmp_file"
        log_warn "Failed to patch ForgeX screen.sh for screen drawing"
        return 1
    fi
}

# Remove screen drawing patches from ForgeX screen.sh (for uninstall)
unpatch_forgex_screen_drawing() {
    screen_sh="/opt/config/mod/.shell/screen.sh"

    if [ ! -f "$screen_sh" ]; then
        return 1
    fi

    # Check if our drawing patches are present
    if ! grep -q '# Skip when HelixScreen is controlling display' "$screen_sh" 2>/dev/null; then
        log_info "ForgeX screen.sh has no drawing patches, nothing to remove"
        return 0
    fi

    log_info "Removing HelixScreen drawing patches from ForgeX screen.sh..."

    # Remove our 4-line block: comment + if + exit 0 + fi
    tmp_file="${screen_sh}.tmp"
    awk '
    /# Skip when HelixScreen is controlling display/ { skip=1; next }
    skip && /if \[ -f \/tmp\/helixscreen_active \]; then/ { next }
    skip && /^[[:space:]]*exit 0[[:space:]]*$/ { next }
    skip && /^[[:space:]]*fi[[:space:]]*$/ { skip=0; next }
    { print }
    ' "$screen_sh" > "$tmp_file"

    if [ -s "$tmp_file" ]; then
        $SUDO mv "$tmp_file" "$screen_sh"
        $SUDO chmod +x "$screen_sh"
    else
        rm -f "$tmp_file"
        log_warn "Failed to unpatch ForgeX screen.sh drawing patches"
        return 1
    fi

    # Verify removal
    if grep -q '# Skip when HelixScreen is controlling display' "$screen_sh" 2>/dev/null; then
        log_warn "Could not fully remove drawing patches from screen.sh"
        return 1
    fi

    log_success "ForgeX screen.sh drawing patches removed"
    return 0
}

# Install logged wrapper to prevent direct framebuffer writes during boot
# ForgeX's 'logged' binary writes directly to /dev/fb0 when --send-to-screen is used,
# bypassing our screen.sh patches. This wrapper strips that flag when HelixScreen is active.
install_forgex_logged_wrapper() {
    logged_bin="/opt/config/mod/.bin/exec/logged"
    logged_real="/opt/config/mod/.bin/exec/logged-real"
    logged_wrapper="/opt/config/mod/.bin/exec/logged-wrapper"

    if [ ! -f "$logged_bin" ]; then
        log_info "ForgeX logged binary not found, skipping wrapper"
        return 1
    fi

    # Always re-write the wrapper to pick up fixes on upgrade
    if [ -L "$logged_bin" ] && [ -f "$logged_real" ]; then
        log_info "Updating ForgeX logged wrapper..."
    elif [ -L "$logged_bin" ]; then
        # Don't wrap if it's already a symlink to something else
        log_warn "ForgeX logged is already a symlink, skipping wrapper"
        return 1
    else
        log_info "Installing ForgeX logged wrapper..."
    fi

    # Create the wrapper script
    cat > "$logged_wrapper" << 'WRAPPER_EOF'
#!/bin/sh
# Wrapper for logged that strips --send-to-screen when HelixScreen is active
# The logged binary writes directly to /dev/fb0, bypassing screen.sh patches

if [ -f /tmp/helixscreen_active ]; then
    # Remove --send-to-screen and related args, keep everything else
    args=""
    skip_next=0
    for arg in "$@"; do
        if [ $skip_next -eq 1 ]; then
            skip_next=0
            continue
        fi
        case "$arg" in
            --send-to-screen) continue ;;
            --screen-no-followup) continue ;;
            --screen-level) skip_next=1; continue ;;
            --screen-queue) skip_next=1; continue ;;
            *) args="$args $arg" ;;
        esac
    done
    exec /opt/config/mod/.bin/exec/logged-real $args
else
    exec /opt/config/mod/.bin/exec/logged-real "$@"
fi
WRAPPER_EOF

    $SUDO chmod +x "$logged_wrapper"

    # Move original to logged-real and symlink logged to wrapper (skip if already done)
    if [ ! -L "$logged_bin" ]; then
        $SUDO mv "$logged_bin" "$logged_real"
        $SUDO ln -s "$logged_wrapper" "$logged_bin"
    fi

    if [ -L "$logged_bin" ] && [ -f "$logged_real" ]; then
        log_success "ForgeX logged wrapper installed"
        return 0
    else
        # Rollback on failure
        [ -f "$logged_real" ] && $SUDO mv "$logged_real" "$logged_bin"
        rm -f "$logged_wrapper"
        log_warn "Failed to install ForgeX logged wrapper"
        return 1
    fi
}

# Remove logged wrapper (for uninstall)
uninstall_forgex_logged_wrapper() {
    logged_bin="/opt/config/mod/.bin/exec/logged"
    logged_real="/opt/config/mod/.bin/exec/logged-real"
    logged_wrapper="/opt/config/mod/.bin/exec/logged-wrapper"

    if [ ! -f "$logged_real" ]; then
        return 0  # Not installed
    fi

    log_info "Removing ForgeX logged wrapper..."

    $SUDO rm -f "$logged_bin"
    $SUDO mv "$logged_real" "$logged_bin"
    $SUDO rm -f "$logged_wrapper"

    log_success "ForgeX logged wrapper removed"
    return 0
}

# Uninstall ForgeX-specific configuration (for uninstall)
# Restores display mode, stock UI, screen.sh, GuppyScreen/tslib init scripts,
# and cleans up backup files from manual patches.
# Note: Sets caller's `restored_ui` variable via dynamic scoping.
uninstall_forgex() {
    # Restore ForgeX display mode to GUPPY (from HEADLESS or STOCK)
    if [ -f "/opt/config/mod_data/variables.cfg" ]; then
        if grep -q "display[[:space:]]*=[[:space:]]*'HEADLESS'" "/opt/config/mod_data/variables.cfg"; then
            log_info "Restoring ForgeX display mode to GUPPY..."
            $SUDO sed -i "s/display[[:space:]]*=[[:space:]]*'HEADLESS'/display = 'GUPPY'/" "/opt/config/mod_data/variables.cfg"
        elif grep -q "display[[:space:]]*=[[:space:]]*'STOCK'" "/opt/config/mod_data/variables.cfg"; then
            log_info "Restoring ForgeX display mode to GUPPY..."
            $SUDO sed -i "s/display[[:space:]]*=[[:space:]]*'STOCK'/display = 'GUPPY'/" "/opt/config/mod_data/variables.cfg"
        fi
    fi

    # Restore stock FlashForge UI in auto_run.sh
    restore_stock_firmware_ui || true

    # Remove HelixScreen patches from screen.sh
    unpatch_forgex_screen_sh || true
    unpatch_forgex_screen_drawing || true

    # Remove logged wrapper
    uninstall_forgex_logged_wrapper || true

    # Re-enable GuppyScreen and tslib init scripts
    if [ -f "/opt/config/mod/.root/S80guppyscreen" ]; then
        $SUDO chmod +x "/opt/config/mod/.root/S80guppyscreen" 2>/dev/null || true
        restored_ui="GuppyScreen (/opt/config/mod/.root/S80guppyscreen)"
    fi
    if [ -f "/opt/config/mod/.root/S35tslib" ]; then
        $SUDO chmod +x "/opt/config/mod/.root/S35tslib" 2>/dev/null || true
    fi

    # Clean up any leftover backup files from manual patches
    for backup_file in /opt/config/mod/.shell/*.helix-backup /opt/config/mod/.shell/*.bak; do
        if [ -f "$backup_file" ] 2>/dev/null; then
            log_info "Removing leftover backup: $backup_file"
            $SUDO rm -f "$backup_file"
        fi
    done
}

# ============================================
# Module: competing_uis.sh
# ============================================

#
# Known competing screen UIs to stop
# Includes: GuppyScreen (AD5M/K1), Grumpyscreen (K1/Simple AF), KlipperScreen, FeatherScreen,
# mksclient (Sovol SV06 Ace stock touchscreen UI)
COMPETING_UIS="guppyscreen GuppyScreen grumpyscreen Grumpyscreen KlipperScreen klipperscreen featherscreen FeatherScreen mksclient"

# Wayland compositors that hold the DRM/KMS master. On Armbian/Pi-class boards
# (e.g. BTT CB1) KlipperScreen commonly runs *inside* one of these; the
# compositor — not the UI process — owns /dev/dri/card0, so HelixScreen's direct
# DRM output gets EACCES ("not DRM master") until it is stopped. Matched by exact
# executable name via pidof. We deliberately do NOT touch getty/fbcon (they own
# the legacy console /dev/fb0, not the KMS master) or seatd (a seat broker, not a
# master holder) — stopping those carries risk without freeing card0.
WAYLAND_COMPOSITORS="cage weston labwc sway wayfire"

# Record a disabled service for later re-enablement
# Args: $1 = type ("systemd" or "sysv-chmod"), $2 = target (service name or script path)
record_disabled_service() {
    local type="$1"
    local target="$2"
    local entry="${type}:${target}"
    local state_file="${INSTALL_DIR}/config/.disabled_services"

    # Ensure config directory exists
    if [ -n "${INSTALL_DIR:-}" ] && [ ! -d "${INSTALL_DIR}/config" ]; then
        $(file_sudo "${INSTALL_DIR}") mkdir -p "${INSTALL_DIR}/config"
    fi

    # Don't duplicate entries
    if [ -f "$state_file" ] && grep -qF "$entry" "$state_file" 2>/dev/null; then
        return 0
    fi

    echo "$entry" | $(file_sudo "${INSTALL_DIR}/config") tee -a "$state_file" >/dev/null
}

# Stop Wayland compositors holding the DRM master (cage/weston/labwc/sway/...).
# Run AFTER the named-UI loop so a compositor launched by a UI service (e.g.
# KlipperScreen.service ExecStart=cage -- screen.py) is already gone; this catches
# a standalone compositor service or one orphaned/launched from an autologin
# .profile that still pins /dev/dri/card0. Reversible: disabled services are
# recorded for re-enablement on uninstall. Sets found_any in the caller's scope.
stop_wayland_compositors() {
    local comp svc
    for comp in $WAYLAND_COMPOSITORS; do
        # Standalone systemd units (cage@tty1.service, weston.service, ...)
        if [ "$INIT_SYSTEM" = "systemd" ]; then
            for svc in "$comp" "${comp}@tty1"; do
                if systemctl is-active --quiet "$svc" 2>/dev/null; then
                    log_info "Stopping Wayland compositor service $svc (holds DRM master)..."
                    $SUDO systemctl stop "$svc" 2>/dev/null || true
                    $SUDO systemctl disable "$svc" 2>/dev/null || true
                    record_disabled_service "systemd" "$svc"
                    found_any=true
                fi
            done
        fi
        # Kill any lingering compositor process (exact basename via pidof)
        if kill_process_by_name "$comp"; then
            log_info "Killed lingering Wayland compositor: $comp (was holding /dev/dri/card0)"
            found_any=true
        fi
    done
}

# Stop ForgeX-specific competing UIs (stock FlashForge firmware UI)
stop_forgex_competing_uis() {
    # Stop stock FlashForge firmware UI (AD5M/Adventurer 5M)
    # ffstartup-arm is the startup manager that launches firmwareExe (the stock Qt UI)
    if [ -f /opt/PROGRAM/ffstartup-arm ]; then
        log_info "Stopping stock FlashForge UI..."
        kill_process_by_name firmwareExe ffstartup-arm || true
        found_any=true
    fi
}

# Stop Klipper Mod-specific competing UIs (Xorg, KlipperScreen)
stop_kmod_competing_uis() {
    # Stop Xorg first (required for framebuffer access)
    # Xorg takes over /dev/fb0 layer, preventing direct framebuffer rendering
    if [ -x "/etc/init.d/S40xorg" ]; then
        log_info "Stopping Xorg (Klipper Mod display server)..."
        $SUDO /etc/init.d/S40xorg stop 2>/dev/null || true
        # Disable Xorg init script (non-destructive, reversible)
        $SUDO chmod a-x /etc/init.d/S40xorg 2>/dev/null || true
        record_disabled_service "sysv-chmod" "/etc/init.d/S40xorg"
        # Kill any remaining Xorg processes
        kill_process_by_name Xorg X || true
        found_any=true
    fi

    # Kill python processes running KlipperScreen (common on Klipper Mod)
    # BusyBox ps doesn't support 'aux', use portable approach
    # shellcheck disable=SC2009
    for pid in $(ps -ef 2>/dev/null | grep -E 'KlipperScreen.*screen\.py' | grep -v grep | awk '{print $2}'); do
        log_info "Killing KlipperScreen python process (PID $pid)..."
        $SUDO kill "$pid" 2>/dev/null || true
        found_any=true
    done
}

# Stop stock Creality UI on K1 series (display-server, Monitor, master-server, etc.)
# S99start_app launches the entire stock Creality UI stack
stop_k1_stock_competing_uis() {
    if [ -x /etc/init.d/S99start_app ]; then
        log_info "Stopping stock Creality UI (S99start_app)..."
        /etc/init.d/S99start_app stop 2>/dev/null || true
        # Disable so it doesn't restart on reboot (reversible)
        chmod a-x /etc/init.d/S99start_app 2>/dev/null || true
        record_disabled_service "sysv-chmod" "/etc/init.d/S99start_app"
        found_any=true
    fi

    # Kill any remaining stock Creality UI processes
    for proc in display-server Monitor master-server audio-server wifi-server app-server upgrade-server web-server; do
        if kill_process_by_name "$proc"; then
            log_info "Killed remaining $proc process"
            found_any=true
        fi
    done

    # S99start_app also manages dropbear (SSH) on stock K1 firmware.
    # Disabling it kills SSH on next reboot (#535). Ensure SSH survives.
    ensure_k1_ssh
}

# Stop the Sovol SV06 Ace stock touchscreen UI (#986).
# Unlike the K1/CC1 stock UIs, mksclient is NOT a systemd/init.d service: it is a
# plain binary at /home/sovol/printer_data/build/mksclient run as user `sovol`.
# So there is no init script to chmod -x; we disable persistence by removing the
# execute bit on the binary itself (the existing re-enable path chmod +x restores
# it). mksclient also exports sysfs GPIO 67 at boot (the camera light), which pins
# it away from Klipper's [output_pin cameralight] — so after killing mksclient we
# unexport GPIO 67 to release it. Sets found_any in the caller's scope.
stop_sovol_competing_uis() {
    local bin
    for bin in /home/sovol/printer_data/build/mksclient /home/*/printer_data/build/mksclient; do
        # Skip if the glob didn't match (literal pattern returned) or not a file.
        [ -f "$bin" ] || continue
        log_info "Stopping stock Sovol UI (mksclient: $bin)..."
        kill_process_by_name mksclient || true
        # Persistent disable: drop the execute bit so it can't relaunch on boot.
        # Recorded as sysv-chmod so uninstall's chmod +x re-enables the binary.
        $SUDO chmod a-x "$bin" 2>/dev/null || true
        record_disabled_service "sysv-chmod" "$bin"
        found_any=true
    done

    # mksclient exports GPIO 67 (camera light) at boot; release it so Klipper's
    # [output_pin cameralight] can claim the line after the UI is gone.
    if [ -e /sys/class/gpio/gpio67 ]; then
        echo 67 > /sys/class/gpio/unexport 2>/dev/null || true
    fi
}

# Ensure SSH (dropbear) is running and will start on boot.
# On stock K1 firmware, dropbear is managed by S99start_app which we disable.
# This creates an independent dropbear init script so SSH survives reboots.
ensure_k1_ssh() {
    # Already running — nothing to do
    if pidof dropbear >/dev/null 2>&1; then
        # Make sure it has a boot-time init script
        _ensure_dropbear_init_script
        return 0
    fi

    # Try existing init script first
    for script in /etc/init.d/S50dropbear /etc/init.d/S*dropbear*; do
        [ -f "$script" ] || continue
        chmod +x "$script" 2>/dev/null || true
        "$script" start 2>/dev/null || true
        if pidof dropbear >/dev/null 2>&1; then
            log_info "SSH (dropbear) started via $script"
            return 0
        fi
    done

    # No init script or it failed — start dropbear directly
    local dropbear_bin=""
    for bin in /usr/sbin/dropbear /usr/bin/dropbear /sbin/dropbear; do
        if [ -x "$bin" ]; then
            dropbear_bin="$bin"
            break
        fi
    done

    if [ -n "$dropbear_bin" ]; then
        log_info "Starting dropbear directly ($dropbear_bin)..."
        "$dropbear_bin" -R 2>/dev/null || true
        _ensure_dropbear_init_script "$dropbear_bin"
        if pidof dropbear >/dev/null 2>&1; then
            log_info "SSH (dropbear) started successfully"
        else
            log_warn "Failed to start dropbear — SSH may not be available"
        fi
    else
        log_warn "dropbear not found — SSH may not be available"
    fi
}

# Create a minimal dropbear init script if one doesn't exist.
# Ensures SSH starts on boot independently of S99start_app.
# Args: $1 = dropbear binary path (optional, defaults to /usr/sbin/dropbear)
_ensure_dropbear_init_script() {
    local dropbear_path="${1:-/usr/sbin/dropbear}"

    # Check if any dropbear init script already exists
    for script in /etc/init.d/S50dropbear /etc/init.d/S*dropbear*; do
        if [ -f "$script" ] && [ -x "$script" ]; then
            return 0
        fi
    done

    # Create a minimal init script at S50 (before HelixScreen at S99)
    log_info "Creating dropbear init script (S50dropbear)..."
    cat > /etc/init.d/S50dropbear << INITEOF
#!/bin/sh
# Auto-created by HelixScreen to ensure SSH survives S99start_app being disabled
DROPBEAR="${dropbear_path}"
PIDFILE="/var/run/dropbear.pid"
case "\$1" in
    start)
        [ -x "\$DROPBEAR" ] || exit 0
        "\$DROPBEAR" -R -P "\$PIDFILE"
        ;;
    stop)
        [ -f "\$PIDFILE" ] && kill "\$(cat "\$PIDFILE")" 2>/dev/null
        killall dropbear 2>/dev/null || true
        rm -f "\$PIDFILE"
        ;;
    restart)
        \$0 stop
        sleep 1
        \$0 start
        ;;
    *)
        echo "Usage: \$0 {start|stop|restart}"
        exit 1
        ;;
esac
INITEOF
    chmod +x /etc/init.d/S50dropbear
}

# Register HelixScreen with COSMOS's gui-switcher and stop the currently active GUI.
# On Centauri Carbon / COSMOS, sibling UIs (grumpyscreen, guppyscreen, atomscreen) are
# peers managed by gui-switcher — we DO NOT chmod them out. Instead we tell
# config-manager to pick HelixScreen and let gui-switcher do the handoff.
stop_cc1_competing_uis() {
    if ! command -v config-manager >/dev/null 2>&1; then
        log_warn "config-manager not found — cannot register with gui-switcher"
        return 0
    fi

    # Stop the currently active GUI before we hand the framebuffer to ourselves.
    local current_ui
    current_ui=$(config-manager ui screen_ui 2>/dev/null || echo "")
    if [ -n "$current_ui" ] && [ -x "/etc/init.d/${current_ui}" ]; then
        log_info "Stopping active COSMOS GUI: ${current_ui}"
        /etc/init.d/"${current_ui}" stop 2>/dev/null || true
        found_any=true
    fi

    # Register HelixScreen as the selected UI. `config-manager` on COSMOS uses
    # a 3-arg form to set; fall back to editing cosmos.conf if the set form
    # isn't supported.
    if config-manager ui screen_ui helixscreen 2>/dev/null; then
        log_info "Registered HelixScreen with gui-switcher"
    elif [ -f /etc/klipper/config/cosmos.conf ]; then
        log_info "Updating /etc/klipper/config/cosmos.conf directly..."
        $SUDO sed -i "s|^screen_ui[[:space:]]*=.*|screen_ui = helixscreen|" /etc/klipper/config/cosmos.conf 2>/dev/null || true
    fi

    # COSMOS gui-switcher (S96 init) reads `config-manager ui screen_ui` and
    # launches /etc/init.d/<value>. config-manager hardcodes an allowlist of
    # ['grumpyscreen','guppyscreen','atomscreen'] in /usr/bin/config-manager —
    # rejecting 'helixscreen' as invalid and falling back to grumpyscreen.
    # /usr/bin is on read-only squashfs so we can't patch the validator.
    # /etc is on a writable overlay, so we substitute /etc/init.d/grumpyscreen
    # with a wrapper that delegates to /etc/init.d/helixscreen. Net effect:
    # gui-switcher → grumpyscreen wrapper → helixscreen. Original is preserved
    # at /etc/init.d/grumpyscreen.helix-bak and restored on uninstall.
    # Upstream fix tracked at OpenCentauri/cosmos#145.
    if [ -x /etc/init.d/grumpyscreen ] && \
       ! grep -q "HELIXSCREEN_WRAPPER" /etc/init.d/grumpyscreen 2>/dev/null; then
        log_info "Substituting /etc/init.d/grumpyscreen with helixscreen wrapper"
        if ! $SUDO cp -p /etc/init.d/grumpyscreen /etc/init.d/grumpyscreen.helix-bak; then
            log_warn "Could not back up grumpyscreen — skipping wrapper install"
        else
            $SUDO tee /etc/init.d/grumpyscreen >/dev/null <<'WRAPPER_EOF' || \
                log_warn "Failed to install grumpyscreen wrapper — gui-switcher will not launch HelixScreen at boot"
#!/bin/sh
# HELIXSCREEN_WRAPPER (do not remove this marker — used for idempotency)
# Workaround for OpenCentauri config-manager allowlist (cosmos#145):
# config-manager refuses to return 'helixscreen' as screen_ui, so
# gui-switcher always asks /etc/init.d/grumpyscreen to start. We delegate
# to HelixScreen's init script. Original grumpyscreen preserved at
# grumpyscreen.helix-bak and restored by HelixScreen's uninstaller.
exec /etc/init.d/helixscreen "$@"
WRAPPER_EOF
            $SUDO chmod +x /etc/init.d/grumpyscreen 2>/dev/null || true
        fi
    fi
}

# Stop competing screen UIs (GuppyScreen, KlipperScreen, Xorg, etc.)
# Dispatches platform-specific logic, then runs generic UI stopping
stop_competing_uis() {
    # During self-update, competing UIs were already disabled during initial install.
    # Re-running this would chmod -x init scripts that may have been restored or
    # customized by the platform (e.g. ZMOD manages S80guppyscreen) (#314).
    if _is_self_update; then
        log_info "Skipping competing UI check (self-update; already handled at install)"
        return 0
    fi

    log_info "Checking for competing screen UIs..."

    found_any=false

    # Platform-specific competing UI handling
    case "${AD5M_FIRMWARE:-}" in
        forge_x)    stop_forgex_competing_uis ;;
        klipper_mod) stop_kmod_competing_uis ;;
        zmod)
            # ZMOD manages its own init scripts (S80guppyscreen etc.)
            # Do NOT fall through to the generic loop which would chmod -x them
            log_info "ZMOD platform: skipping generic UI disabling (ZMOD-managed)"
            return 0
            ;;
    esac

    # K1 platform: stop stock Creality UI
    case "${K1_FIRMWARE:-}" in
        stock_klipper|guilouz) stop_k1_stock_competing_uis ;;
    esac

    # Sovol SV06 Ace: stock UI is the plain `mksclient` binary (not a service).
    # Run the dedicated handler when the binary is present so it gets chmod-a-x'd
    # and GPIO 67 is released (the generic loop below only does a fallback kill).
    if [ -f /home/sovol/printer_data/build/mksclient ] || ls /home/*/printer_data/build/mksclient >/dev/null 2>&1; then
        stop_sovol_competing_uis
    fi

    # CC1 / COSMOS: use gui-switcher handoff instead of disabling peers.
    # Early-return so the generic loop below doesn't chmod out grumpyscreen/guppyscreen/atomscreen.
    if [ "${platform:-}" = "cc1" ]; then
        stop_cc1_competing_uis
        if [ "$found_any" = true ]; then
            log_info "Waiting for previous GUI to stop..."
            sleep 2
        fi
        return 0
    fi

    # Snapmaker U1: unisrv is the proprietary camera/MQTT daemon (handles
    # Klipper's TIMELAPSE_START), NOT a UI. The real U1 stock UI is /usr/bin/gui
    # via /etc/init.d/S99screen, handled by snapmaker-u1-setup-autostart.sh.
    # Killing unisrv here breaks timelapse on every deploy.

    # Handle the specific previous UI if we know it (for clean reversibility)
    if [ -n "$PREVIOUS_UI_SCRIPT" ] && [ -x "$PREVIOUS_UI_SCRIPT" ] 2>/dev/null; then
        log_info "Stopping previous UI: $PREVIOUS_UI_SCRIPT"
        $SUDO "$PREVIOUS_UI_SCRIPT" stop 2>/dev/null || true
        # Disable by removing execute permission (non-destructive, reversible)
        $SUDO chmod a-x "$PREVIOUS_UI_SCRIPT" 2>/dev/null || true
        record_disabled_service "sysv-chmod" "$PREVIOUS_UI_SCRIPT"
        found_any=true
    fi

    for ui in $COMPETING_UIS; do
        # Check systemd services
        if [ "$INIT_SYSTEM" = "systemd" ]; then
            if systemctl is-active --quiet "$ui" 2>/dev/null; then
                log_info "Stopping $ui (systemd service)..."
                $SUDO systemctl stop "$ui" 2>/dev/null || true
                $SUDO systemctl disable "$ui" 2>/dev/null || true
                record_disabled_service "systemd" "$ui"
                found_any=true
            fi
        fi

        # Check SysV init scripts (various locations)
        for initscript in /etc/init.d/S*${ui}* /etc/init.d/${ui}* /opt/config/mod/.root/S*${ui}*; do
            # Skip if glob didn't match any files (literal pattern returned)
            [ -e "$initscript" ] || continue
            # Skip if this is the PREVIOUS_UI_SCRIPT we already handled
            if [ "$initscript" = "$PREVIOUS_UI_SCRIPT" ]; then
                continue
            fi
            if [ -x "$initscript" ]; then
                log_info "Stopping $ui ($initscript)..."
                $SUDO "$initscript" stop 2>/dev/null || true
                # Disable by removing execute permission (non-destructive)
                $SUDO chmod a-x "$initscript" 2>/dev/null || true
                record_disabled_service "sysv-chmod" "$initscript"
                found_any=true
            fi
        done

        # Kill any remaining processes by name
        if kill_process_by_name "$ui"; then
            log_info "Killed remaining $ui processes"
            found_any=true
        fi
    done

    # Free the DRM master from any Wayland compositor (KlipperScreen-under-cage etc.)
    stop_wayland_compositors

    if [ "$found_any" = true ]; then
        log_info "Waiting for competing UIs to stop..."
        sleep 2
    else
        log_info "No competing UIs found"
    fi
}

# ============================================
# Module: printer_seed.sh
# ============================================

#
#   - display orientation/panel config (top-level "display" block, e.g. rotate)
#     — needed for the very first boot frame to render right-side-up.
#
# Single source of truth (#986): the source of seed data is the runtime preset
# at assets/config/presets/<printer_id>.json. The installer reads ONLY the two
# install-critical, pre-Moonraker device-level blocks from it: top-level "input"
# and top-level "display". It deliberately does NOT seed:
#   - the preset's "printer" block (heaters/fans/leds/filament_sensors), nor
#   - the top-level "preset" key.
# Both are applied by the app's runtime preset loader instead. The app's
# PrinterDetector::auto_detect_and_save() (src/printer/printer_detector.cpp)
# applies the FULL preset (printer.* + set_preset → has_preset() → wizard
# preset-mode) once Moonraker connects. If the installer pre-set "preset" or a
# printer_type, that path would hit the "already set" branch and SKIP that full
# apply. So the installer's job is strictly the two device-level blocks; the
# rest is the app's responsibility.
#
# The seeded blocks are deep-merged WITHOUT clobbering any keys the user has
# already set: existing settings always win (the preset is the lower-priority
# side).
#
# Seeded ids are recorded to ${INSTALL_DIR}/config/.seeded_settings so uninstall
# can be aware of what the installer wrote.
#
# Reads: INSTALL_DIR, SUDO (and HELIX_PRESET_DIR override for tests)
# Calls: file_sudo() from common.sh

# Source guard

# Resolve the directory holding the runtime presets (single source of truth).
# Override with HELIX_PRESET_DIR (tests). Otherwise prefer the installed copy
# under ${INSTALL_DIR}/assets/config/presets, then fall back to the in-repo
# source tree (dev installer running from a checkout).
_helix_preset_dir() {
    if [ -n "${HELIX_PRESET_DIR:-}" ]; then
        echo "$HELIX_PRESET_DIR"
        return 0
    fi
    if [ -n "${INSTALL_DIR:-}" ] && [ -d "${INSTALL_DIR}/assets/config/presets" ]; then
        echo "${INSTALL_DIR}/assets/config/presets"
        return 0
    fi
    # Dev checkout: <repo>/assets/config/presets, relative to this module.
    local _self_dir
    _self_dir="$(cd "$(dirname "$0")" 2>/dev/null && pwd)" || _self_dir=""
    if [ -n "$_self_dir" ] && [ -d "${_self_dir}/../../../assets/config/presets" ]; then
        (cd "${_self_dir}/../../../assets/config/presets" && pwd)
        return 0
    fi
    echo "${INSTALL_DIR:-/opt/helixscreen}/assets/config/presets"
}

# Record a seeded printer-id to the state file (for uninstall awareness).
# Args: $1 = printer_id
_record_seeded_settings() {
    local printer_id="$1"
    local state_file="${INSTALL_DIR}/config/.seeded_settings"

    if [ -n "${INSTALL_DIR:-}" ] && [ ! -d "${INSTALL_DIR}/config" ]; then
        $(file_sudo "${INSTALL_DIR}") mkdir -p "${INSTALL_DIR}/config"
    fi

    # Don't duplicate.
    if [ -f "$state_file" ] && grep -qF "settings:${printer_id}" "$state_file" 2>/dev/null; then
        return 0
    fi
    echo "settings:${printer_id}" | $(file_sudo "${INSTALL_DIR}/config") tee -a "$state_file" >/dev/null
}

# Pre-bake the install-critical device-level subset of a printer's runtime
# preset into the install's settings.json. Only the top-level "input" and
# "display" blocks (see SEED_BLOCKS in the embedded Python) are extracted and
# deep-merged; the preset's "printer" block and top-level "preset" key are
# deliberately omitted — the app's runtime PrinterDetector applies the full
# preset once Moonraker connects. Existing user keys win over the seeded subset
# (the preset is the lower-priority side). Creates settings.json from the subset
# if it is absent or empty.
#
# Graceful by design: a missing preset is a no-op success, and an absent
# python3 logs a warning and skips WITHOUT failing the install.
#
# Args: $1 = printer_id
seed_settings_for_printer() {
    local printer_id="$1"
    [ -n "$printer_id" ] || return 0

    local preset_dir
    preset_dir="$(_helix_preset_dir)"
    local fragment="${preset_dir}/${printer_id}.json"

    # Missing preset → nothing to seed for this printer. Success.
    if [ ! -f "$fragment" ]; then
        return 0
    fi

    # JSON deep-merge requires python3. jq is NOT guaranteed on minimal targets
    # (established #969 fallback pattern), and a deep recursive merge in pure
    # shell is unsafe. If python3 is unavailable, warn and skip — never fail.
    if ! command -v python3 >/dev/null 2>&1; then
        log_warn "python3 not available; skipping settings seed for ${printer_id}"
        return 0
    fi

    local settings="${INSTALL_DIR}/config/settings.json"

    if [ -n "${INSTALL_DIR:-}" ] && [ ! -d "${INSTALL_DIR}/config" ]; then
        $(file_sudo "${INSTALL_DIR}") mkdir -p "${INSTALL_DIR}/config"
    fi

    log_info "Seeding settings defaults for ${printer_id}..."

    # Merge into a temp file we own, then move into place via file_sudo so we
    # respect the same privilege model as the rest of the installer.
    local tmp_out="${settings}.seed.$$"

    # Extract the install-critical device-level blocks from the preset, strip
    # any "_"-prefixed provenance keys, then deep-merge that subset into the base
    # settings: existing settings (base) take precedence; the subset fills only
    # keys the base does not already define. Recurses into nested objects.
    if SETTINGS_PATH="$settings" FRAGMENT_PATH="$fragment" TMP_OUT="$tmp_out" python3 - <<'PY'
import json, os, sys

settings_path = os.environ["SETTINGS_PATH"]
fragment_path = os.environ["FRAGMENT_PATH"]
tmp_out = os.environ["TMP_OUT"]

# The ONLY preset blocks baked into the user's settings.json BEFORE first launch.
# These are the install-critical, pre-Moonraker device-level blocks:
#   - "input":   touch calibration. The first-run touch-calibration wizard reads
#                settings.json /input/calibration/valid at startup, before the
#                app connects to Moonraker, so it MUST be pre-baked.
#   - "display": panel orientation/config (e.g. rotate) needed for the first
#                boot frame to render right-side-up.
# Everything else (the preset's "printer" block and the top-level "preset" key)
# is deliberately NOT seeded — the app's PrinterDetector applies the FULL preset
# once Moonraker connects. Pre-setting "preset" here would make that path skip
# the full apply (the "already set" branch). Add a block here ONLY if the app
# reads it before its runtime preset loader runs.
SEED_BLOCKS = ["input", "display"]

def load(path):
    if not os.path.exists(path):
        return {}
    try:
        with open(path) as f:
            data = f.read().strip()
        if not data:
            return {}
        obj = json.loads(data)
        return obj if isinstance(obj, dict) else {}
    except (ValueError, OSError):
        # Malformed existing settings: treat as empty base rather than crash
        # the install. The seeded subset becomes the new content.
        return {}

def strip_underscore(obj):
    """Recursively drop any "_"-prefixed keys (provenance/metadata) so the
    preset's nested documentation (e.g. input.calibration._comment) never leaks
    into the user's settings.json."""
    if isinstance(obj, dict):
        return {k: strip_underscore(v) for k, v in obj.items()
                if not k.startswith("_")}
    if isinstance(obj, list):
        return [strip_underscore(v) for v in obj]
    return obj

def extract_subset(preset, blocks):
    """Build a fragment dict containing only the named top-level blocks present
    in the preset, with provenance keys stripped. A block absent from the preset
    is simply omitted from the fragment."""
    out = {}
    for key in blocks:
        if isinstance(preset, dict) and isinstance(preset.get(key), dict):
            out[key] = strip_underscore(preset[key])
    return out

def deep_merge(base, frag, top_level=False):
    """Return base with frag's keys filled in where base lacks them.
    Existing base values always win (fragment is lower priority)."""
    for k, v in frag.items():
        # Defense-in-depth: never copy a top-level "_"-prefixed provenance key
        # into the user's settings.json (the subset is already stripped above).
        if top_level and k.startswith("_"):
            continue
        if k in base and isinstance(base[k], dict) and isinstance(v, dict):
            deep_merge(base[k], v)
        elif k not in base:
            base[k] = v
        # else: base already has a non-dict value → keep it (user wins)
    return base

base = load(settings_path)
preset = load(fragment_path)
frag = extract_subset(preset, SEED_BLOCKS)
merged = deep_merge(base, frag, top_level=True)

with open(tmp_out, "w") as f:
    json.dump(merged, f, indent=2)
    f.write("\n")
PY
    then
        if [ -f "$tmp_out" ]; then
            if $(file_sudo "${INSTALL_DIR}/config") mv "$tmp_out" "$settings" 2>/dev/null; then
                _record_seeded_settings "$printer_id"
                log_success "Seeded settings defaults for ${printer_id}"
            else
                log_warn "Could not write seeded settings.json for ${printer_id}"
                rm -f "$tmp_out" 2>/dev/null || true
            fi
        fi
    else
        log_warn "Failed to merge settings seed for ${printer_id}; leaving settings.json unchanged"
        rm -f "$tmp_out" 2>/dev/null || true
    fi

    return 0
}

# Detect a known printer-model that needs install-time seeding/config.
# Prints a printer-id to stdout (empty if none matched).
#
# Returns "sovol_sv06_ace" when the stock Sovol touchscreen UI binary
# `mksclient` is present at its confirmed install path
# /home/sovol/printer_data/build/mksclient (also globbed as
# /home/*/printer_data/build/mksclient for robustness if the user account
# differs). This is the confirmed fingerprint: published Sovol/R8CEH configs
# show mksclient is a plain binary at that path, run as user `sovol`. Empty
# otherwise.
#
# TODO(#986): the binary path + `sovol` user is now the CONFIRMED fingerprint
# (from published Sovol/R8CEH firmware configs). The only remaining uncertainty
# is the exact /etc/hostname and /proc/device-tree/model strings on the panel,
# which we chose not to fetch — the binary path is a strong, unambiguous signal
# on its own, so hostname matching was dropped to avoid false negatives on
# renamed hosts.
detect_printer_model() {
    # Confirmed signal: the stock Sovol UI binary at its known build path.
    # HELIX_SOVOL_MKSCLIENT lets tests redirect the path under a temp HOME.
    local _bin
    for _bin in \
        "${HELIX_SOVOL_MKSCLIENT:-}" \
        /home/sovol/printer_data/build/mksclient \
        /home/*/printer_data/build/mksclient; do
        [ -n "$_bin" ] || continue
        if [ -f "$_bin" ]; then
            echo "sovol_sv06_ace"
            return 0
        fi
    done

    echo ""
    return 0
}

# ============================================
# Module: klipper_include.sh
# ============================================

#
#
# Bundled snippets live at: config/klipper_includes/<printer_id>.cfg
# Installed to:             ~/printer_data/config/helixscreen/<printer_id>.cfg
# printer.cfg gets:         [include helixscreen/<printer_id>.cfg]
#
# Both the copied cfg and the printer.cfg edit are recorded to
# ${INSTALL_DIR}/config/.klipper_includes so uninstall can undo them.
#
# Reads: KLIPPER_HOME, INSTALL_DIR, SUDO (and HELIX_KLIPPER_CFG_DIR for tests)
# Calls: file_sudo() from common.sh

# Source guard

# Resolve the directory holding bundled Klipper cfg snippets.
# Override with HELIX_KLIPPER_CFG_DIR (tests). Otherwise prefer the installed
# copy under ${INSTALL_DIR}/config/klipper_includes, then fall back to the
# in-repo source tree (dev installer running from a checkout).
_helix_klipper_cfg_dir() {
    if [ -n "${HELIX_KLIPPER_CFG_DIR:-}" ]; then
        echo "$HELIX_KLIPPER_CFG_DIR"
        return 0
    fi
    if [ -n "${INSTALL_DIR:-}" ] && [ -d "${INSTALL_DIR}/config/klipper_includes" ]; then
        echo "${INSTALL_DIR}/config/klipper_includes"
        return 0
    fi
    local _self_dir
    _self_dir="$(cd "$(dirname "$0")" 2>/dev/null && pwd)" || _self_dir=""
    if [ -n "$_self_dir" ] && [ -d "${_self_dir}/../../../config/klipper_includes" ]; then
        (cd "${_self_dir}/../../../config/klipper_includes" && pwd)
        return 0
    fi
    echo "${INSTALL_DIR:-/opt/helixscreen}/config/klipper_includes"
}

# Record an undo action to the include state file (deduplicated).
# Args: $1 = entry (e.g. "cfg:/path" or "include:/printer.cfg:helixscreen/x.cfg")
_record_klipper_include() {
    local entry="$1"
    local state_file="${INSTALL_DIR}/config/.klipper_includes"

    if [ -n "${INSTALL_DIR:-}" ] && [ ! -d "${INSTALL_DIR}/config" ]; then
        $(file_sudo "${INSTALL_DIR}") mkdir -p "${INSTALL_DIR}/config"
    fi

    if [ -f "$state_file" ] && grep -qF "$entry" "$state_file" 2>/dev/null; then
        return 0
    fi
    echo "$entry" | $(file_sudo "${INSTALL_DIR}/config") tee -a "$state_file" >/dev/null
}

# Install the bundled Klipper include for a printer-id.
#  1. copy config/klipper_includes/<id>.cfg → printer_data/config/helixscreen/<id>.cfg
#  2. ensure a marker-guarded [include helixscreen/<id>.cfg] line in printer.cfg
#  3. record both for uninstall
#
# Defensive: a missing bundled cfg, a missing printer_data/config, or a missing
# printer.cfg all warn-and-skip WITHOUT failing the install.
#
# Args: $1 = printer_id
install_klipper_include_for_printer() {
    local printer_id="$1"
    [ -n "$printer_id" ] || return 0

    local cfg_dir
    cfg_dir="$(_helix_klipper_cfg_dir)"
    local bundled="${cfg_dir}/${printer_id}.cfg"

    # Missing bundled cfg → nothing to include for this printer. Success.
    if [ ! -f "$bundled" ]; then
        return 0
    fi

    if [ -z "${KLIPPER_HOME:-}" ]; then
        log_warn "KLIPPER_HOME not set; skipping Klipper include for ${printer_id}"
        return 0
    fi

    local pd_config="${KLIPPER_HOME}/printer_data/config"
    if [ ! -d "$pd_config" ]; then
        log_warn "No printer_data/config found; skipping Klipper include for ${printer_id}"
        return 0
    fi

    local printer_cfg="${pd_config}/printer.cfg"
    if [ ! -f "$printer_cfg" ]; then
        log_warn "printer.cfg not found at ${printer_cfg}; skipping Klipper include for ${printer_id}"
        return 0
    fi

    # --- 1. Copy the bundled cfg into printer_data/config/helixscreen/ ---
    local pd_helix="${pd_config}/helixscreen"
    if [ ! -d "$pd_helix" ]; then
        if ! $(file_sudo "$pd_config") mkdir -p "$pd_helix" 2>/dev/null; then
            log_warn "Could not create ${pd_helix}; skipping Klipper include for ${printer_id}"
            return 0
        fi
    fi

    local dest_cfg="${pd_helix}/${printer_id}.cfg"
    if $(file_sudo "$pd_helix") cp "$bundled" "$dest_cfg" 2>/dev/null; then
        log_info "Installed Klipper config: ${dest_cfg}"
        _record_klipper_include "cfg:${dest_cfg}"
    else
        log_warn "Could not copy ${bundled} to ${dest_cfg}; skipping include for ${printer_id}"
        return 0
    fi

    # --- 2. Ensure the marker-guarded include line in printer.cfg ---
    local include_line="[include helixscreen/${printer_id}.cfg]"
    if grep -qF "$include_line" "$printer_cfg" 2>/dev/null; then
        log_info "printer.cfg already includes helixscreen/${printer_id}.cfg"
    else
        # Append the include with a marker comment so uninstall (and humans) can
        # identify lines the installer added.
        {
            printf '\n'
            printf '%s\n' "# Added by HelixScreen installer (#986) -- helixscreen/${printer_id}.cfg"
            printf '%s\n' "$include_line"
        } | $(file_sudo "$printer_cfg") tee -a "$printer_cfg" >/dev/null

        if grep -qF "$include_line" "$printer_cfg" 2>/dev/null; then
            log_success "Added [include helixscreen/${printer_id}.cfg] to printer.cfg"
            _record_klipper_include "include:${printer_cfg}:helixscreen/${printer_id}.cfg"
            # A Klipper restart / firmware_restart is needed to pick up the new
            # include. We do not invent a restart path here; the installer's
            # platform recovery / service start handles process restarts, and a
            # firmware_restart is a user-visible printer action best left to the
            # operator after install.
            log_info "Klipper restart / firmware_restart needed to apply helixscreen/${printer_id}.cfg"
        else
            log_warn "Failed to add include line to printer.cfg for ${printer_id}"
        fi
    fi

    return 0
}

# ============================================
# Module: release.sh
# ============================================

#
# R2 CDN configuration (overridable via environment)
: "${R2_BASE_URL:=https://releases.helixscreen.org}"
: "${R2_CHANNEL:=stable}"

# Plain HTTP endpoint for systems without SSL (K1, AD5M BusyBox wget)
: "${HTTP_BASE_URL:=http://dl.helixscreen.org}"

# Cached manifest from R2 (set by get_latest_version, consumed by download_release)
_R2_MANIFEST=""

# Which archive format is in use for this install. Set by download_release() or
# use_local_tarball() based on what was found/provided. Consumed by
# extract_release() and validate_tarball() to dispatch to the right tooling.
# Values: "zip" (preferred, unversioned filename) or "tar.gz" (legacy fallback).
_ARCHIVE_FORMAT="tar.gz"

# Resolve the staged archive path in TMP_DIR for the current _ARCHIVE_FORMAT.
_archive_tmp_path() {
    case "${_ARCHIVE_FORMAT:-tar.gz}" in
        zip) echo "${TMP_DIR}/helixscreen.zip" ;;
        *)   echo "${TMP_DIR}/helixscreen.tar.gz" ;;
    esac
}

# Detect whether curl supports the flags we need (not BusyBox curl).
# BusyBox curl lacks -S, -L, --connect-timeout, --max-time, --progress-bar, etc.
# Cache the result so we only probe once.
_REAL_CURL=""
_has_real_curl() {
    if [ -z "$_REAL_CURL" ]; then
        if command -v curl >/dev/null 2>&1 && curl --version 2>/dev/null | grep -qi "curl"; then
            _REAL_CURL=yes
        else
            _REAL_CURL=no
        fi
    fi
    [ "$_REAL_CURL" = "yes" ]
}

# User-Agent for python downloads. Our CDN/origin returns HTTP 403 to requests
# with an empty UA or the default Python-urllib/x.y UA; any other UA passes.
_PY_UA="helixscreen-installer/1.0"

# Core python urllib GET (fallback when curl/wget unavailable). Writes the
# response to DEST, or to stdout when DEST is "-". Sends a non-default
# User-Agent so the CDN doesn't 403 us (it rejects the urllib default).
# Returns non-zero on any error. Args: url dest("-"=stdout) [max_seconds]
# NOTE: urllib's timeout is a per-socket-operation (inactivity) timeout, not a
# total transfer deadline, and min_speed CDN fail-fast is not honored here.
_py_get() {
    _has_python || return 1
    HELIX_PY_URL="$1" HELIX_PY_DEST="$2" HELIX_PY_UA="$_PY_UA" \
        HELIX_PY_TIMEOUT="${3:-300}" "$_PY_BIN" - <<'PYEOF'
import os, sys, urllib.request, shutil
url = os.environ["HELIX_PY_URL"]
dest = os.environ["HELIX_PY_DEST"]
ua = os.environ["HELIX_PY_UA"]
try:
    timeout = float(os.environ.get("HELIX_PY_TIMEOUT", "300"))
except ValueError:
    timeout = 300.0
try:
    req = urllib.request.Request(url, headers={"User-Agent": ua})
    with urllib.request.urlopen(req, timeout=timeout) as resp:
        if dest == "-":
            shutil.copyfileobj(resp, sys.stdout.buffer)
        else:
            with open(dest, "wb") as out:
                shutil.copyfileobj(resp, out)
except Exception:
    sys.exit(1)
PYEOF
}

# Fetch a URL to stdout via python urllib. Args: url
_py_fetch() { _py_get "$1" "-" 15; }

# Download a URL to a file via python urllib. Args: url dest [max_seconds]
_py_download() { _py_get "$1" "$2" "${3:-300}"; }

# Test a zip archive for validity via python zipfile (fallback when unzip
# unavailable). Returns non-zero if the archive is missing or corrupt.
# Args: archive
_py_unzip_test() {
    _has_python || return 1
    HELIX_PY_ZIP="$1" "$_PY_BIN" - <<'PYEOF'
import os, sys, zipfile
path = os.environ["HELIX_PY_ZIP"]
try:
    with zipfile.ZipFile(path) as zf:
        if zf.testzip() is not None:
            sys.exit(1)
except Exception:
    sys.exit(1)
PYEOF
}

# Extract a zip archive into a destination directory via python zipfile
# (fallback when unzip unavailable). Restores unix permission bits from each
# entry's external_attr (extractall does NOT preserve them); files under a
# bin/ path are forced owner-executable so helixscreen/bin/helix-screen ends up
# runnable even when the zip carries no mode bits. Args: archive destdir
_py_unzip_extract() {
    _has_python || return 1
    HELIX_PY_ZIP="$1" HELIX_PY_DESTDIR="$2" "$_PY_BIN" - <<'PYEOF'
import os, sys, stat, zipfile
path = os.environ["HELIX_PY_ZIP"]
destdir = os.environ["HELIX_PY_DESTDIR"]
try:
    with zipfile.ZipFile(path) as zf:
        for info in zf.infolist():
            zf.extract(info, destdir)
            # Directory entries: nothing to chmod.
            if info.filename.endswith("/"):
                continue
            target = os.path.join(destdir, info.filename)
            # Restore unix permission bits from the zip's external_attr
            # (extractall/extract do NOT preserve them).
            mode = (info.external_attr >> 16) & 0o777
            if mode:
                os.chmod(target, mode)
            # Ensure files under the top-level bin/ are owner-executable, even
            # when the zip carried no exec bit (e.g. bin/helix-screen stored as
            # 0644 or with no mode bits at all). Anchored to a leading "bin/"
            # component so unrelated nested dirs named "bin" aren't affected.
            parts = info.filename.split("/")
            if len(parts) > 1 and parts[0] == "bin":
                st = os.stat(target)
                os.chmod(target, st.st_mode | stat.S_IXUSR)
except Exception:
    sys.exit(1)
PYEOF
}

# Fetch a URL to stdout using curl or wget
# Returns non-zero if neither is available or fetch fails
fetch_url() {
    local url=$1
    if _has_real_curl; then
        curl -sSL --connect-timeout 10 "$url" 2>/dev/null
    elif command -v wget >/dev/null 2>&1; then
        wget -qO- --timeout=10 "$url" 2>/dev/null
    elif _has_python; then
        _py_fetch "$url"
    else
        return 1
    fi
}

# Fetch a URL via plain HTTP (for systems without SSL support)
# Prefers wget (BusyBox wget handles HTTP fine but not HTTPS)
fetch_url_http() {
    local url=$1
    if command -v wget >/dev/null 2>&1; then
        wget -qO- --timeout=10 "$url" 2>/dev/null
    elif _has_real_curl; then
        curl -sSL --connect-timeout 10 "$url" 2>/dev/null
    elif _has_python; then
        _py_fetch "$url"
    else
        return 1
    fi
}

# Download a file via plain HTTP (for systems without SSL support)
# Args: url dest [max_seconds]
download_file_http() {
    local url=$1 dest=$2 max_secs=${3:-300}
    if command -v wget >/dev/null 2>&1; then
        if [ -t 2 ]; then
            wget --timeout="$max_secs" -O "$dest" "$url" && \
                [ -f "$dest" ] && [ -s "$dest" ]
        else
            wget -q --timeout="$max_secs" -O "$dest" "$url" && \
                [ -f "$dest" ] && [ -s "$dest" ]
        fi
    elif _has_real_curl; then
        download_file "$url" "$dest" "$max_secs"
    elif _has_python; then
        _py_download "$url" "$dest" "$max_secs" && [ -f "$dest" ] && [ -s "$dest" ]
    else
        return 1
    fi
}

# Download a URL to a file
# Returns 0 on success (file exists and is non-empty), non-zero on failure
# Sets _DOWNLOAD_HTTP_CODE to the HTTP status (curl only, empty for wget)
# Args: url dest [max_seconds] [min_speed_bps]
#   max_seconds:  total transfer timeout (default 300)
#   min_speed_bps: abort if average speed stays below this for 20s (default 0 = disabled)
#                  Set to e.g. 51200 (50 KB/s) for CDN attempts so a slow CDN
#                  fails fast and the caller can fall through to a better source.
_DOWNLOAD_HTTP_CODE=""
download_file() {
    local url=$1 dest=$2 max_secs=${3:-300} min_speed=${4:-0}
    _DOWNLOAD_HTTP_CODE=""
    if _has_real_curl; then
        local http_code progress_flag speed_flags
        if [ -t 2 ]; then
            progress_flag="--progress-bar"
        else
            progress_flag="-s"
        fi
        # Speed floor: abort if average speed stays below min_speed for 20 consecutive
        # seconds. Lets a slow CDN fail fast so we can fall through to GitHub.
        if [ "${min_speed:-0}" -gt 0 ] 2>/dev/null; then
            speed_flags="--speed-limit ${min_speed} --speed-time 20"
        else
            speed_flags=""
        fi
        # Note: progress output goes to stderr naturally (no 2>&1).
        # The \n before %{http_code} ensures it's on its own line for tail -1.
        http_code=$(curl -SL \
            --connect-timeout 30 \
            --max-time "$max_secs" \
            $progress_flag \
            $speed_flags \
            -w "\n%{http_code}" \
            -o "$dest" \
            "$url") || true
        http_code=$(printf '%s' "$http_code" | tail -1)
        _DOWNLOAD_HTTP_CODE="$http_code"
        [ "$http_code" = "200" ] && [ -f "$dest" ] && [ -s "$dest" ]
    elif command -v wget >/dev/null 2>&1; then
        # wget has no built-in speed floor; rely on max_secs being short for CDN calls.
        if [ -t 2 ]; then
            wget --timeout="$max_secs" -O "$dest" "$url" && \
                [ -f "$dest" ] && [ -s "$dest" ]
        else
            wget -q --timeout="$max_secs" -O "$dest" "$url" && \
                [ -f "$dest" ] && [ -s "$dest" ]
        fi
    elif _has_python; then
        # urllib can't honor min_speed (no speed floor); rely on max_secs.
        if _py_download "$url" "$dest" "$max_secs" && [ -f "$dest" ] && [ -s "$dest" ]; then
            _DOWNLOAD_HTTP_CODE="200"
            return 0
        fi
        return 1
    else
        return 1
    fi
}

# Extract "version" value from manifest JSON on stdin
# Uses POSIX basic regex only (BusyBox compatible)
parse_manifest_version() {
    sed -n 's/.*"version"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/p' | head -n 1
}

# Extract platform asset URL from manifest JSON on stdin
# Greps for the platform-specific filename pattern then extracts the URL
# Uses POSIX basic regex only (BusyBox compatible)
parse_manifest_platform_url() {
    local platform=$1
    grep "helixscreen-${platform}-" | \
        sed -n 's/.*"url"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/p' | head -n 1
}

# Validate an archive is readable and not truncated.
# Dispatches on the archive's filename extension: *.zip uses `unzip -tqq`,
# everything else uses `gunzip -t`. Exits on failure.
# Args: archive_path, context (e.g., "Downloaded " or "Local ")
validate_archive() {
    local archive=$1
    local context=${2:-""}

    case "$archive" in
        *.zip)
            if command -v unzip >/dev/null 2>&1; then
                if ! unzip -tqq "$archive" >/dev/null 2>&1; then
                    log_error "${context}file is not a valid zip archive."
                    [ -n "$context" ] && log_error "The ${context}may have been corrupted or incomplete."
                    exit 1
                fi
            elif _has_python; then
                if ! _py_unzip_test "$archive"; then
                    log_error "${context}file is not a valid zip archive."
                    [ -n "$context" ] && log_error "The ${context}may have been corrupted or incomplete."
                    exit 1
                fi
            else
                log_error "${context}file is a zip but neither unzip nor python3 is available to validate it."
                exit 1
            fi
            ;;
        *)
            if ! gunzip -t "$archive" 2>/dev/null; then
                log_error "${context}file is not a valid gzip archive."
                [ -n "$context" ] && log_error "The ${context}may have been corrupted or incomplete."
                exit 1
            fi
            ;;
    esac

    # Releases should be >1MB — catch truncated downloads that nonetheless
    # parse as valid archives (e.g. an empty zip central directory).
    local size_kb
    size_kb=$(du -k "$archive" 2>/dev/null | cut -f1)
    if [ "${size_kb:-0}" -lt 1024 ]; then
        log_error "${context}file too small (${size_kb}KB). File may be incomplete."
        exit 1
    fi
}

# Backwards-compatible wrapper — new code should call validate_archive.
validate_tarball() {
    validate_archive "$1" "${2:-}"
}

# Check if we can download from HTTPS URLs
# BusyBox wget on AD5M doesn't support HTTPS
check_https_capability() {
    # python urllib with the ssl module reaches HTTPS on python-only systems
    # like recent Creality K2 firmware — treat as HTTPS-capable. (An ssl-less
    # python can still download over the plain-HTTP mirror, so it must NOT be
    # reported HTTPS-capable here.)
    if _py_has_module ssl; then
        return 0
    fi

    # curl with SSL support works (skip BusyBox curl which lacks needed flags)
    if _has_real_curl; then
        # Test if curl can reach HTTPS (quick timeout)
        if curl -sSL --connect-timeout 5 -o /dev/null "https://github.com" 2>/dev/null; then
            return 0
        fi
    fi

    # Check if wget supports HTTPS
    if command -v wget >/dev/null 2>&1; then
        # BusyBox wget outputs "not an http or ftp url" for https
        if wget --help 2>&1 | grep -qi "https"; then
            return 0
        fi
        # Try a test fetch - BusyBox wget fails immediately on https URLs
        if wget -q --timeout=5 -O /dev/null "https://github.com" 2>/dev/null; then
            return 0
        fi
    fi

    return 1
}

# Show manual install instructions when HTTPS download isn't available
show_manual_install_instructions() {
    local platform=$1
    local version=${2:-latest}

    echo ""
    log_error "=========================================="
    log_error "  HTTPS Download Not Available"
    log_error "=========================================="
    echo ""
    log_error "This system cannot download from HTTPS URLs."
    log_error "BusyBox wget (common on embedded devices) doesn't support HTTPS."
    echo ""
    log_info "To install HelixScreen, download the release on another computer"
    log_info "and copy it to this device:"
    printf '\n'
    printf '%b\n' "  1. Download the release:"
    if [ "$version" = "latest" ]; then
        printf '%b\n' "     ${CYAN}https://github.com/${GITHUB_REPO}/releases/latest${NC}"
    else
        printf '%b\n' "     ${CYAN}https://github.com/${GITHUB_REPO}/releases/tag/${version}${NC}"
    fi
    printf '\n'
    printf '%b\n' "  2. Download: ${BOLD}helixscreen-${platform}.zip${NC}"
    printf '\n'
    printf '%b\n' "  3. Copy to this device (note: AD5M needs -O flag):"
    if [ "$platform" = "ad5m" ]; then
        # AD5M /tmp is a tiny tmpfs (~54MB), use /data/ instead
        printf '%b\n' "     ${CYAN}scp -O helixscreen-${platform}.zip root@<this-ip>:/data/${NC}"
        printf '%b\n' "     ${YELLOW}Windows: use WSL, WinSCP (SCP mode), or PuTTY pscp${NC}"
        printf '\n'
        printf '%b\n' "  4. Run the installer with the local file:"
        printf '%b\n' "     ${CYAN}sh /data/install.sh --local /data/helixscreen-${platform}.zip${NC}"
    else
        printf '%b\n' "     ${CYAN}scp helixscreen-${platform}.zip root@<this-ip>:/tmp/${NC}"
        printf '\n'
        printf '%b\n' "  4. Run the installer with the local file:"
        printf '%b\n' "     ${CYAN}sh /tmp/install.sh --local /tmp/helixscreen-${platform}.zip${NC}"
    fi
    printf '\n'
    exit 1
}

# Get latest release version from GitHub (with R2 CDN as primary source)
# Returns the tag name as-is (e.g., "v0.9.3")
# Args: platform (for error message if HTTPS unavailable)
get_latest_version() {
    local platform=${1:-unknown}
    local version=""

    # Try HTTPS sources first (R2 CDN → GitHub API)
    if check_https_capability; then
        # Try R2 manifest first (faster CDN, no API rate limits)
        local manifest_url="${R2_BASE_URL}/${R2_CHANNEL}/manifest.json"
        log_info "Fetching latest version from CDN..."

        _R2_MANIFEST=$(fetch_url "$manifest_url") || true
        if [ -n "$_R2_MANIFEST" ]; then
            version=$(echo "$_R2_MANIFEST" | parse_manifest_version)
            if [ -n "$version" ]; then
                # Manifest has bare version (e.g., "0.9.5"), we need the tag (e.g., "v0.9.5")
                version="v${version}"
                log_info "Latest version (CDN): ${version}"
                echo "$version"
                return 0
            fi
            log_warn "CDN manifest found but version could not be parsed, trying GitHub..."
            _R2_MANIFEST=""
        else
            log_warn "CDN unavailable, trying GitHub..."
        fi

        # Fallback: GitHub API
        local url="https://api.github.com/repos/${GITHUB_REPO}/releases/latest"
        log_info "Fetching latest version from GitHub..."

        # Use basic sed regex (no -E flag) for BusyBox compatibility
        version=$(fetch_url "$url" | grep '"tag_name"' | sed 's/.*"\([^"][^"]*\)".*/\1/')

        if [ -n "$version" ]; then
            echo "$version"
            return 0
        fi
        log_warn "HTTPS sources failed, trying HTTP fallback..."
    else
        log_warn "HTTPS not available, trying HTTP fallback..."
    fi

    # HTTP fallback for systems without SSL (K1, AD5M BusyBox wget)
    local http_manifest_url="${HTTP_BASE_URL}/${R2_CHANNEL}/manifest.json"
    log_info "Fetching latest version via HTTP..."

    _R2_MANIFEST=$(fetch_url_http "$http_manifest_url") || true
    if [ -n "$_R2_MANIFEST" ]; then
        version=$(echo "$_R2_MANIFEST" | parse_manifest_version)
        if [ -n "$version" ]; then
            version="v${version}"
            log_info "Latest version (HTTP): ${version}"
            echo "$version"
            return 0
        fi
    fi

    # All sources exhausted — show manual instructions
    log_error "Failed to fetch latest version from any source."
    show_manual_install_instructions "$platform" "latest"
}

# Map a detected platform identifier to the release artifact platform name.
# Most platforms use their own artifact name, but some share artifacts.
# Prints the release platform name to stdout.
get_release_platform() {
    local platform=$1
    local RELEASE_PLATFORM
    case "$platform" in
        snapmaker-u1) RELEASE_PLATFORM="snapmaker-u1" ;;
        *) RELEASE_PLATFORM="$platform" ;;
    esac
    echo "$RELEASE_PLATFORM"
}

# Try to download + validate a single candidate URL.
# Args: url dest transport  ("https" | "http")
# Returns 0 on success (archive staged at dest), 1 otherwise.
# Validation is format-aware based on dest's filename extension.
_try_download_candidate() {
    local url=$1 dest=$2 transport=$3
    case "$transport" in
        https)
            download_file "$url" "$dest" 300 51200 || return 1 ;;
        http)
            download_file_http "$url" "$dest" 300 || return 1 ;;
        *)
            return 1 ;;
    esac

    case "$dest" in
        *.zip)
            # unzip -tqq returns 0 if the central directory + every entry CRC is valid.
            # Fall back to python zipfile when unzip isn't present (K2 firmware).
            if command -v unzip >/dev/null 2>&1; then
                unzip -tqq "$dest" >/dev/null 2>&1 || return 1
            elif _has_python; then
                _py_unzip_test "$dest" || return 1
            else
                return 1
            fi
            ;;
        *)
            gunzip -t "$dest" 2>/dev/null || return 1
            ;;
    esac
    return 0
}

# Download release archive. Prefers the unversioned .zip (consumed by both this
# installer and Moonraker Update Manager) and falls back to the legacy versioned
# .tar.gz if no .zip is available at any transport — kept for bridge releases
# during the zip migration. Sets _ARCHIVE_FORMAT to record which format won.
# Tries R2 CDN, then GitHub Releases, then the plain-HTTP mirror.
download_release() {
    local version=$1
    local platform=$2
    platform=$(get_release_platform "$platform")

    mkdir -p "$TMP_DIR"
    CLEANUP_TMP=true

    local zip_filename="helixscreen-${platform}.zip"
    local zip_dest="${TMP_DIR}/helixscreen.zip"
    local tar_filename="helixscreen-${platform}-${version}.tar.gz"
    local tar_dest="${TMP_DIR}/helixscreen.tar.gz"

    # Build candidate URL lists. Zip gets tried before tar at every transport.
    local zip_r2="${R2_BASE_URL}/releases/${version}/${zip_filename}"
    local tar_r2=""
    if [ -n "$_R2_MANIFEST" ]; then
        tar_r2=$(echo "$_R2_MANIFEST" | parse_manifest_platform_url "$platform")
    fi
    if [ -z "$tar_r2" ]; then
        tar_r2="${R2_BASE_URL}/releases/${version}/${tar_filename}"
    fi

    local zip_gh="https://github.com/${GITHUB_REPO}/releases/download/${version}/${zip_filename}"
    local tar_gh="https://github.com/${GITHUB_REPO}/releases/download/${version}/${tar_filename}"

    local zip_http="${HTTP_BASE_URL}/releases/${version}/${zip_filename}"
    local tar_http="${HTTP_BASE_URL}/releases/${version}/${tar_filename}"
    if [ -n "$_R2_MANIFEST" ]; then
        local http_manifest_url
        http_manifest_url=$(echo "$_R2_MANIFEST" | parse_manifest_platform_url "$platform")
        if [ -n "$http_manifest_url" ]; then
            tar_http=$(echo "$http_manifest_url" | sed "s|${R2_BASE_URL}|${HTTP_BASE_URL}|")
        fi
    fi

    log_info "Downloading HelixScreen ${version} for ${platform}..."

    local size
    # --- Attempt 1: R2 CDN, zip preferred ---
    log_info "URL: $zip_r2"
    if _try_download_candidate "$zip_r2" "$zip_dest" https; then
        _ARCHIVE_FORMAT="zip"
        size=$(ls -lh "$zip_dest" | awk '{print $5}')
        log_success "Downloaded ${zip_filename} (${size}) from CDN"
        return 0
    fi
    rm -f "$zip_dest"
    log_info "URL: $tar_r2"
    if _try_download_candidate "$tar_r2" "$tar_dest" https; then
        _ARCHIVE_FORMAT="tar.gz"
        size=$(ls -lh "$tar_dest" | awk '{print $5}')
        log_success "Downloaded ${tar_filename} (${size}) from CDN"
        return 0
    fi
    rm -f "$tar_dest"
    log_warn "CDN download failed, trying GitHub..."

    # --- Attempt 2: GitHub Releases ---
    log_info "URL: $zip_gh"
    if _try_download_candidate "$zip_gh" "$zip_dest" https; then
        _ARCHIVE_FORMAT="zip"
        size=$(ls -lh "$zip_dest" | awk '{print $5}')
        log_success "Downloaded ${zip_filename} (${size}) from GitHub"
        return 0
    fi
    rm -f "$zip_dest"
    log_info "URL: $tar_gh"
    if _try_download_candidate "$tar_gh" "$tar_dest" https; then
        _ARCHIVE_FORMAT="tar.gz"
        size=$(ls -lh "$tar_dest" | awk '{print $5}')
        log_success "Downloaded ${tar_filename} (${size}) from GitHub"
        return 0
    fi
    rm -f "$tar_dest"

    # --- Attempt 3: plain-HTTP mirror (BusyBox wget fallback) ---
    log_info "Trying HTTP fallback..."
    log_info "URL: $zip_http"
    if _try_download_candidate "$zip_http" "$zip_dest" http; then
        _ARCHIVE_FORMAT="zip"
        size=$(ls -lh "$zip_dest" | awk '{print $5}')
        log_success "Downloaded ${zip_filename} (${size}) via HTTP"
        return 0
    fi
    rm -f "$zip_dest"
    log_info "URL: $tar_http"
    if _try_download_candidate "$tar_http" "$tar_dest" http; then
        _ARCHIVE_FORMAT="tar.gz"
        size=$(ls -lh "$tar_dest" | awk '{print $5}')
        log_success "Downloaded ${tar_filename} (${size}) via HTTP"
        return 0
    fi
    rm -f "$tar_dest"

    log_error "Failed to download release."
    log_error "Tried zip: $zip_r2"
    log_error "Tried zip: $zip_gh"
    log_error "Tried zip: $zip_http"
    log_error "Tried tar: $tar_r2"
    log_error "Tried tar: $tar_gh"
    log_error "Tried tar: $tar_http"
    if [ -n "$_DOWNLOAD_HTTP_CODE" ] && [ "$_DOWNLOAD_HTTP_CODE" != "200" ]; then
        log_error "HTTP status: $_DOWNLOAD_HTTP_CODE"
    fi
    log_error ""
    log_error "Possible causes:"
    log_error "  - Version ${version} may not exist for platform ${platform}"
    log_error "  - Network connectivity issues"
    log_error "  - CDN, GitHub, and HTTP mirror may be unavailable"
    log_error ""
    log_error "To install manually, download on another machine and use:"
    log_error "  ./install.sh --local /path/to/${zip_filename}"
    exit 1
}

# Use a local release archive instead of downloading.
# Accepts either .zip (preferred) or .tar.gz (legacy). Format is detected from
# the source filename extension and recorded in _ARCHIVE_FORMAT for
# extract_release() to dispatch on.
use_local_tarball() {
    local src=$1

    log_info "Using local archive: $src"

    case "$src" in
        *.zip)    _ARCHIVE_FORMAT="zip" ;;
        *.tar.gz|*.tgz) _ARCHIVE_FORMAT="tar.gz" ;;
        *)
            log_error "Unrecognized archive extension: $src"
            log_error "Expected a .zip or .tar.gz file."
            exit 1
            ;;
    esac

    validate_archive "$src" "Local "

    # Stage the archive under its canonical TMP_DIR name so extract_release()
    # and the in-app update flow can find it regardless of the source path.
    # Prefer a symlink to avoid copying large files on constrained devices.
    mkdir -p "$TMP_DIR"
    CLEANUP_TMP=true

    local dest
    dest=$(_archive_tmp_path)
    if [ "$src" != "$dest" ]; then
        # Resolve to absolute path so a symlink created in $TMP_DIR doesn't
        # become dangling if the user passed a relative path.
        # (BusyBox readlink may not support -f, so try realpath first.)
        local abs_src
        abs_src=$(realpath "$src" 2>/dev/null)
        [ -n "$abs_src" ] || abs_src=$(readlink -f "$src" 2>/dev/null)
        [ -n "$abs_src" ] || abs_src="$src"

        # Prefer a symlink to avoid copying large files on constrained devices,
        # but *verify* the staged tarball is readable. Fall back to copying.
        if ln -sf "$abs_src" "$dest" 2>/dev/null && [ -r "$dest" ]; then
            : # symlink OK
        elif cp "$abs_src" "$dest" 2>/dev/null && [ -r "$dest" ]; then
            : # copy OK
        else
            log_error "Failed to stage archive at $dest"
            log_error "Source: $abs_src"
            log_error "Check that the source file exists and the temp directory is writable."
            exit 1
        fi
    fi

    local size
    size=$(ls -lh "$src" | awk '{print $5}')
    log_success "Using local archive (${size}, ${_ARCHIVE_FORMAT})"
}

# Validate binary architecture matches the current system
# Args: binary_path platform
# Returns: 0 if valid, 1 if mismatch or error
validate_binary_architecture() {
    local binary=$1
    local platform=$2

    if [ ! -f "$binary" ]; then
        log_error "Binary not found: $binary"
        return 1
    fi

    # Read first 20 bytes of ELF header as space-separated hex
    # Try hexdump first (BusyBox), fall back to od (POSIX), then xxd
    local header
    header=$(dd if="$binary" bs=1 count=20 2>/dev/null | hexdump -v -e '1/1 "%02x "' 2>/dev/null) || true
    if [ -z "$header" ]; then
        header=$(dd if="$binary" bs=1 count=20 2>/dev/null | od -A n -t x1 -v 2>/dev/null | tr '\n' ' ' | tr -s ' ' | sed 's/^ //;s/ $//') || true
    fi
    if [ -z "$header" ]; then
        header=$(dd if="$binary" bs=1 count=20 2>/dev/null | xxd -p 2>/dev/null | sed 's/../& /g;s/ $//') || true
    fi

    if [ -z "$header" ]; then
        log_error "Cannot read binary header (file may be empty or corrupted)"
        return 1
    fi

    # Parse space-separated hex bytes into individual values
    # Header format: "7f 45 4c 46 CC ... XX XX MM MM ..."
    # Byte 0-3: ELF magic (7f 45 4c 46)
    # Byte 4: EI_CLASS (01=32-bit, 02=64-bit)
    # Byte 18-19: e_machine LE (28 00=ARM, b7 00=AARCH64)

    local magic
    magic=$(echo "$header" | awk '{printf "%s%s%s%s", $1, $2, $3, $4}')
    if [ "$magic" != "7f454c46" ]; then
        log_error "Binary is not a valid ELF file"
        return 1
    fi

    local elf_class
    elf_class=$(echo "$header" | awk '{print $5}')

    local machine_lo machine_hi
    machine_lo=$(echo "$header" | awk '{print $19}')
    machine_hi=$(echo "$header" | awk '{print $20}')

    # Determine expected values based on platform
    local expected_class expected_machine_lo expected_desc
    case "$platform" in
        ad5m|k2|pi32)
            expected_class="01"
            expected_machine_lo="28"
            expected_desc="ARM 32-bit (armv7l)"
            ;;
        ad5x|k1)
            expected_class="01"
            expected_machine_lo="08"
            expected_desc="MIPS 32-bit (mipsel)"
            ;;
        pi|snapmaker-u1)
            expected_class="02"
            expected_machine_lo="b7"
            expected_desc="AARCH64 64-bit"
            ;;
        x86)
            expected_class="02"
            expected_machine_lo="3e"
            expected_desc="x86_64 64-bit"
            ;;
        *)
            log_warn "Unknown platform '$platform', skipping architecture validation"
            return 0
            ;;
    esac

    local actual_desc
    if [ "$elf_class" = "01" ] && [ "$machine_lo" = "28" ]; then
        actual_desc="ARM 32-bit (armv7l)"
    elif [ "$elf_class" = "01" ] && [ "$machine_lo" = "08" ]; then
        actual_desc="MIPS 32-bit (mipsel)"
    elif [ "$elf_class" = "02" ] && [ "$machine_lo" = "b7" ]; then
        actual_desc="AARCH64 64-bit"
    elif [ "$elf_class" = "02" ] && [ "$machine_lo" = "3e" ]; then
        actual_desc="x86_64 64-bit"
    else
        actual_desc="unknown (class=$elf_class, machine=$machine_lo)"
    fi

    if [ "$elf_class" != "$expected_class" ] || [ "$machine_lo" != "$expected_machine_lo" ]; then
        log_error "Architecture mismatch!"
        log_error "  Expected: $expected_desc (for platform '$platform')"
        log_error "  Got:      $actual_desc"
        log_error "  This binary was built for the wrong platform."
        return 1
    fi

    log_info "Architecture validated: $actual_desc"
    return 0
}

# Extract archive with atomic swap and rollback protection.
# Dispatches on _ARCHIVE_FORMAT for zip vs tar.gz. Expects the archive already
# staged at _archive_tmp_path() by download_release() or use_local_tarball().
extract_release() {
    local platform=$1
    local archive
    archive=$(_archive_tmp_path)
    local extract_dir="${TMP_DIR}/extract"
    local new_install="${extract_dir}/helixscreen"

    # Pre-flight: check TMP_DIR has enough space for extraction.
    # Archive expands ~3x, so require 3x archive size + margin.
    local archive_mb extract_required_mb tmp_available_mb
    archive_mb=$(du -m "$archive" 2>/dev/null | awk '{print $1}')
    [ -z "$archive_mb" ] && archive_mb=$(ls -l "$archive" | awk '{print int($5/1048576)}')
    extract_required_mb=$(( (archive_mb * 3) + 20 ))

    local tmp_check_dir
    tmp_check_dir=$(dirname "$TMP_DIR")
    while [ ! -d "$tmp_check_dir" ] && [ "$tmp_check_dir" != "/" ]; do
        tmp_check_dir=$(dirname "$tmp_check_dir")
    done
    tmp_available_mb=$(df "$tmp_check_dir" 2>/dev/null | tail -1 | awk '{print int($4/1024)}')

    if [ -n "$tmp_available_mb" ] && [ "$tmp_available_mb" -lt "$extract_required_mb" ]; then
        log_error "Not enough space in temp directory for extraction."
        log_error "Temp directory: $tmp_check_dir (${tmp_available_mb}MB free, need ${extract_required_mb}MB)"
        log_error "Try: TMP_DIR=/path/with/space sh install.sh ..."
        exit 1
    fi

    log_info "Extracting release (${_ARCHIVE_FORMAT})..."

    # Phase 1: Extract to temporary directory
    mkdir -p "$extract_dir"
    cd "$extract_dir" || exit 1

    local extract_ok=false
    case "${_ARCHIVE_FORMAT:-tar.gz}" in
        zip)
            # The zip has a FLAT layout (no top-level helixscreen/ dir). That's
            # the contract with Moonraker Update Manager — it extracts straight
            # into the printer_data helixscreen directory. To keep downstream
            # code layout-agnostic, we re-create the helixscreen/ prefix here
            # by extracting into a subdirectory.
            # -o overwrites without prompting (no TTY in CI / systemd contexts),
            # -q suppresses the per-file listing. Fall back to python zipfile
            # when unzip isn't present (recent Creality K2 firmware).
            mkdir -p helixscreen
            if command -v unzip >/dev/null 2>&1; then
                ( cd helixscreen && unzip -q -o "$archive" ) && extract_ok=true
            elif _has_python; then
                _py_unzip_extract "$archive" "${extract_dir}/helixscreen" && extract_ok=true
            fi
            ;;
        *)
            # BusyBox tar doesn't support -z; use gunzip pipe on embedded platforms
            case "$platform" in
                ad5m|ad5x|k1|k2)
                    gunzip -c "$archive" | tar xf - && extract_ok=true ;;
                *)
                    tar -xzf "$archive" && extract_ok=true ;;
            esac
            ;;
    esac

    if [ "$extract_ok" = false ]; then
        local post_mb
        post_mb=$(df "$tmp_check_dir" 2>/dev/null | tail -1 | awk '{print int($4/1024)}')
        if [ -n "$post_mb" ] && [ "$post_mb" -lt 5 ]; then
            log_error "Failed to extract archive: no space left on device."
            log_error "Filesystem $(df "$tmp_check_dir" | tail -1 | awk '{print $1}') is full."
            log_error "Try: TMP_DIR=/path/with/space sh install.sh ..."
        else
            log_error "Failed to extract archive."
            log_error "The archive may be corrupted. Try re-downloading."
        fi
        rm -rf "$extract_dir"
        exit 1
    fi

    # Phase 2: Validate extracted content.
    #
    # The in-place update path (NoNewPrivileges, parent read-only) deletes the
    # old contents before moving the new ones in — so a new tree missing any
    # critical top-level entry leaves the user with a half-installed system
    # (see prestonbrown/helixscreen#970: ui_xml absent → "Could not find
    # HelixScreen data root" dead loop). Validate the full set up-front so we
    # bail BEFORE touching the existing install.
    _missing=""
    for _required in bin/helix-screen ui_xml assets; do
        if [ ! -e "${new_install}/${_required}" ]; then
            _missing="${_missing} ${_required}"
        fi
    done
    if [ -n "$_missing" ]; then
        log_error "Extracted archive is incomplete — missing:${_missing}"
        log_error "Expected layout: helixscreen/{bin/helix-screen, ui_xml/, assets/, …}"
        log_error "The archive may be corrupted or built without all asset stages."
        log_error "Existing installation is untouched."
        rm -rf "$extract_dir"
        exit 1
    fi

    # Phase 3: Validate architecture
    if ! validate_binary_architecture "${new_install}/bin/helix-screen" "$platform"; then
        log_error "Aborting installation due to architecture mismatch."
        rm -rf "$extract_dir"
        exit 1
    fi

    # Phase 4: Backup existing installation (if present)
    if [ -d "${INSTALL_DIR}" ]; then
        ORIGINAL_INSTALL_EXISTS=true

        # Backup config (check new name first, then legacy names)
        if [ -f "${INSTALL_DIR}/config/settings.json" ]; then
            BACKUP_CONFIG="${TMP_DIR}/settings.json.backup"
            cp "${INSTALL_DIR}/config/settings.json" "$BACKUP_CONFIG"
            log_info "Backed up existing configuration (from config/settings.json)"
        elif [ -f "${INSTALL_DIR}/config/helixconfig.json" ]; then
            BACKUP_CONFIG="${TMP_DIR}/settings.json.backup"
            cp "${INSTALL_DIR}/config/helixconfig.json" "$BACKUP_CONFIG"
            log_info "Backed up existing configuration (from config/helixconfig.json)"
        elif [ -f "${INSTALL_DIR}/settings.json" ]; then
            BACKUP_CONFIG="${TMP_DIR}/settings.json.backup"
            cp "${INSTALL_DIR}/settings.json" "$BACKUP_CONFIG"
            log_info "Backed up existing configuration (legacy root location)"
        elif [ -f "${INSTALL_DIR}/helixconfig.json" ]; then
            BACKUP_CONFIG="${TMP_DIR}/settings.json.backup"
            cp "${INSTALL_DIR}/helixconfig.json" "$BACKUP_CONFIG"
            log_info "Backed up existing configuration (legacy root location)"
        fi

        # Backup helixscreen.env (preserves HELIX_LOG_LEVEL and other env customizations)
        if [ -f "${INSTALL_DIR}/config/helixscreen.env" ]; then
            BACKUP_ENV="${TMP_DIR}/helixscreen.env.backup"
            cp "${INSTALL_DIR}/config/helixscreen.env" "$BACKUP_ENV"
            log_info "Backed up existing helixscreen.env"
        fi

        # Under NoNewPrivileges (self-update from in-app), we prefer the
        # atomic swap (mv old; mv new) if the parent dir is writable (service
        # file v0.97.4+ adds ReadWritePaths for it).  Fall back to the racy
        # in-place content replacement only on older service files where the
        # parent is still read-only under ProtectSystem=strict.
        if _has_no_new_privs; then
            # Verify INSTALL_DIR is writable.  Older service files only grant
            # ReadWritePaths to config/, so ProtectSystem=strict blocks writes
            # to the rest.  If so, the ExecStartPre ownership fix in the new
            # service file will resolve this on next restart.
            if ! touch "${INSTALL_DIR}/.update_test" 2>/dev/null; then
                log_error "Cannot write to ${INSTALL_DIR} (read-only under ProtectSystem)."
                log_error "The systemd service file needs updating to allow self-updates."
                log_error "Fix: re-run the installer once with:"
                log_error "  curl -fsSL https://releases.helixscreen.org/install.sh | bash"
                rm -rf "$extract_dir"
                exit 1
            fi
            rm -f "${INSTALL_DIR}/.update_test" 2>/dev/null

            # Test if parent dir is writable — if so, skip the racy in-place
            # path and fall through to the atomic swap below.
            local _parent_dir
            _parent_dir="$(dirname "${INSTALL_DIR}")"
            if touch "${_parent_dir}/.update_test" 2>/dev/null; then
                rm -f "${_parent_dir}/.update_test" 2>/dev/null
                log_info "Parent dir writable — using atomic swap"
                # Fall through to the standard atomic swap path below
            else
                log_info "Self-update: replacing install contents in-place (parent read-only)..."

                # Remove old contents (except config/).
                # Don't use || true — if rm fails, we must not proceed to mv
                # because mv can't overwrite a non-empty directory.
                local _inplace_failed=false
                for _item in "${INSTALL_DIR}"/*; do
                    [ -e "$_item" ] || continue
                    _base=$(basename "$_item")
                    [ "$_base" = "config" ] && continue
                    if ! rm -rf "$_item"; then
                        log_error "Failed to remove old ${_base}"
                        _inplace_failed=true
                    fi
                done
                # Hidden files too
                for _item in "${INSTALL_DIR}"/.*; do
                    [ -e "$_item" ] || continue
                    _base=$(basename "$_item")
                    case "$_base" in .|..) continue ;; esac
                    rm -rf "$_item" 2>/dev/null || true
                done

                if [ "$_inplace_failed" = true ]; then
                    log_error "In-place update failed. Install may be in a broken state."
                    log_error "Fix: re-run the installer: curl -fsSL https://releases.helixscreen.org/install.sh | bash"
                    rm -rf "$extract_dir"
                    exit 1
                fi

                # Move new contents in (except config/)
                for _item in "${new_install}"/*; do
                    [ -e "$_item" ] || continue
                    _base=$(basename "$_item")
                    [ "$_base" = "config" ] && continue
                    if ! mv "$_item" "${INSTALL_DIR}/${_base}"; then
                        log_error "Failed to install: ${_base}"
                        rm -rf "$extract_dir"
                        exit 1
                    fi
                done
                # Hidden files too
                for _item in "${new_install}"/.*; do
                    [ -e "$_item" ] || continue
                    _base=$(basename "$_item")
                    case "$_base" in .|..) continue ;; esac
                    mv "$_item" "${INSTALL_DIR}/${_base}" 2>/dev/null || true
                done

                # Merge new config defaults without overwriting user files.
                # New versions may ship config files that didn't exist before.
                if [ -d "${new_install}/config" ]; then
                    for _item in "${new_install}/config"/*; do
                        [ -e "$_item" ] || continue
                        _base=$(basename "$_item")
                        if [ ! -e "${INSTALL_DIR}/config/${_base}" ]; then
                            mv "$_item" "${INSTALL_DIR}/config/${_base}" 2>/dev/null || true
                            log_info "Added new config default: ${_base}"
                        elif [ -d "$_item" ] && [ -d "${INSTALL_DIR}/config/${_base}" ]; then
                            # Merge directory contents (e.g. printer_database.d/)
                            for _subitem in "$_item"/*; do
                                [ -e "$_subitem" ] || continue
                                _subbase=$(basename "$_subitem")
                                if [ ! -e "${INSTALL_DIR}/config/${_base}/${_subbase}" ]; then
                                    mv "$_subitem" "${INSTALL_DIR}/config/${_base}/${_subbase}" 2>/dev/null || true
                                fi
                            done
                        fi
                    done
                fi

                rm -rf "$extract_dir"
                log_success "Updated in-place at ${INSTALL_DIR}"
                return 0
            fi
        fi

        # Standard path (fresh install or non-self-update with sudo access):
        # atomic directory swap via rename in parent directory.

        # Choose backup dir name for atomic swap.
        # Prefer INSTALL_DIR.old; if it exists and can't be removed (e.g. root-owned
        # under NoNewPrivileges), fall back to a timestamped name so the swap succeeds.
        INSTALL_BACKUP="${INSTALL_DIR}.old"
        if [ -d "$INSTALL_BACKUP" ]; then
            log_info "Removing stale backup from previous install..."
            if ! rm -rf "$INSTALL_BACKUP" 2>/dev/null && ! $SUDO rm -rf "$INSTALL_BACKUP" 2>/dev/null; then
                INSTALL_BACKUP="${INSTALL_DIR}.old.$(date +%s)"
                log_warn "Could not remove stale .old dir (root-owned?); using $INSTALL_BACKUP instead"
            fi
        fi

        # Atomic swap: move old install to backup
        if ! $(file_sudo "${INSTALL_DIR}") mv "${INSTALL_DIR}" "$INSTALL_BACKUP"; then
            log_error "Failed to backup existing installation."
            rm -rf "$extract_dir"
            exit 1
        fi
    fi

    # Phase 5: Move new install into place
    $(file_sudo "$(dirname "${INSTALL_DIR}")") mkdir -p "$(dirname "${INSTALL_DIR}")"
    if ! $(file_sudo "$(dirname "${INSTALL_DIR}")") mv "${new_install}" "${INSTALL_DIR}"; then
        log_error "Failed to install new release."
        # ROLLBACK: restore old installation
        if [ -d "${INSTALL_BACKUP:-}" ]; then
            log_warn "Rolling back to previous installation..."
            # Remove partial new install that may block the rollback mv
            [ -d "${INSTALL_DIR}" ] && $SUDO rm -rf "${INSTALL_DIR}"
            if $SUDO mv "$INSTALL_BACKUP" "${INSTALL_DIR}"; then
                log_warn "Rollback complete. Previous installation restored."
            else
                log_error "CRITICAL: Rollback failed! Previous install at $INSTALL_BACKUP"
                log_error "Manually restore with: mv $INSTALL_BACKUP ${INSTALL_DIR}"
            fi
        fi
        rm -rf "$extract_dir"
        exit 1
    fi

    # Phase 6: Restore config and settings
    # User's config always takes priority over bundled defaults so customizations
    # survive updates.  Try TMP_DIR backup first; fall back to the .old copy.
    # (Under systemd PrivateTmp=true the TMP_DIR mount can vanish on restart,
    # so the .old directory on the real filesystem acts as a safety net.)
    $(file_sudo "${INSTALL_DIR}") mkdir -p "${INSTALL_DIR}/config" 2>/dev/null || true

    # Remove tarball's default settings.json if we have a backup to restore.
    # If Phase 6 restore fails, we want the file to be MISSING so that
    # Config::init()'s restore_from_backup() safety net kicks in.
    # Without this, a failed restore leaves the tarball defaults in place,
    # which Config::init() loads without attempting backup recovery.
    #
    # Note: helixscreen.env is NOT removed here — there is no Config::init
    # safety net for env files, and the restore step below uses `cp` which
    # overwrites, so leaving the tarball's bundled copy in place gives both
    # behaviors (user backup wins if present, bundled default stays otherwise).
    # Removing it caused the env file to disappear permanently across upgrades
    # when no backup existed (Pi user report 2026-05-13).
    if [ "$ORIGINAL_INSTALL_EXISTS" = true ]; then
        rm -f "${INSTALL_DIR}/config/settings.json" 2>/dev/null
    fi

    # _restore_config_file SRC DEST LABEL — copy a single config file with
    # appropriate sudo, logging success or warning on failure.
    _restore_config_file() {
        local _src=$1 _dest=$2 _label=$3
        if $(file_sudo "$(dirname "$_dest")") cp "$_src" "$_dest" 2>/dev/null; then
            log_info "Restored $_label"
        else
            log_warn "Failed to restore $_label"
        fi
    }

    # Restore settings.json — try candidates in priority order (new name, then legacy)
    _config_dest="${INSTALL_DIR}/config/settings.json"
    if [ -n "${BACKUP_CONFIG:-}" ] && [ -s "$BACKUP_CONFIG" ]; then
        _restore_config_file "$BACKUP_CONFIG" "$_config_dest" "settings.json from TMP_DIR backup"
    elif [ -n "${INSTALL_BACKUP:-}" ]; then
        if [ -f "${INSTALL_BACKUP}/config/settings.json" ]; then
            _restore_config_file "${INSTALL_BACKUP}/config/settings.json" "$_config_dest" "settings.json from .old backup"
        elif [ -f "${INSTALL_BACKUP}/config/helixconfig.json" ]; then
            _restore_config_file "${INSTALL_BACKUP}/config/helixconfig.json" "$_config_dest" "settings.json from .old backup (migrated from helixconfig.json)"
        elif [ -f "${INSTALL_BACKUP}/settings.json" ]; then
            _restore_config_file "${INSTALL_BACKUP}/settings.json" "$_config_dest" "settings.json from .old backup (legacy root location)"
        elif [ -f "${INSTALL_BACKUP}/helixconfig.json" ]; then
            _restore_config_file "${INSTALL_BACKUP}/helixconfig.json" "$_config_dest" "settings.json from .old backup (legacy root location)"
        fi
    fi
    if [ ! -f "$_config_dest" ] && [ "$ORIGINAL_INSTALL_EXISTS" = true ]; then
        log_warn "Could not restore settings.json from any backup source!"
        log_warn "User configuration may have been lost."
    fi

    # Restore helixscreen.env — user may have customized HELIX_LOG_LEVEL,
    # MOONRAKER_HOST, etc.  Overwrite the bundled default with their backup.
    _env_dest="${INSTALL_DIR}/config/helixscreen.env"
    if [ -n "${BACKUP_ENV:-}" ] && [ -s "$BACKUP_ENV" ]; then
        _restore_config_file "$BACKUP_ENV" "$_env_dest" "helixscreen.env from TMP_DIR backup"
    elif [ -n "${INSTALL_BACKUP:-}" ] && [ -f "${INSTALL_BACKUP}/config/helixscreen.env" ]; then
        _restore_config_file "${INSTALL_BACKUP}/config/helixscreen.env" "$_env_dest" "helixscreen.env from .old backup"
    fi

    # One-time migration: older env templates shipped `HELIX_LOG_LEVEL=info`
    # uncommented, which silently shadowed the in-app Settings → System → Log
    # Level setting on every restart. Comment it out IFF it still matches the
    # exact old default, so users who deliberately set a different value keep
    # their customization.
    if [ -f "$_env_dest" ] && grep -q '^HELIX_LOG_LEVEL=info[[:space:]]*$' "$_env_dest"; then
        $(file_sudo "$_env_dest") sed -i 's/^HELIX_LOG_LEVEL=info[[:space:]]*$/#HELIX_LOG_LEVEL=info/' "$_env_dest" 2>/dev/null && \
            log_info "Migrated helixscreen.env: commented out default HELIX_LOG_LEVEL=info (in-app Log Level setting now applies)"
    fi

    # Prune legacy seed files from the .old backup before the restore loop.
    # Older releases shipped these inside config/; current releases ship them
    # under assets/config/ instead. Without this prune, the loop below would
    # restore the *old* shipped versions on top of the new ones — users would
    # be stuck on stale printer_database.json / themes / presets forever.
    # User-state files (settings.json, telemetry_*.json, custom_images/,
    # printer_database.d/, themes/<user-themes>.json) are untouched.
    if [ -n "${INSTALL_BACKUP:-}" ] && [ -d "${INSTALL_BACKUP}/config" ]; then
        for _legacy_seed in printer_database.json printing_tips.json default_layout.json helix_macros.cfg; do
            $(file_sudo "${INSTALL_BACKUP}/config") rm -f "${INSTALL_BACKUP}/config/${_legacy_seed}" 2>/dev/null || true
        done
        for _legacy_seed_dir in presets print_start_profiles sounds platform; do
            $(file_sudo "${INSTALL_BACKUP}/config") rm -rf "${INSTALL_BACKUP}/config/${_legacy_seed_dir}" 2>/dev/null || true
        done
        # themes/defaults moved out of themes/; keep user themes (sibling files).
        $(file_sudo "${INSTALL_BACKUP}/config/themes") rm -rf "${INSTALL_BACKUP}/config/themes/defaults" 2>/dev/null || true
    fi

    # Restore any remaining user data from previous config/ (custom_images/,
    # printer_database.d/, user themes, etc.).  Only copies items that don't
    # already exist in the new install so bundled files are never overwritten.
    # Uses [ ! -e ] instead of cp -n for BusyBox compatibility.
    # For directories that exist in both old and new installs (e.g. printer_database.d/),
    # merge at the file level so user additions are preserved alongside new bundled files.
    if [ -n "${INSTALL_BACKUP:-}" ] && [ -d "${INSTALL_BACKUP}/config" ]; then
        for _item in "${INSTALL_BACKUP}/config"/*; do
            [ -e "$_item" ] || continue
            _base=$(basename "$_item")
            if [ ! -e "${INSTALL_DIR}/config/${_base}" ]; then
                # Item doesn't exist in new install — restore the whole thing
                if $(file_sudo "${INSTALL_DIR}/config") cp -r "$_item" "${INSTALL_DIR}/config/${_base}" 2>/dev/null; then
                    log_info "Restored user data: config/${_base}"
                else
                    log_warn "Failed to restore user data: config/${_base}"
                fi
            elif [ -d "$_item" ] && [ -d "${INSTALL_DIR}/config/${_base}" ]; then
                # Both old and new have this directory — merge individual files
                for _subitem in "$_item"/*; do
                    [ -e "$_subitem" ] || continue
                    _subbase=$(basename "$_subitem")
                    if [ ! -e "${INSTALL_DIR}/config/${_base}/${_subbase}" ]; then
                        if $(file_sudo "${INSTALL_DIR}/config/${_base}") cp -r "$_subitem" "${INSTALL_DIR}/config/${_base}/${_subbase}" 2>/dev/null; then
                            log_info "Restored user data: config/${_base}/${_subbase}"
                        else
                            log_warn "Failed to restore user data: config/${_base}/${_subbase}"
                        fi
                    fi
                done
            fi
        done
    fi

    # Cleanup — cd out first since we cd'd into extract_dir earlier;
    # removing the CWD causes "getcwd: cannot access parent directories"
    # errors in subsequent commands (#703)
    cd / 2>/dev/null || true
    rm -rf "$extract_dir"

    # Remove legacy files that were shipped in older releases but are no longer needed.
    # Source fonts (.ttf/.otf) are only used by font regen scripts during development,
    # not at runtime. Removes ~35 MB of dead weight on embedded devices.
    local _legacy_removed=0
    for _ext in ttf otf; do
        for _f in "${INSTALL_DIR}"/assets/fonts/*."${_ext}"; do
            [ -f "$_f" ] || continue
            $(file_sudo "${INSTALL_DIR}") rm -f "$_f" 2>/dev/null && _legacy_removed=$((_legacy_removed + 1))
        done
    done
    $(file_sudo "${INSTALL_DIR}") rm -f "${INSTALL_DIR}/assets/fonts/.clang-format" 2>/dev/null && _legacy_removed=$((_legacy_removed + 1))
    [ "$_legacy_removed" -gt 0 ] && log_info "Removed $_legacy_removed legacy dev-only files from assets/fonts"

    log_success "Extracted to ${INSTALL_DIR}"
}

# Remove backup of previous installation (call after service starts successfully)
cleanup_old_install() {
    # Keep .old as a last-resort recovery path if config wasn't restored.
    # Without this guard, a failed Phase 6 + cleanup = permanent config loss.
    if [ "$ORIGINAL_INSTALL_EXISTS" = true ] && [ ! -f "${INSTALL_DIR}/config/settings.json" ]; then
        log_warn "Config not restored — keeping .old backup for recovery"
        return 0
    fi

    # Clean both the standard .old and any timestamped fallback backups
    for _backup in "${INSTALL_DIR}.old" "${INSTALL_DIR}.old."*; do
        if [ -d "$_backup" ]; then
            rm -rf "$_backup" 2>/dev/null || $SUDO rm -rf "$_backup" 2>/dev/null || true
            log_info "Cleaned up previous installation backup: $_backup"
        fi
    done
}

# ============================================
# Module: service.sh
# ============================================

#
# SERVICE_NAME is defined in common.sh
# Portable in-place sed: GNU sed uses -i, BSD/macOS sed requires -i ''
_sed_inplace() {
    local pattern=$1 file=$2
    $SUDO sed -i "$pattern" "$file" 2>/dev/null || \
    $SUDO sed -i '' "$pattern" "$file" 2>/dev/null || true
}

# Returns true if this process is running under the NoNewPrivileges systemd constraint.
# When helix-screen self-updates, it spawns install.sh as a child process.  The
# helixscreen.service unit has NoNewPrivileges=true, so ALL sudo calls in install.sh
# will fail.  Callers use this to skip operations that require root (service file
# copy, daemon-reload, systemctl start) and instead let update_checker.cpp restart
# the process via exit(0), which the watchdog treats as "restart silently".
_has_no_new_privs() {
    # Primary: check /proc/self/status (kernel 4.10+)
    if [ -r /proc/self/status ] && grep -q '^NoNewPrivs:[[:space:]]*1' /proc/self/status 2>/dev/null; then
        return 0
    fi
    # Fallback for older kernels (e.g. SonicPad 4.9): if we know this is a
    # self-update spawned from the running app, the service unit's
    # NoNewPrivileges=true is inherited — sudo will fail.
    _is_self_update
}

# _is_self_update() is defined in common.sh (sourced before this module)

# Fix a known-broken PLATFORM_HOOKS path in an already-deployed init script.
#
# Init scripts shipped before 2026-04-20 sourced platform hooks from
# ${DAEMON_DIR}/assets/config/platform/hooks.sh, but the installer (and the
# deploy makefile) write hooks to ${DAEMON_DIR}/platform/hooks.sh.  Result:
# the file was never found, platform_stop_competing_uis() stayed a no-op,
# and stock UIs (Creality K2 /etc/init.d/app, etc.) ran alongside HelixScreen.
#
# Self-update deliberately skips copying the init script to preserve
# platform customizations (#314), so a pure source-tree fix can't reach
# already-installed users.  This surgical sed rewrites only that one
# known-broken substring; anything else the platform may have customized
# is left alone.
_migrate_init_script_hooks_path() {
    local init_script="${INIT_SCRIPT_DEST:-}"
    [ -n "$init_script" ] && [ -f "$init_script" ] || return 0
    if grep -q 'assets/config/platform/hooks\.sh' "$init_script" 2>/dev/null; then
        log_info "Migrating stale PLATFORM_HOOKS path in $init_script"
        _sed_inplace 's|assets/config/platform/hooks\.sh|platform/hooks.sh|' "$init_script"
    fi
}

# Install service (dispatcher)
# Calls install_service_systemd or install_service_sysv based on INIT_SYSTEM
install_service() {
    local platform=$1

    if [ "$platform" = "snapmaker-u1" ]; then
        install_service_snapmaker_u1
        return
    fi

    if [ "$INIT_SYSTEM" = "systemd" ]; then
        install_service_systemd
    else
        install_service_sysv
        # K2 (procd) needs an extra shim — see install_procd_shim_k2
        if [ "$platform" = "k2" ]; then
            install_procd_shim_k2
        fi
    fi
}

# K2 (Tina Linux / procd) requires init scripts to use the rc.common
# shebang AND declare a DEPEND directive — without both, procd's boot
# iterator silently skips them. Our shared SysV-style S99helixscreen has
# neither, so on K2 it's never auto-started at boot, leaving the device
# stuck on the Creality boot logo with no UI.
#
# Fix: install a tiny procd-compatible /etc/init.d/helixscreen shim that
# delegates every action to the real SysV script. Replace any existing
# rc.d symlink (older installs pointed it at the SysV script directly,
# which procd silently skips).
install_procd_shim_k2() {
    local shim_src="${INSTALL_DIR}/config/helixscreen-k2-procd-shim.sh"
    local shim_dest="/etc/init.d/helixscreen"

    if [ ! -x /etc/rc.common ]; then
        log_warn "K2 procd shim: /etc/rc.common not found — skipping (boot autostart will not work)"
        return 0
    fi

    if [ ! -f "$shim_src" ]; then
        log_error "K2 procd shim source missing: $shim_src"
        log_error "The release package may be incomplete."
        log_error "Recovery: re-run the installer to download a fresh copy:"
        log_error "  curl -fsSL https://releases.helixscreen.org/install.sh | bash"
        return 1
    fi

    log_info "Installing K2 procd boot shim..."
    $SUDO cp "$shim_src" "$shim_dest"
    $SUDO chmod +x "$shim_dest"

    # Older installs (and `make deploy-k2` before mk/cross.mk was fixed)
    # symlinked /etc/rc.d/S99helixscreen directly to the SysV script,
    # which procd skips at boot. Drop those, then let rc.common's `enable`
    # create fresh S99/K01 symlinks pointing at the shim. Verify the rc.d
    # entry before returning — `enable` exits 0 even on weird edge cases,
    # and a silently-wrong symlink is the original bug we're fixing here.
    $SUDO rm -f /etc/rc.d/S99helixscreen /etc/rc.d/K01helixscreen
    if ! $SUDO "$shim_dest" enable; then
        log_warn "K2 procd shim: enable failed — UI will not autostart at boot"
        log_warn "Manual fix: $SUDO $shim_dest enable"
        return 1
    fi

    local rcd_target
    rcd_target=$(readlink /etc/rc.d/S99helixscreen 2>/dev/null || true)
    if [ "$rcd_target" != "../init.d/helixscreen" ]; then
        log_error "K2 procd shim: /etc/rc.d/S99helixscreen -> '$rcd_target' (expected '../init.d/helixscreen')"
        log_error "UI will not autostart at boot (see [L086])."
        return 1
    fi

    log_success "Installed K2 procd shim at $shim_dest (boot symlink verified)"
}

install_service_snapmaker_u1() {
    log_info "Configuring Snapmaker U1 autostart..."

    # --- Fix DAEMON_DIR in the init script (U1 keeps it in-place, not /etc/init.d/) ---
    local init_script="${INSTALL_DIR}/config/helixscreen.init"
    if [ ! -f "$init_script" ]; then
        log_error "Init script not found: $init_script"
        exit 1
    fi
    chmod +x "$init_script"
    _sed_inplace "s|DAEMON_DIR=.*|DAEMON_DIR=\"${INSTALL_DIR}\"|" "$init_script"

    # --- Patch S99screen to delegate to helixscreen.init on boot ---
    if [ -f "${INSTALL_DIR}/scripts/snapmaker-u1-setup-autostart.sh" ]; then
        if ! bash "${INSTALL_DIR}/scripts/snapmaker-u1-setup-autostart.sh" "${INSTALL_DIR}"; then
            log_error "Snapmaker U1 autostart configuration failed."
            log_error "Ensure /oem and /etc/init.d are writable."
            exit 1
        fi
    else
        log_error "Snapmaker U1 autostart script not found at ${INSTALL_DIR}/scripts/snapmaker-u1-setup-autostart.sh"
        log_error "The release package may be incomplete."
        log_error "Recovery: re-run the installer to download a fresh copy:"
        log_error "  curl -fsSL https://releases.helixscreen.org/install.sh | bash"
        exit 1
    fi
}

# Install systemd service
install_service_systemd() {
    # During self-update, the main service file is already installed and may
    # contain platform customizations (#314) — don't overwrite it.
    # BUT: always update the update-watcher units (path + oneshot service).
    # They have no platform customizations and older versions had a PathExists
    # bug that causes an infinite restart loop after any update.
    if _is_self_update; then
        log_info "Skipping main service file install (self-update; preserving customizations)"
        update_watcher_if_stale
        CLEANUP_SERVICE=true
        return 0
    fi

    log_info "Installing systemd service..."

    local service_src="${INSTALL_DIR}/config/helixscreen.service"
    local service_dest="/etc/systemd/system/${SERVICE_NAME}.service"

    if [ ! -f "$service_src" ]; then
        log_error "Service file not found: $service_src"
        log_error "The release package may be incomplete."
        log_error "Recovery: re-run the installer to download a fresh copy:"
        log_error "  curl -fsSL https://releases.helixscreen.org/install.sh | bash"
        exit 1
    fi

    # Under NoNewPrivileges (self-update spawned by helix-screen), sudo is blocked and
    # /etc/systemd/system/ is read-only in the service's mount namespace.  The service
    # is already installed and correct — skip reinstall.  The process restart is handled
    # by update_checker.cpp calling exit(0) after install.sh succeeds.
    if _has_no_new_privs; then
        if [ -f "$service_dest" ]; then
            log_info "Skipping service reinstall (NoNewPrivileges; already installed)"
            CLEANUP_SERVICE=true
            return 0
        fi
        log_error "Service not installed and NoNewPrivileges prevents installation"
        exit 1
    fi

    $SUDO cp "$service_src" "$service_dest"

    # Template placeholders (match SysV pattern in install_service_sysv).
    # KLIPPER_GROUP is the user's actual primary group (resolved via id -gn);
    # falling back to KLIPPER_USER would re-introduce the QIDI Q2 bug where
    # `mks` user has no `mks` group and systemd refuses to spawn the unit.
    local helix_user="${KLIPPER_USER:-root}"
    local helix_group="${KLIPPER_GROUP:-${KLIPPER_USER:-root}}"
    local install_dir="${INSTALL_DIR:-/opt/helixscreen}"

    local install_parent
    install_parent="$(dirname "${install_dir}")"

    _sed_inplace "s|@@HELIX_USER@@|${helix_user}|g" "$service_dest"
    _sed_inplace "s|@@HELIX_GROUP@@|${helix_group}|g" "$service_dest"
    _sed_inplace "s|@@INSTALL_DIR@@|${install_dir}|g" "$service_dest"
    _sed_inplace "s|@@INSTALL_PARENT@@|${install_parent}|g" "$service_dest"

    if ! $SUDO systemctl daemon-reload; then
        log_error "Failed to reload systemd daemon."
        exit 1
    fi

    # Install update watcher (restarts helixscreen after Moonraker web-type update)
    # Workaround for mainsail-crew/mainsail#2444: type: web lacks managed_services
    install_update_watcher_systemd

    CLEANUP_SERVICE=true
    log_success "Installed systemd service"
}

# During self-update, check if the deployed update-watcher path unit has the
# old PathExists directive (which causes infinite restart loops) and fix it.
# The watcher units have no platform customizations — only @@INSTALL_DIR@@.
# Under NoNewPrivileges we can't write to /etc/systemd/system/ or run
# systemctl daemon-reload, so we rely on helixscreen-update.service's
# ExecStartPre to refresh the main service file on next Moonraker update.
# However, the PATH unit itself won't get refreshed that way, so we attempt
# a direct fix here and fall back to a warning if permissions block it.
update_watcher_if_stale() {
    local path_dest="/etc/systemd/system/helixscreen-update.path"
    local svc_dest="/etc/systemd/system/helixscreen-update.service"

    # Only relevant on systemd with the watcher installed
    [ "$INIT_SYSTEM" = "systemd" ] || return 0
    [ -f "$path_dest" ] || return 0

    # Detect staleness: PathExists bug (restart loop), missing sentinel check
    # (self-update double-trigger #536), or missing refresh-service-units.sh.
    local stale=false reason=""
    if grep -q '^PathExists=' "$path_dest" 2>/dev/null; then
        stale=true reason="PathExists bug (restart loop)"
    elif [ -f "$svc_dest" ] && ! grep -q 'self_restart_sentinel' "$svc_dest" 2>/dev/null; then
        stale=true reason="missing self-update sentinel check (#536)"
    elif [ -f "$svc_dest" ] && ! grep -q 'refresh-service-units' "$svc_dest" 2>/dev/null; then
        stale=true reason="missing service file refresh"
    fi

    if ! $stale; then
        log_info "Update watcher units are current"
        return 0
    fi

    log_warn "Stale update watcher units: $reason"

    local path_src="${INSTALL_DIR}/config/helixscreen-update.path"
    local svc_src="${INSTALL_DIR}/config/helixscreen-update.service"
    local install_dir="${INSTALL_DIR:-/opt/helixscreen}"
    local install_parent
    install_parent="$(dirname "$install_dir")"

    if _has_no_new_privs; then
        # Can't write to /etc/systemd/system/ under NoNewPrivileges.
        # Attempt in-place fixes — may fail under ProtectSystem=strict.
        local fixed=false
        if grep -q '^PathExists=' "$path_dest" 2>/dev/null; then
            sed -i 's/^PathExists=/PathChanged=/' "$path_dest" 2>/dev/null && fixed=true
        fi
        if [ -f "$svc_src" ] && [ -f "$svc_dest" ]; then
            if cp "$svc_src" "$svc_dest" 2>/dev/null; then
                sed -i -e "s|@@INSTALL_DIR@@|${install_dir}|g" \
                       -e "s|@@INSTALL_PARENT@@|${install_parent}|g" \
                    "$svc_dest" 2>/dev/null
                fixed=true
            fi
        fi
        if $fixed; then
            log_success "Updated watcher units (best-effort under NoNewPrivileges)"
        else
            log_warn "Cannot update watcher units under NoNewPrivileges."
            log_warn "Fix: sudo ${install_dir}/config/refresh-service-units.sh"
        fi
        return 0
    fi

    # Have sudo access — do a full replacement
    if [ -f "$path_src" ] && [ -f "$svc_src" ]; then
        $SUDO cp "$path_src" "$path_dest"
        $SUDO cp "$svc_src" "$svc_dest"
        _sed_inplace "s|@@INSTALL_DIR@@|${install_dir}|g" "$path_dest"
        _sed_inplace "s|@@INSTALL_DIR@@|${install_dir}|g" "$svc_dest"
        _sed_inplace "s|@@INSTALL_PARENT@@|${install_parent}|g" "$path_dest"
        _sed_inplace "s|@@INSTALL_PARENT@@|${install_parent}|g" "$svc_dest"
        $SUDO systemctl daemon-reload 2>/dev/null || true
        $SUDO systemctl restart helixscreen-update.path 2>/dev/null || true
        log_success "Updated watcher units ($reason)"
    fi
}

# Install systemd path unit that restarts helixscreen after Moonraker extracts an update
install_update_watcher_systemd() {
    local path_src="${INSTALL_DIR}/config/helixscreen-update.path"
    local svc_src="${INSTALL_DIR}/config/helixscreen-update.service"
    local path_dest="/etc/systemd/system/helixscreen-update.path"
    local svc_dest="/etc/systemd/system/helixscreen-update.service"

    if [ ! -f "$path_src" ] || [ ! -f "$svc_src" ]; then
        log_info "Update watcher units not found, skipping"
        return 0
    fi

    local install_dir="${INSTALL_DIR:-/opt/helixscreen}"

    $SUDO cp "$path_src" "$path_dest"
    $SUDO cp "$svc_src" "$svc_dest"

    # Template the install directory path in both units
    _sed_inplace "s|@@INSTALL_DIR@@|${install_dir}|g" "$path_dest"
    _sed_inplace "s|@@INSTALL_DIR@@|${install_dir}|g" "$svc_dest"

    $SUDO systemctl daemon-reload
    $SUDO systemctl enable helixscreen-update.path 2>/dev/null || true
    $SUDO systemctl start helixscreen-update.path 2>/dev/null || true

    log_info "Installed update watcher (helixscreen-update.path)"
}

# Install SysV init script
install_service_sysv() {
    # During self-update, the init script is already installed and correct.
    # Overwriting it destroys platform customizations (ZMOD, Klipper Mod) (#314).
    if _is_self_update; then
        log_info "Skipping init script install (self-update; already installed)"
        _migrate_init_script_hooks_path
        CLEANUP_SERVICE=true
        return 0
    fi

    log_info "Installing SysV init script..."

    local init_src="${INSTALL_DIR}/config/helixscreen.init"

    if [ ! -f "$init_src" ]; then
        log_error "Init script not found: $init_src"
        log_error "The release package may be incomplete."
        log_error "Recovery: re-run the installer to download a fresh copy:"
        log_error "  curl -fsSL https://releases.helixscreen.org/install.sh | bash"
        exit 1
    fi

    # Use the dynamically set INIT_SCRIPT_DEST (varies by firmware)
    $SUDO cp "$init_src" "$INIT_SCRIPT_DEST"
    $SUDO chmod +x "$INIT_SCRIPT_DEST"

    # Update the DAEMON_DIR in the init script to match the install location
    # This is important for Klipper Mod which uses a different path
    _sed_inplace "s|DAEMON_DIR=.*|DAEMON_DIR=\"${INSTALL_DIR}\"|" "$INIT_SCRIPT_DEST"

    CLEANUP_SERVICE=true
    log_success "Installed SysV init script at $INIT_SCRIPT_DEST"
}

# Start service (dispatcher)
# Calls start_service_systemd or start_service_sysv based on INIT_SYSTEM.
# Snapmaker U1 uses its own init script path (patched S99screen, not S99helixscreen).
start_service() {
    local platform=${1:-}

    if [ "$platform" = "snapmaker-u1" ]; then
        start_service_snapmaker_u1
        return
    fi

    if [ "$INIT_SYSTEM" = "systemd" ]; then
        start_service_systemd
    else
        start_service_sysv
    fi
}

# Start service (Snapmaker U1)
# The U1 patches /etc/init.d/S99screen to delegate to helixscreen.init;
# there is no standalone S99helixscreen init script.
start_service_snapmaker_u1() {
    if _is_self_update; then
        log_info "Skipping service start (self-update; restart via watchdog)"
        return 0
    fi

    log_info "Starting HelixScreen (Snapmaker U1)..."

    local init_src="${INSTALL_DIR}/config/helixscreen.init"
    if [ ! -x "$init_src" ]; then
        chmod +x "$init_src" 2>/dev/null || true
    fi

    if [ ! -x "$init_src" ]; then
        log_error "Init script not found or not executable: $init_src"
        log_error "The release package may be incomplete."
        log_error "Recovery: re-run the installer to download a fresh copy:"
        log_error "  curl -fsSL https://releases.helixscreen.org/install.sh | bash"
        exit 1
    fi

    if ! $SUDO "$init_src" start; then
        log_error "Failed to start HelixScreen."
        log_error "Check logs: /var/log/helixscreen/launcher.log or ${INSTALL_DIR}/logs/launcher.log"
        exit 1
    fi

    # Wait for service to start (may be slow on embedded hardware)
    local i
    for i in 1 2 3 4 5; do
        sleep 1
        if pidof helix-screen >/dev/null 2>&1; then
            log_success "HelixScreen is running!"
            return
        fi
    done
    log_warn "Service may still be starting..."
    log_warn "Check logs: /var/log/helixscreen/launcher.log or ${INSTALL_DIR}/logs/launcher.log"
}

# Start service (systemd)
start_service_systemd() {
    log_info "Enabling and starting HelixScreen (systemd)..."

    # Under NoNewPrivileges, systemctl is blocked.  The restart is handled by
    # update_checker.cpp: it calls exit(0) after we return, which the watchdog
    # treats as "normal exit — restart silently".
    if _has_no_new_privs; then
        log_info "Skipping service start (NoNewPrivileges; restart via watchdog)"
        return 0
    fi

    if ! $SUDO systemctl enable "$SERVICE_NAME"; then
        log_error "Failed to enable ${SERVICE_NAME} service."
        exit 1
    fi

    if ! $SUDO systemctl start "$SERVICE_NAME"; then
        log_error "Failed to start ${SERVICE_NAME} service."
        log_error "Check logs with: journalctl -u ${SERVICE_NAME} -n 50"
        exit 1
    fi

    # Wait for service to start (may be slow on embedded hardware)
    local i
    for i in 1 2 3 4 5; do
        sleep 1
        if systemctl is-active --quiet "$SERVICE_NAME"; then
            log_success "HelixScreen is running!"
            return
        fi
    done
    log_warn "Service may still be starting..."
    log_warn "Check status with: systemctl status $SERVICE_NAME"
}

# Start service (SysV init)
start_service_sysv() {
    # During in-app self-update, the watchdog handles the restart via _exit(0).
    # Starting a second instance here would race with the still-running process.
    if _is_self_update; then
        log_info "Skipping service start (self-update; restart via watchdog)"
        return 0
    fi

    log_info "Starting HelixScreen (SysV init)..."

    if [ ! -x "$INIT_SCRIPT_DEST" ]; then
        log_error "Init script not executable: $INIT_SCRIPT_DEST"
        exit 1
    fi

    if ! $SUDO "$INIT_SCRIPT_DEST" start; then
        log_error "Failed to start HelixScreen."
        log_error "Check logs: /var/log/helixscreen/launcher.log or ${INSTALL_DIR}/logs/launcher.log"
        exit 1
    fi

    # Wait for service to start (may be slow on embedded hardware)
    local i
    for i in 1 2 3 4 5; do
        sleep 1
        if $SUDO "$INIT_SCRIPT_DEST" status >/dev/null 2>&1; then
            log_success "HelixScreen is running!"
            return
        fi
    done
    log_warn "Service may still be starting..."
    log_warn "Check: $INIT_SCRIPT_DEST status"
}

# Deploy platform-specific hook file
# Copies the correct hook file to $INSTALL_DIR/platform/hooks.sh so the
# init script can source it at runtime.
deploy_platform_hooks() {
    local install_dir="$1"
    local platform="$2"  # "ad5m-forgex", "ad5m-kmod", "pi", "k1"
    # Tarball ships platform hooks under assets/config/ as part of the
    # read-only seed bundle (see scripts/package.sh). Older installers looked
    # in config/platform/ — that path moved in the config/→assets/config/
    # refactor and the deploy_platform_hooks lookup got left behind,
    # silently dropping the hooks file for every sysv platform (#k2-no-hooks).
    local hooks_src="${install_dir}/assets/config/platform/hooks-${platform}.sh"

    if [ ! -f "$hooks_src" ]; then
        log_warn "No platform hooks for: $platform"
        return 0
    fi

    # Try without sudo first: during self-update INSTALL_DIR is pi-owned so no root
    # is needed.  Fall back to sudo for fresh installs where the directory may be
    # root-owned or not yet created.  Under NoNewPrivileges sudo is blocked, so
    # the sudo fallbacks must be silent and non-fatal.
    mkdir -p "${install_dir}/platform" 2>/dev/null || $SUDO mkdir -p "${install_dir}/platform" 2>/dev/null || true
    cp "$hooks_src" "${install_dir}/platform/hooks.sh" 2>/dev/null || $SUDO cp "$hooks_src" "${install_dir}/platform/hooks.sh" 2>/dev/null || true
    chmod +x "${install_dir}/platform/hooks.sh" 2>/dev/null || $SUDO chmod +x "${install_dir}/platform/hooks.sh" 2>/dev/null || true
    log_info "Deployed platform hooks: $platform"
}

# Fix ownership of install directory for non-root service users.
# The entire INSTALL_DIR must be user-owned so that in-app self-updates
# (which run under NoNewPrivileges=true, blocking sudo) can replace
# files without root access.  ProtectSystem=strict in the service file
# limits filesystem writes to ReadWritePaths regardless of ownership.
# Uses -h to avoid following symlinks outside INSTALL_DIR.
fix_install_ownership() {
    local user="${KLIPPER_USER:-}"
    local group="${KLIPPER_GROUP:-$user}"
    if [ -n "$user" ] && [ "$user" != "root" ] && [ -d "$INSTALL_DIR" ]; then
        log_info "Setting ownership to ${user}:${group}..."
        # Try without sudo first: during self-update under NoNewPrivileges,
        # sudo is blocked but files are already user-owned so chown succeeds
        # without it (or is a no-op).  Fall back to sudo for fresh installs
        # where root may own the directory.
        chown -Rh "${user}:${group}" "${INSTALL_DIR}" 2>/dev/null || \
            $SUDO chown -Rh "${user}:${group}" "${INSTALL_DIR}" 2>/dev/null || true
    fi
}

# Stop service for update
stop_service() {
    local platform=${1:-}

    if [ "$platform" = "snapmaker-u1" ]; then
        stop_service_snapmaker_u1
        return
    fi

    if [ "$INIT_SYSTEM" = "systemd" ]; then
        # Under NoNewPrivileges (self-update), sudo is blocked.  The service will be
        # restarted by the watchdog after exit(0) — stopping it here isn't needed.
        if _has_no_new_privs; then
            log_info "Skipping service stop (NoNewPrivileges; restart via watchdog)"
        elif systemctl is-active --quiet "$SERVICE_NAME" 2>/dev/null; then
            log_info "Stopping existing HelixScreen service (systemd)..."
            $SUDO systemctl stop "$SERVICE_NAME" || true
        fi
    else
        # During in-app self-update, the app must stay running so the user sees
        # the update progress screen.  The watchdog restarts via _exit(0) after
        # install.sh exits — killing the process here would black-screen the display.
        if _is_self_update; then
            log_info "Skipping service stop (self-update; restart via watchdog)"
        else
            # Try the configured init script location first
            if [ -n "$INIT_SCRIPT_DEST" ] && [ -x "$INIT_SCRIPT_DEST" ]; then
                log_info "Stopping existing HelixScreen service (SysV)..."
                $SUDO "$INIT_SCRIPT_DEST" stop 2>/dev/null || true
            fi
            # Also check all possible locations (for updates/uninstalls)
            for init_script in $HELIX_INIT_SCRIPTS; do
                if [ -x "$init_script" ]; then
                    log_info "Stopping HelixScreen at $init_script..."
                    $SUDO "$init_script" stop 2>/dev/null || true
                fi
            done
            # Also try to kill by name (watchdog first to prevent crash dialog flash)
            # shellcheck disable=SC2086
            kill_process_by_name $HELIX_PROCESSES || true
        fi
    fi
}

# Stop service (Snapmaker U1)
stop_service_snapmaker_u1() {
    if _is_self_update; then
        log_info "Skipping service stop (self-update; restart via watchdog)"
        return
    fi

    local init_src="${INSTALL_DIR}/config/helixscreen.init"
    if [ -x "$init_src" ]; then
        log_info "Stopping existing HelixScreen service (Snapmaker U1)..."
        $SUDO "$init_src" stop 2>/dev/null || true
    fi
    # Also kill by name in case init script stop didn't clean up
    # shellcheck disable=SC2086
    kill_process_by_name $HELIX_PROCESSES || true
}

# ============================================
# Module: audio.sh
# ============================================

#
# "snd_pcm_dmix_open: unable to open slave" and UI sound is dead.
#
# Fix: write /etc/asound.conf remapping "default" onto the detected output. This
# is the standard ALSA mechanism and fixes everything that opens "default" —
# HelixScreen, aplay, speaker-test — not just our app. We never touch the user's
# helixscreen.env (that file is reserved for user/runtime overrides), and we never
# clobber an existing /etc/asound.conf.
#
# When more than one HDMI codec is present we pick the one whose sink is actually
# connected, read from the codec's ELD (monitor_present / eld_valid in
# /proc/asound/cardN/eld*), so a screen on the second HDMI port is selected over
# an idle first port automatically.
#
# Reads: ASOUND_PROC_DIR (default /proc/asound), ASOUND_CONF (default
#        /etc/asound.conf), SUDO
# Writes: ASOUND_CONF (only when absent and a remap is needed)

# Source guard

# Injectable for tests; default to the real kernel/system paths.
ASOUND_PROC_DIR="${ASOUND_PROC_DIR:-/proc/asound}"
ASOUND_CONF="${ASOUND_CONF:-/etc/asound.conf}"

# Does an HDMI codec report a connected sink with valid audio?
# $1 = card directory under ASOUND_PROC_DIR. Returns 0 if connected.
_alsa_card_sink_connected() {
    _card_dir="$1"
    for _eld in "$_card_dir"/eld*; do
        [ -f "$_eld" ] || continue
        if grep -Eq 'monitor_present[[:space:]]+1([[:space:]]|$)' "$_eld" 2>/dev/null \
            && grep -Eq 'eld_valid[[:space:]]+1([[:space:]]|$)' "$_eld" 2>/dev/null; then
            return 0
        fi
    done
    return 1
}

# Echo the ALSA card id (e.g. "vc4hdmi1") that "default" should map to, or
# nothing if no remap is needed/possible. Pure read of ASOUND_PROC_DIR — the
# unit-testable core.
#
# Returns empty (no action) when: ALSA is absent, a card 0 already exists (stock
# "default" works), or no playback-capable card is found. Otherwise prefers a
# card with a connected HDMI sink, falling back to the lowest-indexed playback
# card.
alsa_pick_default_card() {
    [ -d "$ASOUND_PROC_DIR" ] || return 0
    # Card 0 present → stock "default" (hw:0) is fine, leave it alone.
    [ -d "$ASOUND_PROC_DIR/card0" ] && return 0

    _fallback=""
    _chosen=""
    for _d in "$ASOUND_PROC_DIR"/card[0-9]*; do
        [ -d "$_d" ] || continue

        # Must expose a playback PCM (pcm*p).
        _has_play=""
        for _p in "$_d"/pcm*p; do
            [ -e "$_p" ] && { _has_play=1; break; }
        done
        [ -n "$_has_play" ] || continue

        _id=$(cat "$_d/id" 2>/dev/null) || _id=""
        [ -n "$_id" ] || continue

        [ -z "$_fallback" ] && _fallback="$_id"

        if _alsa_card_sink_connected "$_d"; then
            _chosen="$_id"
            break
        fi
    done

    [ -z "$_chosen" ] && _chosen="$_fallback"
    [ -n "$_chosen" ] && printf '%s\n' "$_chosen"
    return 0
}

# Emit the /etc/asound.conf body that routes "default" to card id $1.
# Pure (stdout only) so tests can assert the content.
alsa_asound_conf_body() {
    _card="$1"
    cat <<EOF
# Auto-generated by the HelixScreen installer.
#
# This board has no ALSA card 0, so the stock "default" device (hw:0) cannot be
# opened. Route "default" to the detected output ("$_card") so UI sounds — and
# anything else that opens "default" (aplay, speaker-test) — work.
#
# Delete this file to restore ALSA's stock behavior. The installer will not
# recreate it if you remove it or hand-edit it.
pcm.!default {
    type plug
    slave.pcm {
        type hw
        card "$_card"
        device 0
    }
}
ctl.!default {
    type hw
    card "$_card"
}
EOF
}

# Top-level install step: configure ALSA "default" if needed. Safe no-op on
# boards where "default" already works, where ALSA is absent, or where the user
# already owns /etc/asound.conf.
configure_alsa_default() {
    if [ -e "$ASOUND_CONF" ]; then
        log_info "ALSA: $ASOUND_CONF already exists — leaving audio config untouched"
        return 0
    fi

    _card=$(alsa_pick_default_card)
    if [ -z "$_card" ]; then
        # Either card 0 exists (default works), no ALSA, or no usable output.
        return 0
    fi

    log_info "ALSA: no card 0; routing \"default\" → card \"$_card\" via $ASOUND_CONF"
    if alsa_asound_conf_body "$_card" | $SUDO tee "$ASOUND_CONF" >/dev/null 2>&1; then
        log_info "ALSA: wrote $ASOUND_CONF (UI sound enabled for HDMI-audio screens)"
    else
        log_warn "ALSA: failed to write $ASOUND_CONF — UI sound may be unavailable"
    fi
    return 0
}

# ============================================
# Module: moonraker.sh
# ============================================

#
# Common moonraker.conf locations
# ZMOD-on-AD5X notes:
#   /opt/config is a symlink to /usr/data/config; printer_data lives under both.
#   We list both forms so symlink-aware and -unaware path resolutions both hit.
MOONRAKER_CONF_PATHS="
/home/pi/printer_data/config/moonraker.conf
/home/biqu/printer_data/config/moonraker.conf
/home/mks/printer_data/config/moonraker.conf
/root/printer_data/config/moonraker.conf
/opt/config/printer_data/config/moonraker.conf
/opt/config/moonraker.conf
/usr/data/config/printer_data/config/moonraker.conf
/usr/data/printer_data/config/moonraker.conf
"

# Find moonraker.conf
# Returns: path to moonraker.conf or empty string
find_moonraker_conf() {
    # Dynamic: check detected user's home first
    if [ -n "${KLIPPER_HOME:-}" ]; then
        local user_conf="${KLIPPER_HOME}/printer_data/config/moonraker.conf"
        if [ -f "$user_conf" ]; then
            echo "$user_conf"
            return 0
        fi
    fi

    # Static fallback
    for conf in $MOONRAKER_CONF_PATHS; do
        if [ -f "$conf" ]; then
            echo "$conf"
            return 0
        fi
    done
    echo ""
}

# Check if update_manager section for helixscreen already exists
# Args: $1 = moonraker.conf path
# Returns: 0 if exists, 1 if not
has_update_manager_section() {
    local conf="$1"
    grep -q '^\[update_manager helixscreen\]' "$conf" 2>/dev/null
}

# Generate update_manager configuration block
generate_update_manager_config() {
    cat << EOF

# HelixScreen Update Manager
# Added by HelixScreen installer - enables one-click updates from Mainsail/Fluidd
# NOTE: type: web is used instead of type: zip as a workaround for
# mainsail-crew/mainsail#2444 (zip type always shows UP-TO-DATE).
# A systemd path unit handles service restart after Moonraker extracts the update.
[update_manager helixscreen]
type: web
channel: stable
repo: prestonbrown/helixscreen
path: ${INSTALL_DIR}
EOF
}

# Add update_manager section to moonraker.conf
# Args: $1 = moonraker.conf path
add_update_manager_section() {
    local conf="$1"
    local fs
    fs=$(file_sudo "$conf")

    # Create backup
    $fs cp "$conf" "${conf}.bak.helixscreen" 2>/dev/null || true

    # Append configuration
    generate_update_manager_config | $fs tee -a "$conf" >/dev/null

    log_success "Added update_manager section to $conf"
    log_info "You can now update HelixScreen from the Mainsail/Fluidd web interface!"
}

# Check if moonraker.conf has old git_repo-style helixscreen section
# Args: $1 = moonraker.conf path
# Returns: 0 if old git_repo section found, 1 if not
has_old_git_repo_section() {
    local conf="$1"
    # Look for helixscreen section with type: git_repo
    if grep -q '^\[update_manager helixscreen\]' "$conf" 2>/dev/null; then
        # Extract the section and check for git_repo type
        awk '/^\[update_manager helixscreen\]/{found=1; next} found && /^\[/{exit} found && /^type:/{print; exit}' "$conf" | grep -q 'git_repo'
        return $?
    fi
    return 1
}

# Check if moonraker.conf has old zip-style helixscreen section
# Args: $1 = moonraker.conf path
# Returns: 0 if old zip section found, 1 if not
has_old_zip_section() {
    local conf="$1"
    if grep -q '^\[update_manager helixscreen\]' "$conf" 2>/dev/null; then
        awk '/^\[update_manager helixscreen\]/{found=1; next} found && /^\[/{exit} found && /^type:/{print; exit}' "$conf" | grep -q 'zip'
        return $?
    fi
    return 1
}

# Migrate old section (git_repo or zip) to type: web
# Args: $1 = moonraker.conf path
migrate_to_web_type() {
    local conf="$1"

    log_info "Migrating update_manager to type: web..."

    # Remove old section
    remove_update_manager_section "$conf" 2>/dev/null || true

    # Add new web section
    add_update_manager_section "$conf"

    # Clean up old sparse clone directory if it exists (from git_repo era)
    local old_repo_dir="${INSTALL_DIR}-repo"
    if [ -d "$old_repo_dir" ]; then
        log_info "Removing old updater repo at $old_repo_dir..."
        $SUDO rm -rf "$old_repo_dir"
    fi

    log_success "Migrated to type: web update manager"
}

# Remove unsupported options from the helixscreen update_manager section.
# type: web only supports: type, channel, repo, path.
# Options like persistent_files, managed_services, and install_script are
# not supported and cause Moonraker to log "unparsed config option" warnings.
# Args: $1 = moonraker.conf path
cleanup_unsupported_options() {
    local conf="$1"

    # Check if any unsupported options exist in the helixscreen section.
    # persistent_files has indented continuation lines; the others are single-line.
    if ! awk '
        /^\[update_manager helixscreen\]/{found=1; next}
        found && /^\[/{exit}
        found && /^(persistent_files|managed_services|install_script):/{print; exit}
    ' "$conf" | grep -q .; then
        return 0
    fi

    log_info "Removing unsupported options from [update_manager helixscreen]"
    local fs
    fs=$(file_sudo "$conf")
    $fs cp "$conf" "${conf}.bak.helixscreen" 2>/dev/null || true

    # Remove matching key: lines within the helixscreen section.
    # persistent_files also has indented continuation lines (4-space indent).
    $fs awk '
        /^\[update_manager helixscreen\]/ { in_section=1 }
        in_section && /^\[/ && !/^\[update_manager helixscreen\]/ { in_section=0 }
        in_section && /^(persistent_files|managed_services|install_script):/ { skip_block=1; next }
        skip_block && /^    / { next }
        skip_block { skip_block=0 }
        { print }
    ' "$conf" > "${conf}.tmp" && $fs mv "${conf}.tmp" "$conf"

    log_success "Cleaned up unsupported options from moonraker.conf"
}

# Write release_info.json if not already present
# Moonraker type:web needs this file to detect installed version
write_release_info() {
    local release_info="${INSTALL_DIR}/release_info.json"

    if [ -f "$release_info" ]; then
        return 0
    fi

    # Try to detect version from binary
    local version=""
    if [ -x "${INSTALL_DIR}/bin/helix-screen" ]; then
        version=$("${INSTALL_DIR}/bin/helix-screen" --version 2>/dev/null | head -n 1 | grep -oE 'v[0-9]+\.[0-9]+\.[0-9]+[^ ]*' || echo "")
    fi

    if [ -z "$version" ]; then
        log_warn "Could not detect version for release_info.json"
        return 0
    fi

    # Resolve the platform-specific asset name through the single source of
    # truth in platform.sh (shared with mk/cross.mk's baked release_info.json,
    # so the two never drift). A wrong/missing asset_name makes Moonraker fall
    # back to the alphabetically-first release asset — a .sym debug file — and
    # die with "File is not a zip file" (prestonbrown/helixscreen#993).
    local asset_name
    asset_name="$(helix_self_update_asset "${PLATFORM:-pi}")"

    log_info "Writing release_info.json (${version})..."
    cat > "${release_info}.tmp" << EOF
{"project_name":"helixscreen","project_owner":"prestonbrown","version":"${version}","asset_name":"${asset_name}"}
EOF
    # Try without sudo first (self-update: INSTALL_DIR is user-owned under NoNewPrivileges).
    # Fall back to sudo for fresh installs where the directory may be root-owned.
    mv "${release_info}.tmp" "$release_info" 2>/dev/null || \
        $SUDO mv "${release_info}.tmp" "$release_info" 2>/dev/null || true
}

# Ensure helixscreen is in moonraker.asvc (service allowlist)
# Moonraker requires services to be listed here before it can manage them.
# The asvc file lives in printer_data/, one level up from config/moonraker.conf.
# Args: $1 = moonraker.conf path (used to derive printer_data path)
ensure_moonraker_asvc() {
    local conf="$1"
    # printer_data is two levels up from config/moonraker.conf
    local printer_data
    printer_data="$(dirname "$(dirname "$conf")")"
    local asvc="${printer_data}/moonraker.asvc"

    if [ ! -f "$asvc" ]; then
        log_info "No moonraker.asvc found at $asvc, skipping"
        return 0
    fi

    if grep -q '^helixscreen$' "$asvc" 2>/dev/null; then
        return 0
    fi

    local fs
    fs=$(file_sudo "$asvc")
    log_info "Adding helixscreen to $asvc..."
    # Ensure file ends with a newline before appending (#408)
    if [ -s "$asvc" ] && [ "$(tail -c 1 "$asvc" | wc -l)" -eq 0 ]; then
        echo "" | $fs tee -a "$asvc" >/dev/null
    fi
    echo "helixscreen" | $fs tee -a "$asvc" >/dev/null
    log_success "Added helixscreen to Moonraker service allowlist"
}

# Restart Moonraker to pick up configuration changes
restart_moonraker() {
    if command -v systemctl >/dev/null 2>&1 && systemctl is-active --quiet moonraker 2>/dev/null; then
        log_info "Restarting Moonraker to apply configuration..."
        $SUDO systemctl restart moonraker || true
    elif [ -x "/etc/init.d/S56moonraker_service" ]; then
        # K1/Simple AF uses SysV init
        log_info "Restarting Moonraker to apply configuration..."
        if ! $SUDO /etc/init.d/S56moonraker_service restart 2>/dev/null; then
            log_warn "Could not restart Moonraker - you may need to restart it manually"
        fi
    fi
}

# Configure Moonraker update_manager
# Called during installation on platforms with web UI (Pi, K1 with Simple AF)
configure_moonraker_updates() {
    local platform=$1

    # Skip on AD5M (stock Flashforge firmware lacks Mainsail/Fluidd).
    # NOTE: AD5X is intentionally NOT skipped — it's only ever installed via the
    # ZMOD chroot, which ships Mainsail/Fluidd.
    if [ "$platform" = "ad5m" ]; then
        log_info "Skipping Moonraker update_manager on AD5M (typically no web UI)"
        return 0
    fi

    log_info "Configuring Moonraker update_manager..."

    # Write release_info.json if not already present (fallback for older tarballs)
    write_release_info

    local conf
    conf=$(find_moonraker_conf)

    if [ -z "$conf" ]; then
        log_warn "Could not find moonraker.conf in any known location:"
        if [ -n "${KLIPPER_HOME:-}" ]; then
            log_warn "  ${KLIPPER_HOME}/printer_data/config/moonraker.conf"
        fi
        for tried in $MOONRAKER_CONF_PATHS; do
            log_warn "  $tried"
        done
        log_warn "To enable web UI updates, manually add to your moonraker.conf:"
        echo ""
        generate_update_manager_config
        echo ""
        return 0
    fi

    log_info "Using moonraker.conf at: $conf"

    # Migrate old git_repo or zip config to type: web
    # (type: zip shows perpetual UP-TO-DATE in Mainsail — see mainsail-crew/mainsail#2444)
    if has_old_git_repo_section "$conf" || has_old_zip_section "$conf"; then
        migrate_to_web_type "$conf"
        ensure_moonraker_asvc "$conf"
        restart_moonraker
        return 0
    fi

    if has_update_manager_section "$conf"; then
        log_info "update_manager section already exists in $conf"
        # Remove options not supported by type: web (persistent_files,
        # managed_services, install_script) that cause Moonraker warnings.
        cleanup_unsupported_options "$conf"
        # Still ensure asvc is correct even if section already exists
        ensure_moonraker_asvc "$conf"
        return 0
    fi

    add_update_manager_section "$conf"
    ensure_moonraker_asvc "$conf"
    restart_moonraker
}

# Remove update_manager section from moonraker.conf
# Called during uninstallation
remove_update_manager_section() {
    local conf
    conf=$(find_moonraker_conf)

    if [ -z "$conf" ]; then
        return 0
    fi

    if ! has_update_manager_section "$conf"; then
        return 0
    fi

    log_info "Removing update_manager section from $conf..."

    # Create backup
    local fs
    fs=$(file_sudo "$conf")
    $fs cp "$conf" "${conf}.bak.helixscreen-uninstall" 2>/dev/null || true

    # Remove the section (from [update_manager helixscreen] to next section or EOF)
    # This uses awk to skip lines between [update_manager helixscreen] and the next [section]
    $fs sh -c "awk '
        /^\[update_manager helixscreen\]/ { skip=1; next }
        /^\[/ { skip=0 }
        !skip { print }
    ' \"$conf\" > \"${conf}.tmp\"" && $fs mv "${conf}.tmp" "$conf"

    # Also remove any "Added by HelixScreen" comment lines that precede it
    $fs sed -i '/# HelixScreen Update Manager/d' "$conf" 2>/dev/null || \
    $fs sed -i '' '/# HelixScreen Update Manager/d' "$conf" 2>/dev/null || true

    $fs sed -i '/# Added by HelixScreen installer/d' "$conf" 2>/dev/null || \
    $fs sed -i '' '/# Added by HelixScreen installer/d' "$conf" 2>/dev/null || true

    log_success "Removed update_manager section from $conf"
}

# ============================================
# Module: recovery.sh
# ============================================

#
#
# Step 2 is what this file installs. We can't use Moonraker's `[shell_command
# helix_recover]` config block — upstream Moonraker doesn't actually parse such
# sections (shell_command.py is a library used by machine/power/webcam, not a
# user-config consumer). The early v0.99.5x K2 snippet was silently dead code;
# remove_legacy_moonraker_block() strips it from already-installed K2 confs on
# next upgrade.
#
# Platforms that don't need this (stock Pi/RatOS, x86 dev) get nothing — the
# frontend's step 1 or 3 already covers them via systemd_dbus/systemd_cli.

# Re-source guard

# Per-platform `helix-recover.sh` body. Each function emits a stand-alone
# POSIX-sh script that, when invoked by helix-screen, fully restarts the
# platform's klippy + any host-side MCU daemons. Exit 0 = recovery launched
# successfully (the platform's own init script handles the rest). Non-zero =
# helix-screen surfaces a "Firmware restart failed" toast with stderr.

# Common header — used at the top of every emitted script.
_helix_recover_script_header() {
    cat <<'EOF'
#!/bin/sh
# HelixScreen deep-recovery (managed). See:
# https://github.com/prestonbrown/helixscreen/blob/main/scripts/lib/installer/recovery.sh
#
# Invoked by PrinterRecoveryService::run_local_recovery() when klippy_uds is
# unreachable and printer.firmware_restart can't proxy a recovery. Do not
# edit by hand — re-install HelixScreen to regenerate.
set -u
EOF
}

# Creality K2 series (K2 Plus / K2 Pro / K2 Max). Two host-side processes:
# klippy.py and klipper_mcu (rpi virtual MCU bridging the RS-485 to CFS).
# Bouncing klipper_mcu first clears the rpi-MCU-shutdown that traps
# FIRMWARE_RESTART after a CFS fault (key298).
helix_recover_script_k2() {
    _helix_recover_script_header
    cat <<'EOF'
/etc/init.d/klipper_mcu restart
sleep 2
exec /etc/init.d/klipper restart
EOF
}

# Snapmaker U1 (single-extruder, aarch64 Debian, BusyBox init). S60klipper
# bounces both klippy_mcu (/home/lava/firmware_MCU/klippy_mcu) and the python
# klippy host, and uses lava_io to power-cycle the MAIN_MCU and HEAD_MCU rails.
# Verified live 2026-05-13.
helix_recover_script_snapmaker_u1() {
    _helix_recover_script_header
    cat <<'EOF'
exec /etc/init.d/S60klipper restart
EOF
}

# Creality K1 / K1C / K1 Max (stock + Guilouz). Same klippy_mcu + klipper_service
# split as K2 but with the SXX prefixes that Creality's BusyBox init expects.
helix_recover_script_k1() {
    _helix_recover_script_header
    cat <<'EOF'
/etc/init.d/S57klipper_mcu restart
sleep 2
exec /etc/init.d/S55klipper_service restart
EOF
}

# Elegoo Centauri Carbon (COSMOS firmware, armv7l). Single klippy process,
# no host-side mcu daemon. Init script handles a 10s SIGKILL fallback itself.
helix_recover_script_cc1() {
    _helix_recover_script_header
    cat <<'EOF'
exec /etc/init.d/klipper restart
EOF
}

# FlashForge AD5M family (klipper_mod / ZMOD / ForgeX). Three community
# firmwares with different klipper-start mechanisms — probe at runtime since
# the script is generated once per install but the user can switch firmwares
# without re-running helix-screen's installer.
helix_recover_script_ad5m() {
    _helix_recover_script_header
    cat <<'EOF'
if [ -x /opt/config/mod/.shell/restart_klipper.sh ]; then
    exec /opt/config/mod/.shell/restart_klipper.sh
fi
if [ -x /etc/init.d/S55klipper_service ]; then
    exec /etc/init.d/S55klipper_service restart
fi
if [ -x /root/printer_software/klipper/scripts/klipper-restart.sh ]; then
    exec /root/printer_software/klipper/scripts/klipper-restart.sh
fi
echo "helix-recover: no known klipper restart mechanism on this AD5M firmware" >&2
exit 1
EOF
}

# Return the script body for the detected platform, or empty when this
# platform doesn't need a local helper (firmware_restart is sufficient).
helix_recover_script_for_platform() {
    local platform="$1"
    case "$platform" in
        k2)           helix_recover_script_k2 ;;
        k1)           helix_recover_script_k1 ;;
        cc1)          helix_recover_script_cc1 ;;
        ad5m|ad5x)    helix_recover_script_ad5m ;;
        snapmaker-u1) helix_recover_script_snapmaker_u1 ;;
        # pi / pi32 / x86: stock systemd Klipper — `machine.services.restart`
        # works because moonraker.conf has `provider: systemd_*`. Frontend
        # never reaches the local-recovery branch.
        *) : ;;
    esac
}

# Write $install_dir/bin/helix-recover.sh for the platform. Idempotent: a
# re-run with the same platform produces byte-identical output and overwrites
# the existing file (so a recovery.sh edit on the dev side propagates on the
# next upgrade).
install_recovery_script() {
    local install_dir="$1"
    local platform="$2"
    local fs="${3:-}"   # `sudo` prefix if needed, "" otherwise — match moonraker.sh idiom

    [ -z "$install_dir" ] && return 1
    [ -z "$platform" ] && return 1

    local body
    body=$(helix_recover_script_for_platform "$platform")
    if [ -z "$body" ]; then
        log_info "No local recovery script needed for platform: $platform"
        return 0
    fi

    local script="$install_dir/bin/helix-recover.sh"
    $fs mkdir -p "$install_dir/bin"
    printf '%s\n' "$body" | $fs tee "$script" >/dev/null
    $fs chmod +x "$script"
    log_success "Installed helix-recover.sh for $platform → $script"
}

# Remove the local recovery script on uninstall. No-op when absent.
remove_recovery_script() {
    local install_dir="$1"
    local fs="${2:-}"
    local script="$install_dir/bin/helix-recover.sh"
    [ -f "$script" ] || return 0
    $fs rm -f "$script"
    log_success "Removed $script"
}

# Strip the legacy [shell_command helix_recover] block from moonraker.conf.
# Early v0.99.5x K2 installs got this block; it was always silently dead since
# Moonraker upstream doesn't parse [shell_command name] sections. Sweeping it
# on every install keeps existing K2 confs clean as users upgrade.
remove_legacy_moonraker_block() {
    local conf="$1"
    local fs="${2:-}"
    [ -f "$conf" ] || return 0
    grep -q '^\[shell_command helix_recover\]' "$conf" 2>/dev/null || return 0

    log_info "Removing legacy [shell_command helix_recover] from $conf (dead block)"
    local tmp
    tmp=$(mktemp)
    awk '
        /^\[shell_command helix_recover\]/ { skip=1; next }
        skip && /^\[/ { skip=0 }
        !skip { print }
    ' "$conf" > "$tmp"
    $fs cp "$tmp" "$conf"
    rm -f "$tmp"
}

# High-level installer entry point — drop-in companion to
# configure_moonraker_updates() in moonraker.sh. Call from main install flow
# AFTER install_files (so $INSTALL_DIR/bin/ exists) and AFTER
# configure_moonraker_updates (so moonraker.conf exists for the legacy sweep).
#
# Reads: INSTALL_DIR, SUDO. Calls find_moonraker_conf() / file_sudo().
configure_local_recovery() {
    local platform="$1"

    local body
    body=$(helix_recover_script_for_platform "$platform")
    if [ -z "$body" ]; then
        # Stock systemd platform (pi/pi32/x86). Still sweep the legacy block
        # in case the user switched platforms post-install — cheap, idempotent.
        :
    else
        log_info "Configuring local recovery script..."
        install_recovery_script "${INSTALL_DIR}" "$platform" "${SUDO:-}"
    fi

    # Migration sweep: strip the dead [shell_command helix_recover] block from
    # any existing moonraker.conf. Runs on every platform so K2 users upgrading
    # past v0.99.61 lose the stale block on the next install pass.
    local conf
    conf=$(find_moonraker_conf 2>/dev/null)
    if [ -n "$conf" ]; then
        local fs
        fs=$(file_sudo "$conf")
        remove_legacy_moonraker_block "$conf" "$fs"
    fi
}

# Backward-compat shim — main.sh historically called this name. Keep it
# until the next bundle so callers that pulled an older install.sh keep
# working through the upgrade.
configure_moonraker_recovery() {
    configure_local_recovery "$@"
}

# ============================================
# Module: kiauh.sh
# ============================================

#
# Detect KIAUH extensions directory
# Returns the path to the extensions dir, or empty string if not found
detect_kiauh_dir() {
    # Check current user's home first (most common)
    if [ -d "$HOME/kiauh/kiauh/extensions" ]; then
        echo "$HOME/kiauh/kiauh/extensions"
        return 0
    fi

    # Scan /home/*/kiauh/kiauh/extensions/ for other users
    if [ -d "/home" ]; then
        for user_home in /home/*/kiauh/kiauh/extensions; do
            if [ -d "$user_home" ]; then
                echo "$user_home"
                return 0
            fi
        done
    fi

    # Not found
    echo ""
    return 0
}

# Install KIAUH extension for HelixScreen
# Args: $1 = skip flag ("true" to skip, anything else to install)
#
# Default behavior: if KIAUH is detected, install the extension automatically.
# Pass --skip-kiauh-registration to opt out. KIAUH itself sets this flag when
# it invokes install.sh from its own extension wrapper, since the extension
# files are already in place at that point.
install_kiauh_extension() {
    local skip="${1:-false}"
    local kiauh_ext_dir
    local src_dir="$INSTALL_DIR/scripts/kiauh/helixscreen"

    kiauh_ext_dir=$(detect_kiauh_dir)

    # No KIAUH installed — nothing to do
    if [ -z "$kiauh_ext_dir" ]; then
        return 0
    fi

    if [ "$skip" = "true" ]; then
        log_info "KIAUH detected at $kiauh_ext_dir — skipping extension (--skip-kiauh-registration)"
        return 0
    fi

    local target_dir="$kiauh_ext_dir/helixscreen"
    local is_update=false

    if [ -d "$target_dir" ]; then
        is_update=true
    fi

    # Check source files exist
    if [ ! -f "$src_dir/__init__.py" ] || [ ! -f "$src_dir/helixscreen_extension.py" ] || [ ! -f "$src_dir/metadata.json" ]; then
        log_warn "KIAUH extension source files not found at $src_dir"
        log_warn "  Release tarball is missing scripts/kiauh/. To register manually:"
        log_warn "    mkdir -p ~/kiauh/kiauh/extensions/helixscreen"
        log_warn "    cd ~/kiauh/kiauh/extensions/helixscreen"
        log_warn "    for f in __init__.py helixscreen_extension.py metadata.json; do"
        log_warn "      curl -sLO https://raw.githubusercontent.com/prestonbrown/helixscreen/main/scripts/kiauh/helixscreen/\$f"
        log_warn "    done"
        return 0
    fi

    # Already-installed-and-identical: don't touch a working tree
    if [ "$is_update" = true ] \
        && [ -f "$target_dir/__init__.py" ] \
        && [ -f "$target_dir/helixscreen_extension.py" ] \
        && [ -f "$target_dir/metadata.json" ] \
        && cmp -s "$src_dir/__init__.py" "$target_dir/__init__.py" \
        && cmp -s "$src_dir/helixscreen_extension.py" "$target_dir/helixscreen_extension.py" \
        && cmp -s "$src_dir/metadata.json" "$target_dir/metadata.json"; then
        log_info "KIAUH extension already up to date at $target_dir"
        return 0
    fi

    # Copy extension files
    mkdir -p "$target_dir"
    cp "$src_dir/__init__.py" "$target_dir/"
    cp "$src_dir/helixscreen_extension.py" "$target_dir/"
    cp "$src_dir/metadata.json" "$target_dir/"

    if [ "$is_update" = true ]; then
        log_success "KIAUH extension updated at $target_dir (restart KIAUH to pick it up)"
    else
        log_success "KIAUH extension installed at $target_dir"
        log_info "  → Restart KIAUH (~/kiauh/kiauh.sh) and open the Extensions menu to use it"
    fi
}

# ============================================
# Module: uninstall.sh
# ============================================

#
# Sentinel paths checked by helixscreen-update.service so it refuses to fire
# while an uninstall is in progress (closes a race where the update path unit
# could trigger a restart between stop_service and rm -rf $INSTALL_DIR).
# Two locations cover both systemd-with-StateDirectory and the bare fallback;
# both live outside $INSTALL_DIR so they survive its removal.  Both are swept
# by clean_helix_state_dirs at the end of uninstall and by the EXIT/INT/TERM
# trap if an uninstall aborts before reaching the sweep (otherwise a stuck
# sentinel silently blocks every future update.service firing).
#
# Honors $HELIX_STATE_VAR_LIB so this stays consistent with the env-override
# the BATS suite uses to redirect clean_helix_state_dirs away from real
# /var/lib.  Production callers leave it unset; the systemd unit hardcodes
# /var/lib/helixscreen/.uninstalling because @@HELIX_STATE_VAR_LIB@@ isn't a
# template var.
_uninstalling_sentinel_paths() {
    echo "${HELIX_STATE_VAR_LIB:-/var/lib/helixscreen}/.uninstalling"
    if [ -n "${INSTALL_DIR:-}" ]; then
        local _parent
        _parent=$(dirname "$INSTALL_DIR" 2>/dev/null || true)
        case "$_parent" in
            /|.|"") : ;;
            *) echo "${_parent}/.helixscreen/.uninstalling" ;;
        esac
    fi
}

_drop_uninstalling_sentinel() {
    local _p _dir
    _uninstalling_sentinel_paths | while IFS= read -r _p; do
        [ -z "$_p" ] && continue
        _dir=$(dirname "$_p")
        $SUDO mkdir -p "$_dir" 2>/dev/null || true
        $SUDO touch "$_p" 2>/dev/null || true
    done
}

# Sweep sentinel files.  Wired to EXIT/INT/TERM in uninstall() so an aborted
# run doesn't leave a stuck sentinel blocking helixscreen-update.service.
# On a successful uninstall this is a no-op — clean_helix_state_dirs already
# removed them — but the trap fires either way.
_sweep_uninstalling_sentinel() {
    local _p
    _uninstalling_sentinel_paths 2>/dev/null | while IFS= read -r _p; do
        [ -z "$_p" ] && continue
        $SUDO rm -f "$_p" 2>/dev/null || true
    done
}

# Re-enable services that were disabled during installation
# Reads the state file and reverses each recorded disable action
reenable_disabled_services() {
    local state_file="${INSTALL_DIR}/config/.disabled_services"
    [ -f "$state_file" ] || return 0

    log_info "Re-enabling previously disabled services..."
    while IFS= read -r entry; do
        # Skip empty lines and comments
        case "$entry" in ""|\#*) continue ;; esac

        local type="${entry%%:*}"
        local target="${entry#*:}"

        case "$type" in
            systemd)
                log_info "Re-enabling systemd service: $target"
                $SUDO systemctl enable "$target" 2>/dev/null || true
                ;;
            sysv-chmod)
                if [ -f "$target" ]; then
                    log_info "Re-enabling init script: $target"
                    $SUDO chmod +x "$target" 2>/dev/null || true
                fi
                ;;
        esac
    done < "$state_file"
}

# Undo per-printer Klipper includes recorded at install time (#986).
# Reverses each entry in ${INSTALL_DIR}/config/.klipper_includes:
#   cfg:<path>                      → remove the copied snippet
#   include:<printer.cfg>:<relpath> → strip the [include <relpath>] line (and
#                                     the installer's marker comment above it)
# Must run BEFORE $INSTALL_DIR is removed (the state file lives in it) and
# touches printer_data files that live outside $INSTALL_DIR.
undo_klipper_includes() {
    local state_file="${INSTALL_DIR}/config/.klipper_includes"
    [ -f "$state_file" ] || return 0

    log_info "Reverting HelixScreen Klipper config includes..."
    while IFS= read -r entry; do
        case "$entry" in ""|\#*) continue ;; esac

        local type="${entry%%:*}"
        local rest="${entry#*:}"

        case "$type" in
            cfg)
                if [ -f "$rest" ]; then
                    log_info "Removing Klipper snippet: $rest"
                    $(file_sudo "$rest") rm -f "$rest" 2>/dev/null || true
                fi
                ;;
            include)
                # rest = "<printer.cfg path>:<relpath>"
                local pcfg="${rest%%:*}"
                local relpath="${rest#*:}"
                if [ -f "$pcfg" ]; then
                    log_info "Removing [include $relpath] from $pcfg"
                    local include_line="[include ${relpath}]"
                    local marker="# Added by HelixScreen installer (#986) -- ${relpath}"
                    local tmp="${pcfg}.helix-uninstall.$$"
                    # Drop the marker comment line and the include line. Anchored
                    # full-line matches via awk for portability (no sed -i).
                    if awk -v inc="$include_line" -v mark="$marker" \
                        '$0 == inc { next } $0 == mark { next } { print }' \
                        "$pcfg" > "$tmp" 2>/dev/null; then
                        $(file_sudo "$pcfg") mv "$tmp" "$pcfg" 2>/dev/null \
                            || rm -f "$tmp" 2>/dev/null || true
                    else
                        rm -f "$tmp" 2>/dev/null || true
                    fi
                fi
                ;;
        esac
    done < "$state_file"
}

# Undo per-printer settings seeding recorded at install time (#986).
# Reads ${INSTALL_DIR}/config/.seeded_settings (written by
# _record_seeded_settings() in printer_seed.sh as "settings:<printer_id>" lines)
# and logs which printer's defaults were seeded. We deliberately do NOT attempt
# to un-merge those values out of settings.json: the seed was deep-merged into
# whatever the user already had, so seeded keys can't be safely separated from
# the user's own choices (the user may have since edited them, too). The seeded
# defaults therefore REMAIN in settings.json; we only remove the marker file.
# Must run BEFORE $INSTALL_DIR is removed (the state file lives in it).
undo_seeded_settings() {
    local state_file="${INSTALL_DIR}/config/.seeded_settings"
    [ -f "$state_file" ] || return 0

    log_info "Reviewing HelixScreen settings seeds..."
    while IFS= read -r entry; do
        case "$entry" in ""|\#*) continue ;; esac

        local type="${entry%%:*}"
        local printer_id="${entry#*:}"

        case "$type" in
            settings)
                log_info "Seeded defaults for ${printer_id} remain in settings.json (not un-merged: seeded and user values can't be safely separated)"
                ;;
        esac
    done < "$state_file"

    # Remove only the marker; settings.json is left untouched on purpose.
    $(file_sudo "$state_file") rm -f "$state_file" 2>/dev/null || true
}

# Uninstall HelixScreen
# Args: platform (optional)
uninstall() {
    local platform=${1:-}

    log_info "Uninstalling HelixScreen..."

    # Drop sentinel BEFORE any destructive work.  helixscreen-update.service
    # checks for it and refuses to fire while uninstall is running, closing
    # the race where Moonraker's path unit could re-trigger a restart between
    # stop_service and rm -rf.  Swept at the end by clean_helix_state_dirs;
    # the trap covers the abort case so a stuck sentinel can't silently block
    # future update.service firings.
    trap '_sweep_uninstalling_sentinel' EXIT INT TERM
    _drop_uninstalling_sentinel

    # Remove the [update_manager helixscreen] section FIRST, before any files
    # disappear.  If Moonraker auto-refreshes (or someone clicks "Update" in
    # Mainsail mid-uninstall), having the section gone before we start
    # dismantling files prevents a re-extract from racing us.  Moonraker's
    # in-memory updater object survives until Moonraker is reloaded, but
    # type:web only extracts on explicit user trigger so the on-disk edit is
    # the effective fix; no moonraker restart needed.
    if type remove_update_manager_section >/dev/null 2>&1; then
        remove_update_manager_section || true
    fi

    # Detect init system first
    detect_init_system

    if [ "$INIT_SYSTEM" = "systemd" ]; then
        # Stop and disable systemd service
        $SUDO systemctl stop "$SERVICE_NAME" 2>/dev/null || true
        $SUDO systemctl disable "$SERVICE_NAME" 2>/dev/null || true
        $SUDO rm -f "/etc/systemd/system/${SERVICE_NAME}.service"
        # Remove update watcher units (mainsail#2444 workaround)
        $SUDO systemctl stop helixscreen-update.path 2>/dev/null || true
        $SUDO systemctl disable helixscreen-update.path 2>/dev/null || true
        $SUDO rm -f /etc/systemd/system/helixscreen-update.path
        $SUDO rm -f /etc/systemd/system/helixscreen-update.service
        # Remove permission rules (udev, polkit)
        $SUDO rm -f /etc/udev/rules.d/99-helixscreen-backlight.rules
        $SUDO rm -f /etc/polkit-1/localauthority/50-local.d/helixscreen-network.pkla
        $SUDO rm -f /etc/polkit-1/rules.d/49-helixscreen-network.rules
        $SUDO rm -f /etc/polkit-1/rules.d/50-helixscreen-network.rules
        $SUDO systemctl daemon-reload
    else
        # Stop and remove SysV init scripts (check all possible locations)
        local removed_procd_shim=false
        for init_script in $HELIX_INIT_SCRIPTS; do
            if [ -f "$init_script" ]; then
                log_info "Stopping and removing $init_script..."
                $SUDO "$init_script" stop 2>/dev/null || true
                # K2 procd shim: only call disable if this is actually a
                # rc.common-style script. CC1 installs a plain SysV script
                # at the same /etc/init.d/helixscreen path, and CC1's BusyBox
                # rejects `head -1` (only supports `head -n 1`), so we use
                # awk for the shebang check (portable across all BusyBox
                # variants we ship to). Also CC1 has no /etc/rc.common, so
                # the first guard short-circuits anyway.
                if [ "$init_script" = "/etc/init.d/helixscreen" ] && \
                   [ -x /etc/rc.common ] && \
                   awk 'NR==1 {exit !/\/etc\/rc\.common/}' "$init_script" 2>/dev/null; then
                    $SUDO "$init_script" disable 2>/dev/null || true
                    removed_procd_shim=true
                fi
                $SUDO rm -f "$init_script"
            fi
        done
        # Belt-and-suspenders cleanup of rc.d symlinks, but only if we actually
        # removed a procd shim (avoid touching /etc/rc.d on platforms that
        # don't use the procd boot iterator).
        if [ "$removed_procd_shim" = "true" ]; then
            $SUDO rm -f /etc/rc.d/S99helixscreen /etc/rc.d/K01helixscreen 2>/dev/null || true
        fi
    fi

    # Kill any remaining processes (watchdog first to prevent crash dialog flash)
    # shellcheck disable=SC2086
    kill_process_by_name $HELIX_PROCESSES || true

    # Clean up PID files and log file
    $SUDO rm -f /var/run/helixscreen.pid 2>/dev/null || true
    $SUDO rm -f /var/run/helix-splash.pid 2>/dev/null || true
    rm -f /tmp/helixscreen.log 2>/dev/null || true

    # Re-enable services from state file (before removing install dir)
    reenable_disabled_services

    # Revert per-printer Klipper includes (#986) — strip the [include] line from
    # printer.cfg and remove the copied snippet. Must run before $INSTALL_DIR
    # (which holds the .klipper_includes state file) is removed.
    undo_klipper_includes

    # Acknowledge per-printer settings seeding (#986) — log which defaults were
    # seeded (they remain in settings.json by design) and remove the marker.
    # Must run before $INSTALL_DIR (which holds the .seeded_settings state file)
    # is removed.
    undo_seeded_settings

    # Remove installation (check all possible locations)
    local removed_dir=""
    for install_dir in $HELIX_INSTALL_DIRS; do
        if [ -d "$install_dir" ]; then
            $SUDO rm -rf "$install_dir"
            log_success "Removed ${install_dir}"
            removed_dir="$install_dir"
            # Also remove the updater repo clone if present
            if [ -d "${install_dir}-repo" ]; then
                $SUDO rm -rf "${install_dir}-repo"
                log_success "Removed ${install_dir}-repo"
            fi
        fi
    done

    if [ -z "$removed_dir" ]; then
        log_warn "No HelixScreen installation found"
    fi

    # Re-enable the previous UI based on firmware
    log_info "Re-enabling previous screen UI..."
    local restored_ui=""
    local restored_xorg=""

    if [ "$AD5M_FIRMWARE" = "klipper_mod" ] || [ -f "/etc/init.d/S80klipperscreen" ]; then
        # Klipper Mod - restore Xorg and KlipperScreen
        if [ -f "/etc/init.d/S40xorg" ]; then
            $SUDO chmod +x "/etc/init.d/S40xorg" 2>/dev/null || true
            restored_xorg="Xorg (/etc/init.d/S40xorg)"
        fi
        if [ -f "/etc/init.d/S80klipperscreen" ]; then
            $SUDO chmod +x "/etc/init.d/S80klipperscreen" 2>/dev/null || true
            restored_ui="KlipperScreen (/etc/init.d/S80klipperscreen)"
        fi
    fi

    # ZMOD - no UI restore needed; S80guppyscreen is managed by ZMOD
    if [ "$AD5M_FIRMWARE" = "zmod" ]; then
        log_info "ZMOD firmware: no previous UI to restore (managed by ZMOD)"
    fi

    # K2 series (Creality K2 Plus / K2 Pro): re-enable the stock procd-managed UI.
    # hooks-k2.sh runs `/etc/init.d/app disable` on every launch (which removes
    # the procd rc.d symlink), so without this step the device boots into the
    # Creality logo with no UI after uninstall.
    if [ -z "$restored_ui" ] && [ -f /etc/init.d/app ] && \
       { [ "$platform" = "k2" ] || [ -f /mnt/UDISK/printer_data/config/printer.cfg ]; }; then
        log_info "Re-enabling Creality stock UI (/etc/init.d/app)..."
        $SUDO /etc/init.d/app enable 2>/dev/null || true
        $SUDO /etc/init.d/app start 2>/dev/null || true
        restored_ui="Creality stock UI (/etc/init.d/app)"
    fi

    # Check for K1/Simple AF GuppyScreen
    if [ -z "$restored_ui" ] && [ "$AD5M_FIRMWARE" != "zmod" ] && [ -f "/etc/init.d/S99guppyscreen" ]; then
        $SUDO chmod +x "/etc/init.d/S99guppyscreen" 2>/dev/null || true
        restored_ui="GuppyScreen (/etc/init.d/S99guppyscreen)"
    fi

    # ForgeX - restore GuppyScreen and stock UI settings
    if [ -z "$restored_ui" ] && [ "$AD5M_FIRMWARE" = "forge_x" ]; then
        uninstall_forgex
    fi

    # COSMOS (Centauri Carbon): restore /etc/init.d/grumpyscreen from the
    # backup the installer made when it substituted in the helixscreen-wrapper
    # init script (see competing_uis.sh stop_cc1_competing_uis). Also revert
    # cosmos.conf in case the upstream config-manager allowlist fix lands and
    # actually starts honoring 'helixscreen' values — we want to be a clean
    # citizen on uninstall regardless.
    if [ -z "$restored_ui" ] && [ -x "/usr/bin/update-cosmos" ]; then
        if [ -f /etc/init.d/grumpyscreen.helix-bak ]; then
            log_info "Restoring original /etc/init.d/grumpyscreen"
            $SUDO mv /etc/init.d/grumpyscreen.helix-bak /etc/init.d/grumpyscreen \
                || log_warn "Could not restore /etc/init.d/grumpyscreen — gui-switcher may not launch a UI on next boot"
        fi
        if [ -f /etc/klipper/config/cosmos.conf ] && \
           grep -q "^screen_ui[[:space:]]*=[[:space:]]*helixscreen" /etc/klipper/config/cosmos.conf 2>/dev/null; then
            log_info "Reverting cosmos.conf screen_ui to grumpyscreen"
            $SUDO sed -i "s|^screen_ui[[:space:]]*=.*|screen_ui = grumpyscreen|" \
                /etc/klipper/config/cosmos.conf 2>/dev/null || true
        fi
        if [ -x /etc/init.d/grumpyscreen ]; then
            log_info "Starting grumpyscreen"
            $SUDO /etc/init.d/grumpyscreen start 2>/dev/null || true
            restored_ui="grumpyscreen (COSMOS stock UI)"
        fi
    fi

    # Snapmaker U1: re-enable the stock UI we neutralized at install time.
    # snapmaker-u1-setup-autostart.sh disables the stock UI binary
    # (chmod a-x /usr/bin/gui) so neither firmware 1.3's /etc/init.d/S99screen
    # nor 1.4's relocated launcher can start it; it also patches (or creates)
    # /etc/init.d/S99screen to launch HelixScreen. Reverse both:
    #   1. Re-enable /usr/bin/gui (chmod +x) so a stock launcher can exec it.
    #   2. Restore the launcher — from S99screen.stock on 1.3, or by removing
    #      our HelixScreen-marked S99screen on 1.4 (we created it there).
    if [ -z "$restored_ui" ] && [ "$platform" = "snapmaker-u1" ]; then
        if [ -f /usr/bin/gui ] && [ ! -x /usr/bin/gui ]; then
            log_info "Re-enabling stock UI binary (/usr/bin/gui)"
            $SUDO chmod +x /usr/bin/gui 2>/dev/null \
                || log_warn "Could not re-enable /usr/bin/gui — stock UI may not start on next boot"
        fi
        if [ -f /etc/init.d/S99screen.stock ]; then
            log_info "Restoring stock /etc/init.d/S99screen (firmware 1.3)"
            $SUDO mv /etc/init.d/S99screen.stock /etc/init.d/S99screen \
                || log_warn "Could not restore /etc/init.d/S99screen — stock UI launcher may be missing"
        elif [ -f /etc/init.d/S99screen ] && \
             grep -q HelixScreen /etc/init.d/S99screen 2>/dev/null; then
            log_info "Removing HelixScreen-created /etc/init.d/S99screen (firmware 1.4)"
            $SUDO rm -f /etc/init.d/S99screen 2>/dev/null || true
        fi
        restored_ui="Snapmaker stock UI (/usr/bin/gui re-enabled)"
    fi

    # Clean up helixscreen cache directories
    for cache_dir in /root/.cache/helix /tmp/helix_thumbs /.cache/helix /data/helixscreen/cache /usr/data/helixscreen/cache; do
        if [ -d "$cache_dir" ] 2>/dev/null; then
            log_info "Removing cache: $cache_dir"
            $SUDO rm -rf "$cache_dir"
        fi
    done
    # Clean up /var/tmp helix files
    for tmp_pattern in /var/tmp/helix_*; do
        if [ -e "$tmp_pattern" ] 2>/dev/null; then
            log_info "Removing cache: $tmp_pattern"
            $SUDO rm -rf "$tmp_pattern"
        fi
    done

    # Clean up active flag file
    rm -f /tmp/helixscreen_active 2>/dev/null || true

    # Clean up macOS resource fork files (created by scp from Mac)
    for pattern in /opt/._helixscreen /root/._helixscreen; do
        $(file_sudo "$pattern") rm -f "$pattern" 2>/dev/null || true
    done

    # Remove config symlinks (preserves user files in printer_data)
    if type remove_config_symlink >/dev/null 2>&1; then
        remove_config_symlink || true
    fi

    # Sweep state dirs holding rolling config backups (out-of-INSTALL_DIR by
    # design).  Also sweeps the .uninstalling sentinel dropped at the top.
    clean_helix_state_dirs

    # Strip the legacy [shell_command helix_recover] block from moonraker.conf
    # (dead since v0.99.61 — kept around on already-installed K2s until they
    # next upgrade or, as here, uninstall).
    if type remove_legacy_moonraker_block >/dev/null 2>&1; then
        local _mr_conf
        _mr_conf=$(find_moonraker_conf 2>/dev/null || true)
        if [ -n "$_mr_conf" ] && [ -f "$_mr_conf" ]; then
            remove_legacy_moonraker_block "$_mr_conf" "$(file_sudo "$_mr_conf")" || true
        fi
    fi

    log_success "HelixScreen uninstalled"
    if [ -n "$restored_xorg" ]; then
        log_info "Re-enabled: $restored_xorg"
    fi
    if [ -n "$restored_ui" ]; then
        log_info "Re-enabled: $restored_ui"
        log_info "Reboot to start the previous UI"
    else
        log_info "Note: No previous UI found to restore"
    fi
}

# Clean up old installation completely (for --clean flag)
# Removes all files, config, and caches without backup
# Args: platform
clean_old_installation() {
    local platform=$1

    log_warn "=========================================="
    log_warn "  CLEAN INSTALL MODE"
    log_warn "=========================================="
    log_warn ""
    log_warn "This will PERMANENTLY DELETE:"
    log_warn "  - All HelixScreen files in ${INSTALL_DIR}"
    log_warn "  - Your configuration (settings.json)"
    log_warn "  - Rolling config backups (/var/lib/helixscreen + .helixscreen under the service user's home)"
    log_warn "  - Thumbnail cache files"
    log_warn ""

    # Interactive confirmation if stdin is a terminal
    if [ -t 0 ]; then
        printf "Are you sure? [y/N] "
        read -r response
        case "$response" in
            [yY][eE][sS]|[yY])
                ;;
            *)
                log_info "Clean install cancelled."
                exit 0
                ;;
        esac
    fi

    log_info "Cleaning old installation..."

    # Stop any running services
    stop_service

    # Remove installation directories (check all possible locations)
    for install_dir in $HELIX_INSTALL_DIRS; do
        if [ -d "$install_dir" ]; then
            log_info "Removing $install_dir..."
            $SUDO rm -rf "$install_dir"
        fi
    done

    # Remove thumbnail caches (POSIX-compatible: no arrays)
    for cache_pattern in \
        "/root/.cache/helix/helix_thumbs" \
        "/home/*/.cache/helix/helix_thumbs" \
        "/tmp/helix_thumbs" \
        "/var/tmp/helix_thumbs" \
        "/var/tmp/helix_*" \
        "/data/helixscreen/cache" \
        "/usr/data/helixscreen/cache"
    do
        for cache_dir in $cache_pattern; do
            if [ -d "$cache_dir" ] 2>/dev/null; then
                log_info "Removing cache: $cache_dir"
                $SUDO rm -rf "$cache_dir"
            fi
        done
    done

    # Remove init scripts (check all possible locations)
    for init_script in $HELIX_INIT_SCRIPTS; do
        if [ -f "$init_script" ]; then
            log_info "Removing init script: $init_script"
            $SUDO rm -f "$init_script"
        fi
    done

    # Remove systemd service if present
    if [ -f "/etc/systemd/system/${SERVICE_NAME}.service" ]; then
        log_info "Removing systemd service..."
        $SUDO systemctl disable "$SERVICE_NAME" 2>/dev/null || true
        $SUDO rm -f "/etc/systemd/system/${SERVICE_NAME}.service"
    fi
    # Remove update watcher units
    $SUDO systemctl stop helixscreen-update.path 2>/dev/null || true
    $SUDO systemctl disable helixscreen-update.path 2>/dev/null || true
    $SUDO rm -f /etc/systemd/system/helixscreen-update.path
    $SUDO rm -f /etc/systemd/system/helixscreen-update.service
    # Remove permission rules (udev, polkit)
    $SUDO rm -f /etc/udev/rules.d/99-helixscreen-backlight.rules
    $SUDO rm -f /etc/polkit-1/localauthority/50-local.d/helixscreen-network.pkla
    $SUDO rm -f /etc/polkit-1/rules.d/49-helixscreen-network.rules
    $SUDO rm -f /etc/polkit-1/rules.d/50-helixscreen-network.rules
    $SUDO systemctl daemon-reload 2>/dev/null || true

    # Remove printer_data/config/helixscreen/ (user config) in clean mode
    if [ -n "${KLIPPER_HOME:-}" ]; then
        local pd_helix="${KLIPPER_HOME}/printer_data/config/helixscreen"
        if [ -d "$pd_helix" ] || [ -L "$pd_helix" ]; then
            log_info "Removing user config: $pd_helix"
            $SUDO rm -rf "$pd_helix"
        fi
    fi

    # Sweep state dirs holding rolling config backups
    clean_helix_state_dirs

    log_success "Old installation cleaned"
    echo ""
}

# ============================================
# Module: main.sh
# ============================================

#
# Source guard
# Set up error trap (ERR is bash-specific, skip on POSIX shells like dash/ash)
# shellcheck disable=SC3047
trap 'error_handler $LINENO' ERR 2>/dev/null || true

# Print usage
usage() {
    echo "HelixScreen Installer"
    echo ""
    echo "Usage: $0 [options]"
    echo ""
    echo "Options:"
    echo "  --update       Update existing installation (preserves config)"
    echo "  --uninstall    Remove HelixScreen"
    echo "  --clean        Clean install: remove old installation completely,"
    echo "                 including config and caches (asks for confirmation)"
    echo "  --version VER  Install specific version (default: latest)"
    echo "  --local FILE   Install from local archive (.zip or .tar.gz, skip download)"
    echo "  --skip-kiauh-registration"
    echo "                 Skip KIAUH extension registration (default: install if KIAUH detected)"
    echo "  --help         Show this help message"
    echo ""
    echo "Examples:"
    echo "  $0                    # Fresh install, latest version"
    echo "  $0 --update           # Update existing installation"
    echo "  $0 --clean            # Remove old install completely, then install"
    echo "  $0 --version v1.1.0   # Install specific version"
    echo "  $0 --local /tmp/helixscreen-ad5m.tar.gz  # Install from local file"
}

# Configure platform-specific settings before stopping competing UIs
# (ForgeX display mode, stock UI disable, screen.sh patching)
configure_platform() {
    case "${AD5M_FIRMWARE:-}" in
        forge_x)
            configure_forgex_display || true
            disable_stock_firmware_ui || true
            patch_forgex_screen_sh || true
            patch_forgex_screen_drawing || true
            install_forgex_logged_wrapper || true
            ;;
        klipper_mod)
            # Klipper Mod-specific install-time configuration (if any)
            ;;
    esac
}

# Deploy platform-specific hooks for the init script
# Must be called after extract_release (hooks are in the release package)
install_platform_hooks() {
    local platform_hook=""
    case "${AD5M_FIRMWARE:-}" in
        forge_x)     platform_hook="ad5m-forgex" ;;
        klipper_mod) platform_hook="ad5m-kmod" ;;
        zmod)        platform_hook="ad5m-zmod" ;;
    esac

    # Platform hooks (pi32 shares Pi hooks; AD5X shares the ad5m-zmod hook
    # because both run ZMOD firmware with the same /data layout).
    case "$platform" in
        pi|pi32)       platform_hook="pi" ;;
        k1)            platform_hook="k1" ;;
        k2)            platform_hook="k2" ;;
        cc1)           platform_hook="cc1" ;;
        m1)            platform_hook="m1" ;;
        ad5x)          platform_hook="ad5m-zmod" ;;
        snapmaker-u1)  platform_hook="snapmaker-u1" ;;
    esac

    if [ -n "$platform_hook" ]; then
        deploy_platform_hooks "$INSTALL_DIR" "$platform_hook"
    fi
}

# Print the post-detection platform banner.
#
# For Pi-class SBCs (platform=pi/pi32 — which covers a long tail of ARM Linux
# boxes including QIDI Q2/Plus, BTT CB1, MKS-Pi, generic Armbian) we lead with
# the friendly hardware label and reframe "pi" as the install package. Plain
# "Detected platform: pi" reads as wrong to anyone whose printer says QIDI on
# the lid — they see "pi" first and assume we mis-identified their device.
# Actual Raspberry Pi owners keep the original ordering.
#
# All other platforms (k1, k2, ad5m, snapmaker-u1, x86, …) get the single
# "Detected platform: X" line — there's no device-name ambiguity to clear up.
print_platform_banner() {
    local platform="$1"
    local _hw_label

    if [ "$platform" != "pi" ] && [ "$platform" != "pi32" ]; then
        log_info "Detected platform: ${BOLD}${platform}${NC}"
        return 0
    fi

    _hw_label=$(describe_hardware)
    case "$_hw_label" in
        "Raspberry Pi"*)
            log_info "Detected platform: ${BOLD}${platform}${NC}"
            log_info "Hardware: ${_hw_label}"
            ;;
        *)
            log_info "Detected hardware: ${BOLD}${_hw_label}${NC}"
            log_info "Install package: ${BOLD}${platform}${NC} (generic ARM Linux build, compatible with your SBC)"
            ;;
    esac
}

# Refuse to run --uninstall from a script sitting inside the dir we're about to
# delete. The release tarball ships scripts/install.sh into $INSTALL_DIR for
# offline --local updates; users sometimes invoke that copy with --uninstall,
# which "works" on Linux only because the kernel keeps the inode open after rm.
# Force the user to copy out. No-op (returns 0) when INSTALL_DIR isn't known
# yet or $0 lives elsewhere, so it's safe to call more than once.
_refuse_uninstall_from_install_dir() {
    local _script_dir _script_abs _install_norm
    _script_dir="$(cd "$(dirname "$0")" 2>/dev/null && pwd)" || _script_dir=""
    [ -n "$_script_dir" ] || return 0
    [ -n "${INSTALL_DIR:-}" ] || return 0
    _script_abs="${_script_dir}/$(basename "$0")"
    _install_norm="${INSTALL_DIR%/}"
    case "$_script_abs" in
        "$_install_norm"/* | "$_install_norm")
            log_error "Refusing to run --uninstall from inside \$INSTALL_DIR"
            log_error "  script:      $_script_abs"
            log_error "  INSTALL_DIR: $INSTALL_DIR"
            log_error ""
            log_error "Copy the script out first, then re-run:"
            log_error "  cp '$_script_abs' /tmp/install.sh"
            log_error "  sh /tmp/install.sh --uninstall"
            exit 1
            ;;
    esac
}

# Main installation flow
main() {
    update_mode=false
    uninstall_mode=false
    clean_mode=false
    version=""
    local_tarball=""
    skip_kiauh_registration=false

    # Parse arguments
    while [ $# -gt 0 ]; do
        case $1 in
            --update)
                update_mode=true
                shift
                ;;
            --uninstall)
                uninstall_mode=true
                shift
                ;;
            --clean)
                clean_mode=true
                shift
                ;;
            --version)
                if [ -z "${2:-}" ]; then
                    log_error "--version requires a version argument"
                    exit 1
                fi
                version="$2"
                shift 2
                ;;
            --local)
                if [ -z "${2:-}" ]; then
                    log_error "--local requires a file path argument"
                    exit 1
                fi
                local_tarball="$2"
                shift 2
                ;;
            --skip-kiauh-registration)
                skip_kiauh_registration=true
                shift
                ;;
            --help|-h)
                usage
                exit 0
                ;;
            *)
                log_error "Unknown option: $1"
                usage
                exit 1
                ;;
        esac
    done

    # Self-delete safety guard runs as early as possible — before platform
    # detection, which exits on "unsupported" hardware and would otherwise
    # preempt the guard. Only fires when INSTALL_DIR is already known (env);
    # the post-set_install_paths call below covers the normal runtime case.
    if [ "$uninstall_mode" = true ]; then
        _refuse_uninstall_from_install_dir
    fi

    printf '\n'
    printf '%b\n' "${BOLD}========================================${NC}"
    printf '%b\n' "${BOLD}       HelixScreen Installer${NC}"
    printf '%b\n' "${BOLD}========================================${NC}"
    printf '\n'

    # Detect platform
    platform=$(detect_platform)
    # For platforms that share a binary with pi/pi32 (e.g. m1), the download
    # URL uses the donor platform key while $platform stays put so hooks,
    # banner, and competing-UI shutdown still target the real device.
    download_platform=$(get_download_platform "$platform")
    print_platform_banner "$platform"

    # AD5X: refuse to run outside the ZMOD chroot — applies to fresh install,
    # --update, --uninstall, and --local. Inside the chroot the check is a no-op.
    if [ "$platform" = "ad5x" ]; then
        ad5x_check_chroot_context
    fi

    if [ "$platform" = "unsupported" ]; then
        log_error "Unsupported platform: $(uname -m)"
        log_error "HelixScreen supports:"
        log_error "  - Raspberry Pi (aarch64/armv7l)"
        log_error "  - FlashForge Adventurer 5M (armv7l)"
        log_error "  - Creality K1 series with Simple AF"
        log_error "  - Creality K2 series (K2/K2 Pro/K2 Plus)"
        log_error "  - x86_64 Debian/Ubuntu (x86_64)"
        exit 1
    fi

    # For AD5M/K1, detect firmware variant and set appropriate paths
    local firmware=""
    if [ "$platform" = "ad5m" ]; then
        AD5M_FIRMWARE=$(detect_ad5m_firmware)
        firmware="$AD5M_FIRMWARE"
    elif [ "$platform" = "k1" ]; then
        K1_FIRMWARE=$(detect_k1_firmware)
        firmware="$K1_FIRMWARE"
    fi
    set_install_paths "$platform" "$firmware"

    # Check permissions
    check_permissions "$platform"

    # Handle uninstall (doesn't need all checks). The self-delete guard also
    # ran early (before platform detection); this second call covers the normal
    # case where INSTALL_DIR was computed by set_install_paths just above.
    if [ "$uninstall_mode" = true ]; then
        _refuse_uninstall_from_install_dir
        uninstall "$platform"
        exit 0
    fi

    # Defensive: if uninstall_mode is still true at this point, the early
    # exit above is broken — fail loudly rather than running the install
    # path, which is the failure mode that caused user reports of
    # "--uninstall reinstalled HelixScreen".
    if [ "$uninstall_mode" = true ]; then
        log_error "internal error: install path entered with uninstall_mode=true"
        log_error "please report at https://github.com/prestonbrown/helixscreen/issues"
        exit 99
    fi

    # Pre-flight checks
    log_info "Running pre-flight checks..."
    check_requirements
    install_runtime_deps "$platform"
    check_disk_space "$platform"
    detect_init_system
    check_klipper_ecosystem "$platform"

    # Get version (skip if using local archive)
    if [ -n "$local_tarball" ]; then
        # Validate local file exists
        if [ ! -f "$local_tarball" ]; then
            log_error "Local archive not found: $local_tarball"
            exit 1
        fi
        # Extract version from filename if possible. Only the tar.gz layout
        # carries a version in the name (helixscreen-<plat>-v1.2.3.tar.gz).
        # The unversioned helixscreen-<plat>.zip gets "local" as a placeholder.
        version=$(echo "$local_tarball" | sed -n 's/.*helixscreen-[^-]*-\(v[0-9.]*\)\.tar\.gz/\1/p')
        if [ -z "$version" ]; then
            version="local"
        fi
        log_info "Installing from local file: ${BOLD}${local_tarball}${NC}"
    else
        if [ -z "$version" ]; then
            version=$(get_latest_version "$download_platform")
        fi
    fi
    log_info "Target version: ${BOLD}${version}${NC}"

    # Configure platform-specific settings before stopping UIs
    configure_platform

    # Stop competing UIs
    stop_competing_uis

    # Clean old installation if requested
    if [ "$clean_mode" = true ]; then
        clean_old_installation "$platform"
    fi

    # Download/stage the release archive BEFORE stopping the service.
    # Stopping helixscreen first can disrupt the network on some platforms
    # (e.g. Snapmaker U1 where platform_post_stop restarts the stock GUI which
    # owns wpa_supplicant and drops WiFi/SSH mid-update). Staging first also
    # means a failed download leaves the running service untouched.
    if [ -n "$local_tarball" ]; then
        use_local_tarball "$local_tarball"
    else
        download_release "$version" "$download_platform"
    fi

    if [ "$update_mode" = true ]; then
        if [ ! -d "$INSTALL_DIR" ]; then
            log_warn "No existing installation found. Performing fresh install."
        fi
        stop_service "$platform"
    fi

    extract_release "$platform"
    fix_install_ownership
    install_service "$platform"
    install_platform_hooks

    # Install KIAUH extension if KIAUH is detected
    install_kiauh_extension "$skip_kiauh_registration" || true

    # K1: ensure SSH (dropbear) is running — recovers from #535 where disabling
    # S99start_app also killed SSH. Runs on both fresh install and self-update.
    if [ "$platform" = "k1" ]; then
        ensure_k1_ssh
    fi

    # Verify all shared library dependencies are satisfied before starting
    verify_binary_deps "$platform"

    # Create platform cache directory
    case "$platform" in
        ad5m)
            $SUDO mkdir -p /data/helixscreen/cache
            ;;
        k1)
            $SUDO mkdir -p /usr/data/helixscreen/cache
            ;;
    esac

    # Symlink config into printer_data (Pi/Klipper only - enables web UI editing)
    setup_config_symlink

    # Configure Moonraker update_manager (Pi only - enables web UI updates)
    configure_moonraker_updates "$platform"

    # Install platform-specific helix-recover.sh used by PrinterRecoveryService
    # when klippy_uds is dead and firmware_restart can't proxy. No-op on stock
    # systemd platforms (pi/pi32/x86) where services.restart handles it.
    configure_local_recovery "$platform"

    # Fix known Klipper config issues (AD5M screw_thread, etc.)
    fix_ad5m_klipper_config || true

    # Generic per-printer install-time layer (#986): detect a known printer
    # model and apply its bundled settings seed + Klipper include, if any.
    # detect_printer_model() is conservative and returns empty for unknown
    # hardware, so this is a no-op on every platform without a registered id.
    local seed_pid
    seed_pid=$(detect_printer_model)
    if [ -n "$seed_pid" ]; then
        log_info "Recognized printer model: ${seed_pid} -- applying install-time defaults"
        seed_settings_for_printer "$seed_pid" || true
        install_klipper_include_for_printer "$seed_pid" || true
    fi

    # Configure ALSA "default" when the board has no card 0 (e.g. Pi + HDMI-audio
    # screens like the BTT HDMI5, whose only outputs are vc4hdmi0/vc4hdmi1 at
    # indices 1/2). Safe no-op when "default" already works or /etc/asound.conf
    # already exists.
    configure_alsa_default || true

    # Start service
    start_service "$platform"
    cleanup_old_install

    # Cleanup on success
    cleanup_on_success

    printf '\n'
    printf '%b\n' "${GREEN}${BOLD}========================================${NC}"
    printf '%b\n' "${GREEN}${BOLD}    Installation Complete!${NC}"
    printf '%b\n' "${GREEN}${BOLD}========================================${NC}"
    printf '\n'
    echo "HelixScreen ${version} installed to ${INSTALL_DIR}"
    echo ""
    print_post_install_commands
    echo ""

    if [ "$platform" = "ad5m" ] || [ "$platform" = "k1" ] || [ "$platform" = "k2" ]; then
        echo "Note: You may need to reboot for the display to update."
    fi
}

# Run main
main "$@"
